/* ════════════════════════════════════════════════════════════════
   FIREBASE REALTIME DATABASE
   ════════════════════════════════════════════════════════════════ */
const FB = "https://projuktipunjo-apk-default-rtdb.asia-southeast1.firebasedatabase.app";
const fbGet    = async p => { try { const r=await fetch(`${FB}/${p}.json`); return await r.json(); } catch { return null; } };
const fbSet    = async (p,d) => { try { const r=await fetch(`${FB}/${p}.json`,{method:"PUT",headers:{"Content-Type":"application/json"},body:JSON.stringify(d)}); return await r.json(); } catch { return null; } };
const fbPush   = async (p,d) => { try { const r=await fetch(`${FB}/${p}.json`,{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify(d)}); return await r.json(); } catch { return null; } };
const fbPatch  = async (p,d) => { try { const r=await fetch(`${FB}/${p}.json`,{method:"PATCH",headers:{"Content-Type":"application/json"},body:JSON.stringify(d)}); return await r.json(); } catch { return null; } };
const fbDelete = async p => { try { await fetch(`${FB}/${p}.json`,{method:"DELETE"}); return true; } catch { return false; } };

// ── localStorage persistence helpers ────────────────────────────
const LS_DELETED_PT   = "pp_deleted_pt_reqs";
const LS_PT_STATUS    = "pp_pt_req_status";
const LS_DELETED_PAY  = "pp_deleted_payments";
const LS_PAY_STATUS   = "pp_pay_status";
const LS_DELETED_DEMO_NOTIF = "pp_deleted_demo_notifs";
const LS_DELETED_FB_NOTIF   = "pp_deleted_fb_notifs";

const lsGetSet = k => { try { return new Set(JSON.parse(localStorage.getItem(k)||"[]")); } catch { return new Set(); } };
const lsGetObj = k => { try { return JSON.parse(localStorage.getItem(k)||"{}"); } catch { return {}; } };
const lsSaveSet = (k, s) => { try { localStorage.setItem(k, JSON.stringify([...s])); } catch {} };
const lsSaveObj = (k, o) => { try { localStorage.setItem(k, JSON.stringify(o)); } catch {} };

// Initialize window caches from localStorage on first load
const _initPpCache = () => {
  if(!window._ppDeletedPtReqs) window._ppDeletedPtReqs = lsGetSet(LS_DELETED_PT);
  if(!window._ppDemoStatus)    window._ppDemoStatus    = lsGetObj(LS_PT_STATUS);
  if(!window._ppDeletedPayKeys) window._ppDeletedPayKeys = lsGetSet(LS_DELETED_PAY);
  if(!window._ppPayStatus)     window._ppPayStatus     = lsGetObj(LS_PAY_STATUS);
  if(!window._ppDeletedDemoNotifs) window._ppDeletedDemoNotifs = lsGetSet(LS_DELETED_DEMO_NOTIF);
  if(!window._ppDeletedFbNotifs)   window._ppDeletedFbNotifs   = lsGetSet(LS_DELETED_FB_NOTIF);
};
_initPpCache();

// Wrappers that keep window + localStorage in sync
const ppAddDeletedPtReq = key => {
  window._ppDeletedPtReqs.add(key);
  lsSaveSet(LS_DELETED_PT, window._ppDeletedPtReqs);
};
const ppSetPtStatus = (key, statusObj) => {
  window._ppDemoStatus[key] = statusObj;
  lsSaveObj(LS_PT_STATUS, window._ppDemoStatus);
};
const ppDelPtStatus = key => {
  delete window._ppDemoStatus[key];
  lsSaveObj(LS_PT_STATUS, window._ppDemoStatus);
};
const ppAddDeletedPayKey = key => {
  window._ppDeletedPayKeys.add(key);
  lsSaveSet(LS_DELETED_PAY, window._ppDeletedPayKeys);
};
const ppSetPayStatus = (key, statusObj) => {
  window._ppPayStatus[key] = statusObj;
  lsSaveObj(LS_PAY_STATUS, window._ppPayStatus);
};
const ppAddDeletedDemoNotif = key => {
  window._ppDeletedDemoNotifs.add(key);
  lsSaveSet(LS_DELETED_DEMO_NOTIF, window._ppDeletedDemoNotifs);
};
const ppAddDeletedFbNotif = key => {
  window._ppDeletedFbNotifs.add(key);
  lsSaveSet(LS_DELETED_FB_NOTIF, window._ppDeletedFbNotifs);
};

// ── Notification helper ──────────────────────────────────────────
const sendNotification = async (userId, {type, title, body, icon="🔔", color="#60a5fa"}) => {
  if(!userId) return;
  const safeUid = userId.replace(/[.#$[\]]/g,"_");
  await fbPush(`notifications/${safeUid}`, {
    type, title, body, icon, color,
    read: false,
    createdAt: Date.now(),
    date: new Date().toLocaleDateString("bn-BD")
  });
};

// ── Notify all real admins (for student/client actions) ──────────
const notifyAllAdmins = async ({type, title, body, icon="🔔", color="#f59e0b"}) => {
  try {
    const adminUserIds = new Set();
    // 1. Check users/ path (students/clients who might be admin)
    const usersData = await fbGet("users");
    if(usersData){
      Object.values(usersData)
        .filter(u => !u.isDemo && (u.role==="admin" || u.role==="chief_admin") && u.userId)
        .forEach(u => adminUserIds.add(u.userId));
    }
    // 2. Check chief_admin path
    const chiefData = await fbGet("chief_admin");
    if(chiefData?.userId) adminUserIds.add(chiefData.userId);
    // 3. Check pending_admins path (approved admins might be here)
    const pendingAdmins = await fbGet("pending_admins");
    if(pendingAdmins){
      Object.values(pendingAdmins)
        .filter(u => u.userId && u.status==="approved")
        .forEach(u => adminUserIds.add(u.userId));
    }
    if(adminUserIds.size===0) return;
    await Promise.all([...adminUserIds].map(uid => sendNotification(uid, {type, title, body, icon, color})));
  } catch(e) { /* silent fail */ }
};

