/* ════════════════════════════════════════════════════════════════
   HELPERS
   ════════════════════════════════════════════════════════════════ */
const fmt = n => { const num = Number(n); return "৳" + (isNaN(num) ? "0" : num.toLocaleString()); };
const fmtPhone = p => {
  if(!p) return "—";
  const d=String(p).replace(/\D/g,"");
  if(d.startsWith("880")) return `+${d.slice(0,3)} ${d.slice(3,7)}-${d.slice(7)}`;
  if(d.startsWith("88"))  return `+${d.slice(0,2)} ${d.slice(2,6)}-${d.slice(6)}`;
  if(d.startsWith("0"))   return `+88 ${d.slice(1,5)}-${d.slice(5)}`;
  return `+88 ${d.slice(0,4)}-${d.slice(4)}`;
};
const courseById = id => COURSES.find(c => c.id === id);
const calcPoints = amt => amt>=500?80:amt>=300?50:amt>=200?30:amt>=100?20:amt>=50?10:0;
const statusColor = s => s==="active"?C.green:s==="completed"?C.sky:s==="pending"?C.amber:s==="rejected"?C.red:C.dim;
const genKey16 = () => Math.random().toString(36).substring(2,10).toUpperCase() + Math.random().toString(36).substring(2,10).toUpperCase();
const safeId = id => id.replace(/[.#$[\]/]/g,"-");

// ── NEW ID FORMAT (v10) ──────────────────────────────────────────
// STUDENT:  PP-YYYY-MM-DD-ADMISSIONSERIAL-USERID
//           e.g. PP-2026-10-31-0001-001
// CLIENT:   PP-YYYY-MM-DD-USERID
//           e.g. PP-2026-10-31-001
// ADMIN:    PP-YYYY-MM-DD-USERID
//           e.g. PP-2026-10-31-001
// USERID = global auto-increment (001, 002, 003 …) — never duplicates across any role
// ────────────────────────────────────────────────────────────────

// Pad admission serial to at least 4 digits (accepts 2–5 digit manual input)
const padAdmSerial = s => String(s).replace(/\D/g,"").padStart(4,"0") || "0001";

// USERID is always 3-digit minimum, increments globally across all real users
const nextUserId = (users) => {
  const realIds = users
    .filter(u => !u.isDemo && u.autoUserId)
    .map(u => parseInt(u.autoUserId, 10))
    .filter(n => !isNaN(n));
  const max = realIds.length > 0 ? Math.max(...realIds) : 0;
  return String(max + 1).padStart(3, "0");
};

const buildStudentId = (date, admSerial, userId) =>
  `PP-${date}-${padAdmSerial(admSerial)}-${String(userId).padStart(3,"0")}`;

const buildClientId = (date, userId) =>
  `PP-${date}-${String(userId).padStart(3,"0")}`;

const buildAdminId = (date, userId) =>
  `PP-${date}-${String(userId).padStart(3,"0")}`;

const todayStr = () => {
  const n=new Date();
  return `${n.getFullYear()}-${String(n.getMonth()+1).padStart(2,"0")}-${String(n.getDate()).padStart(2,"0")}`;
};

// Legacy helper kept for compatibility — not used in new ID generation
const sysSerial = (users, role, date) => {
  const realCount = users.filter(u => !u.isDemo && u.role===role && u.regDate===date).length;
  const demoCount = users.filter(u => u.isDemo && u.role===role).length;
  return realCount + demoCount + 1;
};

/* ════════════════════════════════════════════════════════════════
   RESPONSIVE HOOK
   ════════════════════════════════════════════════════════════════ */
const useResponsive = () => {
  const [sc, setSc] = useState(() => { const w=typeof window!=="undefined"?window.innerWidth:1200; return w<768?"mobile":w<1024?"tablet":"desktop"; });
  useEffect(() => {
    const h = () => { const w=window.innerWidth; setSc(w<768?"mobile":w<1024?"tablet":"desktop"); };
    h(); window.addEventListener("resize",h); return ()=>window.removeEventListener("resize",h);
  },[]);
  return sc;
};

