/* ════════════════════════════════════════════════════════════════
   SPLASH
   ════════════════════════════════════════════════════════════════ */
function Splash({onDone}) {
  const [ph,setPh]=useState(0);
  useEffect(()=>{
    const t=[setTimeout(()=>setPh(1),600),setTimeout(()=>setPh(2),1600),setTimeout(()=>setPh(3),2600),setTimeout(()=>onDone(),3400)];
    return ()=>t.forEach(clearTimeout);
  },[]);
  return (
    <div style={{position:"fixed",inset:0,background:`radial-gradient(ellipse at center,${C.mid} 0%,${C.bg} 70%)`,display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center",zIndex:9999,opacity:ph===3?0:1,transition:"opacity 0.5s"}}>
      <div style={{position:"absolute",width:300,height:300,borderRadius:"50%",border:`1px solid ${C.sky}18`,animation:"spin 8s linear infinite"}}/>
      <div style={{position:"absolute",width:220,height:220,borderRadius:"50%",border:`1px solid ${C.gold}20`,animation:"spin 5s linear infinite reverse"}}/>
      <div style={{width:90,height:90,background:`linear-gradient(135deg,${C.skyDeep},${C.sky})`,borderRadius:22,display:"flex",alignItems:"center",justifyContent:"center",boxShadow:`0 0 60px ${C.sky}40`,transform:ph>=1?"scale(1)":"scale(0.3)",opacity:ph>=1?1:0,transition:"all 0.5s cubic-bezier(0.34,1.56,0.64,1)"}}>
        <LogoImg size={72}/>
      </div>
      <div style={{marginTop:20,textAlign:"center",opacity:ph>=2?1:0,transform:ph>=2?"translateY(0)":"translateY(20px)",transition:"all 0.5s 0.1s"}}>
        <div style={{fontSize:"1.8rem",fontWeight:900,color:C.white}}>প্রযুক্তিপুঞ্জ</div>
        <div style={{fontSize:"0.9rem",color:C.sky,fontWeight:600,marginTop:4}}>প্রযুক্তিপুঞ্জ ম্যানেজমেন্ট সিস্টেম</div>
      </div>
      <style>{`@keyframes spin{to{transform:rotate(360deg)}}`}</style>
    </div>
  );
}

/* ════════════════════════════════════════════════════════════════
   LOGIN
   ════════════════════════════════════════════════════════════════ */
function Login({onLogin,onRegister,onForgot,onFirstAdmin,onOwnerRecovery,users}) {
  const [role,setRole]=useState("student");
  const [uid,setUid]=useState("");
  const [pass,setPass]=useState("");
  const [err,setErr]=useState("");

  const [loginLoading,setLoginLoading]=useState(false);
  const doLogin=async()=>{
    setErr("");
    if(!uid||!pass){setErr("User ID এবং Password দিন");return;}
    setLoginLoading(true);
    // 1. Check in-memory users first (fast)
    let u=users.find(u=>(u.userId===uid||u.mobile===uid||u.email===uid)&&u.password===pass);
    // 2. If not found, check Firebase directly (handles new registrations)
    if(!u){
      const fbAll=await fbGet("users");
      if(fbAll){
        const fbArr=Object.values(fbAll);
        u=fbArr.find(u=>(u.userId===uid||u.mobile===uid||u.email===uid)&&u.password===pass);
      }
    }
    setLoginLoading(false);
    if(!u){setErr("User ID বা Password সঠিক নয়");return;}
    if(u.role===ROLES.PENDING_ADMIN){setErr("আপনার অ্যাকাউন্ট এখনো অ্যাপ্রুভ হয়নি। Admin অনুমোদনের অপেক্ষা করুন।");return;}
    if(u.status===STATUS.PENDING){setErr("⏳ আপনার অ্যাকাউন্ট এখনো অনুমোদিত হয়নি। Admin অনুমোদন করার পর Login করতে পারবেন।");return;}
    if(u.status===STATUS.REJECTED){setErr("❌ আপনার নিবন্ধন আবেদন অনুমোদিত হয়নি। প্রয়োজনে কর্তৃপক্ষের সাথে যোগাযোগ করুন।");return;}
    if(u.status===STATUS.BLOCKED||u.status==="blocked"){setErr("🚫 আপনার অ্যাকাউন্ট Block করা হয়েছে। Admin-এর সাথে যোগাযোগ করুন।");return;}
    if(u.status===STATUS.SUSPENDED||u.status==="suspended"){setErr("⏸ আপনার অ্যাকাউন্ট Suspended করা হয়েছে। Admin-এর সাথে যোগাযোগ করুন।");return;}
    const effectiveRole=(u.role===ROLES.CHIEF_ADMIN||u.isMainAdmin)?ROLES.CHIEF_ADMIN:u.role;
    onLogin(effectiveRole,{id:u.userId,name:u.fullNameEn,role:effectiveRole,isMainAdmin:u.isMainAdmin||u.role===ROLES.CHIEF_ADMIN});
  };

  const ROLE_OPTS=[
    {key:"student", label:"Student",   bn:"শিক্ষার্থী",  icon:"🎓", color:C.sky,    grad:`linear-gradient(135deg,#0d3a6e,#1e6de4)`},
    {key:"client",  label:"Client",    bn:"গ্রাহক",      icon:"🏢", color:C.green,  grad:`linear-gradient(135deg,#0d4a1e,#22863a)`},
    {key:"admin",   label:"Admin",     bn:"প্রশাসক",     icon:"🔐", color:C.gold,   grad:`linear-gradient(135deg,#4a2800,#a07010)`},
  ];

  // Demo credentials helper
  const DEMO_CREDS=[
    {role:"student", id:"PP-2026-03-15-0001-001", pw:"demo123", label:"Demo Student"},
    {role:"client",  id:"PP-2026-01-15-006",       pw:"demo123", label:"Demo Client"},
    {role:"admin",   id:"PP-2026-01-01-011",        pw:"demo123", label:"Demo Admin"},
  ];

  return (
    <div style={{minHeight:"100vh",background:`radial-gradient(ellipse at 30% 20%,${C.mid} 0%,${C.bg} 60%)`,display:"flex",alignItems:"center",justifyContent:"center",padding:16}}>
      <div style={{width:"100%",maxWidth:440}}>
        <div style={{textAlign:"center",marginBottom:28}}>
          <div style={{width:80,height:80,margin:"0 auto 14px",background:`linear-gradient(135deg,${C.skyDeep},${C.sky})`,borderRadius:20,display:"flex",alignItems:"center",justifyContent:"center",boxShadow:`0 8px 30px ${C.sky}40`}}>
            <LogoImg size={66}/>
          </div>
          <div style={{fontSize:"1.6rem",fontWeight:900,color:C.white}}>প্রযুক্তিপুঞ্জ</div>
          <div style={{fontSize:"0.75rem",color:C.sky,marginTop:3}}>কম্পিউটার প্রশিক্ষণ | বিক্রয় | সেবা</div>
        </div>

        <Card glow>
          <div style={{marginBottom:20}}>
            <div style={{fontSize:"0.65rem",fontWeight:700,color:C.dim,letterSpacing:"2px",textTransform:"uppercase",marginBottom:10,textAlign:"center"}}>— আপনার পরিচয় বেছে নিন —</div>
            <div style={{display:"grid",gridTemplateColumns:"1fr 1fr 1fr",gap:8}}>
              {ROLE_OPTS.map(r=>{
                const active=role===r.key;
                return (
                  <button key={r.key} onClick={()=>{setRole(r.key);setUid("");setPass("");}} style={{
                    padding:"14px 6px 12px",
                    border:`2px solid ${active?r.color+"88":C.border}`,
                    borderRadius:14,
                    background: active ? r.grad : `rgba(255,255,255,0.03)`,
                    cursor:"pointer",
                    fontFamily:"inherit",
                    transition:"all 0.2s",
                    boxShadow: active ? `0 4px 20px ${r.color}40, inset 0 1px 0 rgba(255,255,255,0.15)` : "none",
                    transform: active ? "translateY(-2px)" : "none",
                    position:"relative",
                    overflow:"hidden",
                  }}>
                    {active&&<div style={{position:"absolute",top:0,left:0,right:0,height:"2px",background:`linear-gradient(90deg,transparent,${r.color},transparent)`}}/>}
                    <div style={{fontSize:"1.6rem",marginBottom:4,filter:active?"drop-shadow(0 2px 8px rgba(255,255,255,0.3))":"none"}}>{r.icon}</div>
                    <div style={{fontSize:"0.78rem",fontWeight:800,color:active?r.color:C.silver,letterSpacing:"0.5px"}}>{r.label}</div>
                    <div style={{fontSize:"0.62rem",color:active?"rgba(255,255,255,0.7)":C.dim,marginTop:2,fontWeight:600}}>{r.bn}</div>
                    {active&&<div style={{position:"absolute",bottom:0,left:"50%",transform:"translateX(-50%)",width:30,height:2,background:r.color,borderRadius:99}}/>}
                  </button>
                );
              })}
            </div>
          </div>

          <Inp label="User ID / Mobile / Email" value={uid} onChange={e=>setUid(e.target.value)} placeholder="আপনার ID বা Mobile দিন" required/>
          <PwdInp label="Password" value={pass} onChange={e=>setPass(e.target.value)} required/>

          {(()=>{const ro=ROLE_OPTS.find(r=>r.key===role);return(
          <button onClick={doLogin} disabled={loginLoading} style={{width:"100%",padding:"13px",fontSize:"0.95rem",fontWeight:800,border:"none",borderRadius:11,cursor:loginLoading?"wait":"pointer",fontFamily:"inherit",marginBottom:12,background:ro?ro.grad:`linear-gradient(135deg,${C.skyDeep},${C.sky})`,color:"#fff",boxShadow:ro?`0 4px 20px ${ro.color}40`:"none",letterSpacing:"0.5px",transition:"all 0.2s",opacity:loginLoading?0.7:1}}>
            {loginLoading?"⏳ যাচাই করা হচ্ছে...":`${ro?.icon} ${ro?.label} Login`}
          </button>);})()}

          {err&&<div style={{color:C.red,fontSize:"0.8rem",marginBottom:12,background:`${C.red}10`,border:`1px solid ${C.red}25`,borderRadius:8,padding:"8px 12px"}}>⚠ {err}</div>}

          <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:10,marginBottom:16}}>
            <button onClick={onRegister} style={{background:`${C.green}12`,border:`1px solid ${C.green}30`,color:C.green,borderRadius:9,padding:"10px",fontWeight:700,fontSize:"0.82rem",cursor:"pointer",fontFamily:"inherit"}}>🟢 Register</button>
            <button onClick={onForgot} style={{background:`${C.red}10`,border:`1px solid ${C.red}25`,color:C.red,borderRadius:9,padding:"10px",fontWeight:700,fontSize:"0.82rem",cursor:"pointer",fontFamily:"inherit"}}>🔴 Forgot Password</button>
          </div>
          {/* First Admin Setup — only show if no chief admin exists */}
          {!users.find(u=>!u.isDemo&&(u.role===ROLES.CHIEF_ADMIN||u.isMainAdmin))&&(
            <button onClick={onFirstAdmin} style={{width:"100%",background:`${C.gold}10`,border:`1px solid ${C.gold}30`,color:C.gold,borderRadius:9,padding:"10px",fontWeight:700,fontSize:"0.82rem",cursor:"pointer",fontFamily:"inherit",marginBottom:14}}>
              First Admin Setup
            </button>
          )}

          {/* Demo credentials — শুধু দেখাবে যদি কোনো ডেমো স্লট এখনো বাকি থাকে */}
          {DEMO_CREDS.some(d=>users.find(u=>u.userId===d.id&&u.isDemo))&&(
          <div style={{background:"rgba(255,255,255,0.03)",border:`1px solid ${C.border}`,borderRadius:10,padding:12}}>
            <div style={{fontSize:"0.65rem",fontWeight:700,color:C.dim,letterSpacing:"1px",marginBottom:8}}>⚡ DEMO QUICK LOGIN</div>
            <div style={{display:"flex",flexWrap:"wrap",gap:6}}>
              {DEMO_CREDS.map(d=>{
                const stillDemo=users.find(u=>u.userId===d.id&&u.isDemo);
                if(!stillDemo) return null;
                return (
                  <button key={d.role} onClick={()=>{setRole(d.role);setUid(d.id);setPass(d.pw);}} style={{background:`${C.sky}10`,border:`1px solid ${C.sky}25`,color:C.sky,borderRadius:7,padding:"5px 10px",fontSize:"0.72rem",cursor:"pointer",fontFamily:"inherit",fontWeight:600}}>{d.label}</button>
                );
              })}
            </div>
          </div>
          )}
          {/* Hidden owner recovery — low-profile, not labeled */}
          <div style={{textAlign:"right",marginTop:10}}>
            <button onClick={onOwnerRecovery} style={{background:"none",border:"none",color:"rgba(255,255,255,0.08)",fontSize:"0.6rem",cursor:"pointer",fontFamily:"inherit",letterSpacing:"0.5px",userSelect:"none"}}>sys</button>
          </div>
        </Card>

        {/* Contact / Social bar */}
        <div style={{marginTop:14,background:`rgba(255,255,255,0.03)`,border:`1px solid ${C.border}`,borderRadius:12,padding:"12px 16px"}}>
          <div style={{fontSize:"0.7rem",fontWeight:800,color:C.silver,letterSpacing:"1.5px",textAlign:"center",marginBottom:8}}>Contact Us</div>
          <div style={{textAlign:"center",marginBottom:8}}>
            <a href={`tel:${CONTACT.phone}`} style={{color:C.goldLt,fontWeight:800,fontSize:"0.9rem",textDecoration:"none",fontFamily:"monospace"}}>{CONTACT.phone}</a>
          </div>
          <div style={{textAlign:"center",marginBottom:8}}>
            <a href={`mailto:${CONTACT.emails[0]}`} style={{display:"inline-block",color:"#ea4335",fontWeight:700,fontSize:"0.75rem",textDecoration:"none",background:"rgba(234,67,53,0.08)",border:"1px solid rgba(234,67,53,0.25)",borderRadius:8,padding:"5px 12px"}}>📧 {CONTACT.emails[0]}</a>
          </div>
          <div style={{display:"flex",justifyContent:"center",gap:7,marginBottom:8,flexWrap:"wrap"}}>
            {/* Facebook official logo */}
            <a href={CONTACT.facebook} target="_blank" rel="noopener" style={{display:"flex",alignItems:"center",gap:5,background:"rgba(24,119,242,0.12)",border:"1px solid rgba(24,119,242,0.3)",color:"#1877f2",padding:"5px 11px",borderRadius:50,fontSize:"0.68rem",fontWeight:700,textDecoration:"none"}}>
              <svg width="14" height="14" viewBox="0 0 24 24" fill="#1877f2"><path d="M24 12.073C24 5.405 18.627 0 12 0S0 5.405 0 12.073C0 18.1 4.388 23.094 10.125 24v-8.437H7.078v-3.49h3.047V9.41c0-3.025 1.792-4.697 4.533-4.697 1.312 0 2.686.236 2.686.236v2.97h-1.513c-1.491 0-1.956.93-1.956 1.886v2.267h3.328l-.532 3.49h-2.796V24C19.612 23.094 24 18.1 24 12.073z"/></svg>
              Facebook
            </a>
            {/* WhatsApp official logo */}
            <a href={CONTACT.whatsapp} target="_blank" rel="noopener" style={{display:"flex",alignItems:"center",gap:5,background:"rgba(37,211,102,0.1)",border:"1px solid rgba(37,211,102,0.3)",color:"#25d366",padding:"5px 11px",borderRadius:50,fontSize:"0.68rem",fontWeight:700,textDecoration:"none"}}>
              <svg width="14" height="14" viewBox="0 0 24 24" fill="#25d366"><path d="M17.472 14.382c-.297-.149-1.758-.867-2.03-.967-.273-.099-.471-.148-.67.15-.197.297-.767.966-.94 1.164-.173.199-.347.223-.644.075-.297-.15-1.255-.463-2.39-1.475-.883-.788-1.48-1.761-1.653-2.059-.173-.297-.018-.458.13-.606.134-.133.298-.347.446-.52.149-.174.198-.298.298-.497.099-.198.05-.371-.025-.52-.075-.149-.669-1.612-.916-2.207-.242-.579-.487-.5-.669-.51-.173-.008-.371-.01-.57-.01-.198 0-.52.074-.792.372-.272.297-1.04 1.016-1.04 2.479 0 1.462 1.065 2.875 1.213 3.074.149.198 2.096 3.2 5.077 4.487.709.306 1.262.489 1.694.625.712.227 1.36.195 1.871.118.571-.085 1.758-.719 2.006-1.413.248-.694.248-1.289.173-1.413-.074-.124-.272-.198-.57-.347m-5.421 7.403h-.004a9.87 9.87 0 01-5.031-1.378l-.361-.214-3.741.982.998-3.648-.235-.374a9.86 9.86 0 01-1.51-5.26c.001-5.45 4.436-9.884 9.888-9.884 2.64 0 5.122 1.03 6.988 2.898a9.825 9.825 0 012.893 6.994c-.003 5.45-4.437 9.884-9.885 9.884m8.413-18.297A11.815 11.815 0 0012.05 0C5.495 0 .16 5.335.157 11.892c0 2.096.547 4.142 1.588 5.945L.057 24l6.305-1.654a11.882 11.882 0 005.683 1.448h.005c6.554 0 11.89-5.335 11.893-11.893a11.821 11.821 0 00-3.48-8.413z"/></svg>
              WhatsApp
            </a>
            {/* Telegram official logo */}
            <a href={CONTACT.telegram} target="_blank" rel="noopener" style={{display:"flex",alignItems:"center",gap:5,background:"rgba(0,136,204,0.1)",border:"1px solid rgba(0,136,204,0.3)",color:"#0088cc",padding:"5px 11px",borderRadius:50,fontSize:"0.68rem",fontWeight:700,textDecoration:"none"}}>
              <svg width="14" height="14" viewBox="0 0 24 24" fill="#0088cc"><path d="M11.944 0A12 12 0 0 0 0 12a12 12 0 0 0 12 12 12 12 0 0 0 12-12A12 12 0 0 0 12 0a12 12 0 0 0-.056 0zm4.962 7.224c.1-.002.321.023.465.14a.506.506 0 0 1 .171.325c.016.093.036.306.02.472-.18 1.898-.962 6.502-1.36 8.627-.168.9-.499 1.201-.82 1.23-.696.065-1.225-.46-1.9-.902-1.056-.693-1.653-1.124-2.678-1.8-1.185-.78-.417-1.21.258-1.91.177-.184 3.247-2.977 3.307-3.23.007-.032.014-.15-.056-.212s-.174-.041-.249-.024c-.106.024-1.793 1.14-5.061 3.345-.48.33-.913.49-1.302.48-.428-.008-1.252-.241-1.865-.44-.752-.245-1.349-.374-1.297-.789.027-.216.325-.437.893-.663 3.498-1.524 5.83-2.529 6.998-3.014 3.332-1.386 4.025-1.627 4.476-1.635z"/></svg>
              Telegram
            </a>
          </div>
          <div style={{textAlign:"center",fontSize:"0.62rem",color:C.dim}}>{CONTACT.address}</div>
          <div style={{textAlign:"center",fontSize:"0.6rem",color:C.dim,marginTop:2}}>{CONTACT.hours}</div>
        </div>
      </div>
    </div>
  );
}

/* ════════════════════════════════════════════════════════════════
   REGISTRATION — STUDENT
   ════════════════════════════════════════════════════════════════ */
function RegisterStudent({onBack,onSuccess,users,setUsers}) {
  const STEPS=["তথ্য পূরণ","Student ID","নিশ্চিত করুন"];
  const [step,setStep]=useState(0);
  const today=todayStr();
  const [form,setForm]=useState({nameBn:"",nameEn:"",fatherName:"",motherName:"",dob:"",mobile:"",email:"",course:"c1",password:"",confirmPwd:""});
  const [admDate,setAdmDate]=useState(today);        // manual admission date
  const [admSerial,setAdmSerial]=useState("0001");   // manual admission serial (2–5 digits)
  const [err,setErr]=useState("");
  const f=(k,v)=>setForm(p=>({...p,[k]:v}));

  const uid=nextUserId(users);
  const studentId=buildStudentId(admDate||today,admSerial,uid);

  const validate=()=>{
    if(!form.nameBn||!form.nameEn||!form.fatherName||!form.motherName||!form.dob){setErr("সকল তারকা চিহ্নিত তথ্য পূরণ করুন।");return false;}
    if(!form.mobile){setErr("Mobile Number দিন।");return false;}
    if(!admDate){setErr("Admission Date দিন।");return false;}
    if(!admSerial||!admSerial.replace(/\D/g,"")){setErr("Admission Serial দিন।");return false;}
    if(!form.password||form.password.length<6){setErr("Password কমপক্ষে ৬ অক্ষর হতে হবে।");return false;}
    if(form.password!==form.confirmPwd){setErr("Password মিলছে না।");return false;}
    const dup=users.find(u=>u.mobile===form.mobile||(form.email&&u.email===form.email));
    if(dup){setErr("এই Mobile/Email দিয়ে ইতিমধ্যে অ্যাকাউন্ট আছে।");return false;}
    return true;
  };

  const submit=async()=>{
    if(!validate()) return;
    const demoSlots=users.filter(u=>u.isDemo&&u.role===ROLES.STUDENT);
    let newUsers=[...users];
    const newUser={userId:studentId,fullNameBn:form.nameBn,fullNameEn:form.nameEn,fatherName:form.fatherName,motherName:form.motherName,dob:form.dob,mobile:form.mobile,email:form.email,password:form.password,role:ROLES.STUDENT,status:STATUS.PENDING,regDate:admDate||today,admissionSerial:padAdmSerial(admSerial),autoUserId:uid,course:form.course,isDemo:false,createdAt:new Date().toISOString()};
    if(demoSlots.length>0){
      const replacedDemo=demoSlots[0];
      const idx=newUsers.findIndex(u=>u.userId===replacedDemo.userId);
      newUsers[idx]=newUser;
      // Firebase-এ পুরনো ডেমো স্লট মুছে দাও
      await fbDelete(`users/${safeId(replacedDemo.userId)}`);
    } else {
      newUsers.push(newUser);
    }
    setUsers(newUsers);
    // Notify admin via Firebase
    const regData={userId:studentId,fullNameEn:form.nameEn,fullNameBn:form.nameBn||form.nameEn,fatherName:form.fatherName||"",motherName:form.motherName||"",dob:form.dob||"",mobile:form.mobile,email:form.email||"",password:form.password,role:ROLES.STUDENT,course:form.course,regDate:admDate||today,status:STATUS.PENDING,createdAt:Date.now()};
    await fbPush("pending_registrations",{...regData,name:form.nameEn});
    await fbSet(`users/${safeId(studentId)}`,regData);
    onSuccess("pendingSuccess",{id:studentId,name:form.nameEn,role:ROLES.STUDENT});
  };

  return (
    <div style={{minHeight:"100vh",background:`radial-gradient(ellipse at 30% 20%,${C.mid} 0%,${C.bg} 60%)`,display:"flex",alignItems:"center",justifyContent:"center",padding:16}}>
      <div style={{width:"100%",maxWidth:520}}>
        <div style={{textAlign:"center",marginBottom:20}}>
          <div style={{width:56,height:56,margin:"0 auto 10px",background:`linear-gradient(135deg,${C.skyDeep},${C.sky})`,borderRadius:14,display:"flex",alignItems:"center",justifyContent:"center"}}>
            <LogoImg size={44}/>
          </div>
          <div style={{fontSize:"1.25rem",fontWeight:900,color:C.white}}>🎓 Student Registration</div>
          <div style={{fontSize:"0.72rem",color:C.dim,marginTop:2}}>প্রযুক্তিপুঞ্জ · নতুন শিক্ষার্থী নিবন্ধন</div>
        </div>
        <Card glow>
          <StepBar steps={STEPS} current={step}/>

          {step===0&&(
            <div>
              <Inp label="পুরো নাম (বাংলা)" value={form.nameBn} onChange={e=>f("nameBn",e.target.value)} placeholder="যেমন: আহমেদ হোসেন" required/>
              <Inp label="Full Name (English)" value={form.nameEn} onChange={e=>f("nameEn",e.target.value)} placeholder="e.g. Ahmed Hossain" required/>
              <Inp label="Father's Name (English)" value={form.fatherName} onChange={e=>f("fatherName",e.target.value)} placeholder="e.g. Abdul Hossain" required/>
              <Inp label="Mother's Name (English)" value={form.motherName} onChange={e=>f("motherName",e.target.value)} placeholder="e.g. Fatema Begum" required/>
              <Inp label="Date of Birth" value={form.dob} onChange={e=>f("dob",e.target.value)} type="date" required/>
              <Inp label="Mobile Number" value={form.mobile} onChange={e=>f("mobile",e.target.value)} placeholder="01XXXXXXXXX" required/>
              <Inp label="Email Address (optional)" value={form.email} onChange={e=>f("email",e.target.value)} type="email" placeholder="example@email.com"/>
              <Inp label="Course" value={form.course} onChange={e=>f("course",e.target.value)} options={COURSES.map(c=>({value:c.id,label:`${c.icon} ${c.en} — ${fmt(c.fee)}`}))} required/>

              {/* Office-issued ID prefix */}
              <div style={{marginBottom:14}}>
                <div style={{fontSize:"0.68rem",color:C.dim,fontWeight:700,letterSpacing:"1px",marginBottom:5}}>OFFICE ID (given by office) *</div>
                <div style={{display:"flex",alignItems:"center",gap:6}}>
                  <div style={{background:`${C.sky}15`,border:`1px solid ${C.sky}30`,borderRadius:7,padding:"8px 12px",fontFamily:"monospace",fontWeight:800,color:C.sky,fontSize:"0.9rem",flexShrink:0}}>PP-</div>
                  <input
                    value={admDate.replace(/-/g,"-")+"-"+admSerial}
                    onChange={e=>{
                      const val=e.target.value.replace(/[^0-9-]/g,"");
                      const parts=val.split("-");
                      if(parts.length>=4){
                        setAdmDate(parts.slice(0,3).join("-"));
                        setAdmSerial(parts.slice(3).join(""));
                      } else {
                        setAdmDate(val);
                      }
                    }}
                    placeholder="2026-03-15-0001"
                    style={{flex:1,background:"rgba(255,255,255,0.07)",border:`1px solid ${C.amber}60`,color:C.amber,borderRadius:7,padding:"8px 12px",fontFamily:"monospace",fontSize:"0.9rem",outline:"none",fontWeight:700,letterSpacing:"1px"}}
                  />
                  <div style={{background:`${C.green}15`,border:`1px solid ${C.green}30`,borderRadius:7,padding:"8px 12px",fontFamily:"monospace",fontWeight:800,color:C.green,fontSize:"0.9rem",flexShrink:0}}>-{String(uid).padStart(3,"0")}</div>
                </div>
                <div style={{fontSize:"0.68rem",color:C.dim,marginTop:5,lineHeight:1.7}}>
                  Final ID: <span style={{color:C.goldLt,fontFamily:"monospace",fontWeight:700}}>PP-{admDate}-{padAdmSerial(admSerial)}-{String(uid).padStart(3,"0")}</span>
                </div>
              </div>
              <PwdInp label="Password" value={form.password} onChange={e=>f("password",e.target.value)} placeholder="কমপক্ষে ৬ অক্ষর" required/>
              <PwdInp label="Confirm Password" value={form.confirmPwd} onChange={e=>f("confirmPwd",e.target.value)} required/>
              {err&&<div style={{color:C.red,fontSize:"0.8rem",marginBottom:10,background:`${C.red}10`,borderRadius:8,padding:"8px 12px"}}>⚠ {err}</div>}
              <Btn onClick={()=>{if(validate()){setErr("");setStep(1);}}} style={{width:"100%"}}>পরবর্তী →</Btn>
            </div>
          )}

          {step===1&&(
            <div>
              <div style={{background:`${C.gold}08`,border:`1px solid ${C.gold}25`,borderRadius:12,padding:"16px 18px",marginBottom:18}}>
                <div style={{fontSize:"0.68rem",color:C.gold,fontWeight:700,letterSpacing:"1px",marginBottom:10}}>🆔 STUDENT ID BUILDER</div>

                {/* Admission Date — manual */}
                <div style={{marginBottom:12}}>
                  <div style={{fontSize:"0.68rem",color:C.dim,fontWeight:700,letterSpacing:"1px",marginBottom:5}}>ADMISSION DATE (Manual)</div>
                  <input type="date" value={admDate} onChange={e=>setAdmDate(e.target.value)} style={{width:"100%",background:"rgba(255,255,255,0.07)",border:`1px solid ${C.sky}50`,color:C.white,borderRadius:7,padding:"7px 10px",fontFamily:"monospace",fontSize:"0.88rem",outline:"none",boxSizing:"border-box"}}/>
                </div>

                {/* Admission Serial — manual, 2–5 digits */}
                <div style={{marginBottom:14}}>
                  <div style={{fontSize:"0.68rem",color:C.dim,fontWeight:700,letterSpacing:"1px",marginBottom:5}}>ADMISSION SERIAL (Manual · 2–5 digits)</div>
                  <input value={admSerial} onChange={e=>setAdmSerial(e.target.value.replace(/\D/g,"").slice(0,5))} placeholder="e.g. 0001" maxLength={5} style={{width:"100%",background:"rgba(255,255,255,0.07)",border:`1px solid ${C.amber}60`,color:C.amber,borderRadius:7,padding:"7px 10px",fontFamily:"monospace",fontSize:"0.95rem",outline:"none",textAlign:"center",fontWeight:700,letterSpacing:"3px",boxSizing:"border-box"}}/>
                </div>

                {/* Visual ID segments */}
                <div style={{display:"flex",alignItems:"center",gap:5,flexWrap:"wrap",marginBottom:12}}>
                  {[{val:"PP",color:C.sky},{val:admDate||today,color:C.white},{val:padAdmSerial(admSerial),color:C.amber},{val:String(uid).padStart(3,"0"),color:C.green}].map((seg,i,arr)=>(
                    <span key={i} style={{display:"flex",alignItems:"center",gap:5}}>
                      <span style={{background:`${seg.color}15`,border:`1px solid ${seg.color}30`,borderRadius:7,padding:"6px 10px",fontFamily:"monospace",fontWeight:800,color:seg.color,fontSize:"0.85rem"}}>{seg.val}</span>
                      {i<arr.length-1&&<span style={{color:C.dim,fontWeight:700}}>-</span>}
                    </span>
                  ))}
                </div>

                {/* Final ID display */}
                <div style={{background:C.mid,borderRadius:8,padding:"10px 14px",marginBottom:10}}>
                  <div style={{fontSize:"0.6rem",color:C.dim,letterSpacing:"1px",marginBottom:3}}>✅ GENERATED STUDENT ID</div>
                  <div style={{fontFamily:"monospace",fontSize:"1.05rem",fontWeight:800,color:C.goldLt,letterSpacing:"1px"}}>{studentId}</div>
                </div>

                <div style={{fontSize:"0.68rem",color:C.dim,lineHeight:1.9}}>
                  <span style={{color:C.sky}}>PP</span> = Fixed Prefix &nbsp;·&nbsp;
                  <span style={{color:C.white}}>{admDate||today}</span> = Admission Date &nbsp;·&nbsp;
                  <span style={{color:C.amber}}>{padAdmSerial(admSerial)}</span> = Admission Serial (Manual) &nbsp;·&nbsp;
                  <span style={{color:C.green}}>{String(uid).padStart(3,"0")}</span> = User ID (Auto)
                </div>
              </div>
              <div style={{display:"flex",gap:10}}>
                <Btn onClick={()=>setStep(0)} variant="ghost" style={{flex:1}}>← পূর্ববর্তী</Btn>
                <Btn onClick={()=>setStep(2)} style={{flex:1}}>পরবর্তী →</Btn>
              </div>
            </div>
          )}

          {step===2&&(
            <div>
              <div style={{background:C.mid,borderRadius:12,padding:"16px 18px",marginBottom:18}}>
                <div style={{fontSize:"0.68rem",color:C.dim,marginBottom:10,letterSpacing:"1px"}}>CONFIRM DETAILS</div>
                {[["নাম (বাংলা)",form.nameBn],["Name (English)",form.nameEn],["Father",form.fatherName],["Mother",form.motherName],["DOB",form.dob],["Mobile",form.mobile],["Email",form.email||"—"],["Course",courseById(form.course)?.en],["Admission Date",admDate],["Admission Serial",padAdmSerial(admSerial)],["Auto User ID",String(uid).padStart(3,"0")],["Student ID",studentId]].map(([k,v])=>(
                  <div key={k} style={{display:"flex",justifyContent:"space-between",padding:"5px 0",borderBottom:`1px solid ${C.border}`}}>
                    <span style={{fontSize:"0.72rem",color:C.dim,fontWeight:600}}>{k}</span>
                    <span style={{fontWeight:600,color:k==="Student ID"?C.goldLt:C.text,fontFamily:["Student ID","Auto User ID","Admission Serial"].includes(k)?"monospace":"inherit"}}>{v}</span>
                  </div>
                ))}
              </div>
              <div style={{background:`${C.green}10`,border:`1px solid ${C.green}25`,borderRadius:10,padding:12,marginBottom:16,fontSize:"0.82rem",color:C.green}}>
                ✅ Account তৈরির পর সরাসরি Login করতে পারবেন।
              </div>
              <div style={{display:"flex",gap:10}}>
                <Btn onClick={()=>setStep(1)} variant="ghost" style={{flex:1}}>← পূর্ববর্তী</Btn>
                <Btn onClick={submit} variant="success" style={{flex:1}}>✅ Register করুন</Btn>
              </div>
            </div>
          )}
        </Card>
        <div style={{textAlign:"center",marginTop:14}}>
          <button onClick={onBack} style={{background:"none",border:"none",color:C.dim,fontSize:"0.78rem",cursor:"pointer",fontFamily:"inherit"}}>← ইতিমধ্যে অ্যাকাউন্ট আছে? Login করুন</button>
        </div>
      </div>
    </div>
  );
}

/* ════════════════════════════════════════════════════════════════
   REGISTRATION — CLIENT
   ════════════════════════════════════════════════════════════════ */
function RegisterClient({onBack,onSuccess,users,setUsers}) {
  const today=todayStr();
  const [regDate,setRegDate]=useState(today);
  const [form,setForm]=useState({nameBn:"",nameEn:"",fatherName:"",motherName:"",dob:"",mobile:"",email:"",password:"",confirmPwd:""});
  const [err,setErr]=useState("");
  const f=(k,v)=>setForm(p=>({...p,[k]:v}));

  const uid=nextUserId(users);
  const clientId=buildClientId(regDate||today,uid);

  const submit=async()=>{
    if(!form.nameBn||!form.nameEn||!form.fatherName||!form.motherName||!form.dob){setErr("সকল প্রয়োজনীয় তথ্য পূরণ করুন।");return;}
    if(!form.mobile){setErr("Mobile Number দিন।");return;}
    if(!form.password||form.password.length<6){setErr("Password কমপক্ষে ৬ অক্ষর।");return;}
    if(form.password!==form.confirmPwd){setErr("Password মিলছে না।");return;}
    const dup=users.find(u=>u.mobile===form.mobile||(form.email&&u.email===form.email));
    if(dup){setErr("এই Mobile/Email দিয়ে অ্যাকাউন্ট আছে।");return;}

    const demoSlots=users.filter(u=>u.isDemo&&u.role===ROLES.CLIENT);
    let newUsers=[...users];
    const newUser={userId:clientId,fullNameBn:form.nameBn,fullNameEn:form.nameEn,fatherName:form.fatherName,motherName:form.motherName,dob:form.dob,mobile:form.mobile,email:form.email,password:form.password,role:ROLES.CLIENT,status:STATUS.PENDING,regDate:regDate||today,autoUserId:uid,isDemo:false,createdAt:new Date().toISOString()};
    if(demoSlots.length>0){
      const replacedDemo=demoSlots[0];
      const idx=newUsers.findIndex(u=>u.userId===replacedDemo.userId);
      newUsers[idx]=newUser;
      await fbDelete(`users/${safeId(replacedDemo.userId)}`);
    } else {
      newUsers.push(newUser);
    }
    setUsers(newUsers);
    const clientRegData={userId:clientId,fullNameEn:form.nameEn,fullNameBn:form.nameBn||form.nameEn,fatherName:form.fatherName||"",motherName:form.motherName||"",dob:form.dob||"",mobile:form.mobile,email:form.email||"",password:form.password,role:ROLES.CLIENT,regDate:regDate||today,status:STATUS.PENDING,createdAt:Date.now()};
    await fbPush("pending_registrations",{...clientRegData,name:form.nameEn});
    await fbSet(`users/${safeId(clientId)}`,clientRegData);
    onSuccess("pendingSuccess",{id:clientId,name:form.nameEn,role:ROLES.CLIENT});
  };

  return (
    <div style={{minHeight:"100vh",background:`radial-gradient(ellipse at 30% 20%,${C.mid} 0%,${C.bg} 60%)`,display:"flex",alignItems:"center",justifyContent:"center",padding:16}}>
      <div style={{width:"100%",maxWidth:500}}>
        <div style={{textAlign:"center",marginBottom:20}}>
          <div style={{width:56,height:56,margin:"0 auto 10px",background:`linear-gradient(135deg,${C.skyDeep},${C.sky})`,borderRadius:14,display:"flex",alignItems:"center",justifyContent:"center"}}>
            <LogoImg size={44}/>
          </div>
          <div style={{fontSize:"1.25rem",fontWeight:900,color:C.white}}>🏢 Client Registration</div>
          <div style={{fontSize:"0.72rem",color:C.dim,marginTop:2}}>প্রযুক্তিপুঞ্জ · Client ID Preview: <span style={{fontFamily:"monospace",color:C.goldLt,fontWeight:700}}>{clientId}</span></div>
        </div>
        <Card glow>
          <Inp label="Registration Date" value={regDate} onChange={e=>setRegDate(e.target.value)} type="date" required/>
          <Inp label="পুরো নাম (বাংলা)" value={form.nameBn} onChange={e=>f("nameBn",e.target.value)} placeholder="যেমন: রহিম উদ্দিন" required/>
          <Inp label="Full Name (English)" value={form.nameEn} onChange={e=>f("nameEn",e.target.value)} placeholder="e.g. Rahim Uddin" required/>
          <Inp label="Father's Name (English)" value={form.fatherName} onChange={e=>f("fatherName",e.target.value)} placeholder="e.g. Karim Uddin" required/>
          <Inp label="Mother's Name (English)" value={form.motherName} onChange={e=>f("motherName",e.target.value)} placeholder="e.g. Sufia Begum" required/>
          <Inp label="Date of Birth" value={form.dob} onChange={e=>f("dob",e.target.value)} type="date" required/>
          <Inp label="Mobile Number" value={form.mobile} onChange={e=>f("mobile",e.target.value)} placeholder="01XXXXXXXXX" required/>
          <Inp label="Email Address (optional)" value={form.email} onChange={e=>f("email",e.target.value)} type="email" placeholder="example@email.com"/>
          <PwdInp label="Password" value={form.password} onChange={e=>f("password",e.target.value)} placeholder="কমপক্ষে ৬ অক্ষর" required/>
          <PwdInp label="Confirm Password" value={form.confirmPwd} onChange={e=>f("confirmPwd",e.target.value)} required/>
          {err&&<div style={{color:C.red,fontSize:"0.8rem",marginBottom:10,background:`${C.red}10`,borderRadius:8,padding:"8px 12px"}}>⚠ {err}</div>}
          <div style={{background:`${C.sky}08`,border:`1px solid ${C.sky}20`,borderRadius:10,padding:12,marginBottom:14,fontSize:"0.8rem",color:C.silver}}>
            🆔 Client ID: <strong style={{color:C.goldLt,fontFamily:"monospace"}}>{clientId}</strong><br/>
            <span style={{fontSize:"0.7rem",color:C.dim}}>Format: PP-YYYY-MM-DD-<span style={{color:C.green}}>USERID(Auto)</span></span>
          </div>
          <Btn onClick={submit} style={{width:"100%",padding:"12px"}}>✅ Register করুন</Btn>
        </Card>
        <div style={{textAlign:"center",marginTop:14}}>
          <button onClick={onBack} style={{background:"none",border:"none",color:C.dim,fontSize:"0.78rem",cursor:"pointer",fontFamily:"inherit"}}>← Login পেজে ফিরুন</button>
        </div>
      </div>
    </div>
  );
}

/* ════════════════════════════════════════════════════════════════
   REGISTRATION — ADMIN (pending until Chief Admin approves)
   ════════════════════════════════════════════════════════════════ */
function RegisterAdmin({onBack,users,setUsers}) {
  const today=todayStr();
  const [form,setForm]=useState({nameBn:"",nameEn:"",fatherName:"",motherName:"",dob:"",mobile:"",email:"",password:"",confirmPwd:""});
  const [err,setErr]=useState("");
  const [done,setDone]=useState(false);
  const [adminId,setAdminId]=useState("");
  const [isFirst,setIsFirst]=useState(false);
  const [generatedKey,setGeneratedKey]=useState(null);
  const f=(k,v)=>setForm(p=>({...p,[k]:v}));

  const submit=async()=>{
    if(!form.nameBn||!form.nameEn||!form.fatherName||!form.motherName||!form.dob){setErr("সকল প্রয়োজনীয় তথ্য পূরণ করুন।");return;}
    if(!form.mobile){setErr("Mobile Number দিন।");return;}
    if(!form.password||form.password.length<6){setErr("Password কমপক্ষে ৬ অক্ষর।");return;}
    if(form.password!==form.confirmPwd){setErr("Password মিলছে না।");return;}
    const dup=users.find(u=>u.mobile===form.mobile||(form.email&&u.email===form.email));
    if(dup){setErr("এই Mobile/Email দিয়ে অ্যাকাউন্ট আছে।");return;}

    const uid2=nextUserId(users);
    const id=buildAdminId(today,uid2);
    setAdminId(id);

    // প্রথম real admin = Chief Admin, বাকিরা pending
    const realAdmins=users.filter(u=>!u.isDemo&&(u.role===ROLES.ADMIN||u.role===ROLES.CHIEF_ADMIN||u.role===ROLES.PENDING_ADMIN));
    const isFirstAdmin = realAdmins.length === 0;
    const newRole = isFirstAdmin ? ROLES.CHIEF_ADMIN : ROLES.PENDING_ADMIN;
    const newStatus = isFirstAdmin ? STATUS.ACTIVE : STATUS.PENDING;
    const secretKey = isFirstAdmin ? genKey16() : null;

    const demoSlots=users.filter(u=>u.isDemo&&u.role===ROLES.ADMIN);
    let newUsers=[...users];
    const newUserObj={userId:id,fullNameBn:form.nameBn,fullNameEn:form.nameEn,fatherName:form.fatherName,motherName:form.motherName,dob:form.dob,mobile:form.mobile,email:form.email,password:form.password,role:newRole,status:newStatus,regDate:today,autoUserId:uid2,isDemo:false,isMainAdmin:isFirstAdmin,secretKey:secretKey||undefined,createdAt:new Date().toISOString()};
    if(demoSlots.length>0){
      const idx=newUsers.findIndex(u=>u.userId===demoSlots[0].userId);
      newUsers[idx]=newUserObj;
    } else {
      newUsers.push(newUserObj);
    }
    setUsers(newUsers);
    if(!isFirstAdmin){
      await fbSet(`pending_admins/${id.replace(/[.#$[\]/]/g,"-")}`,{userId:id,fullNameEn:form.nameEn,mobile:form.mobile,email:form.email,regDate:today,status:"pending"});
    }
    setIsFirst(isFirstAdmin);
    setGeneratedKey(secretKey);
    setDone(true);
  };

  if(done) return (
    <div style={{minHeight:"100vh",background:`radial-gradient(ellipse at 30% 20%,${C.mid} 0%,${C.bg} 60%)`,display:"flex",alignItems:"center",justifyContent:"center",padding:16}}>
      <div style={{width:"100%",maxWidth:480}}>
        <Card glow style={{textAlign:"center",padding:"40px 30px"}}>
          {isFirst ? (
            <>
              <div style={{fontSize:"3rem",marginBottom:12}}>👑</div>
              <div style={{fontSize:"1.2rem",fontWeight:800,color:C.white,marginBottom:6}}>Chief Admin তৈরি সফল!</div>
              <div style={{background:C.mid,borderRadius:12,padding:"16px 18px",marginBottom:14,textAlign:"left"}}>
                <div style={{fontSize:"0.65rem",color:C.dim,letterSpacing:"1px",marginBottom:4}}>YOUR CHIEF ADMIN ID</div>
                <div style={{fontFamily:"monospace",fontSize:"1rem",fontWeight:800,color:C.goldLt}}>{adminId}</div>
              </div>
              {generatedKey&&(
                <div style={{background:`${C.red}10`,border:`2px solid ${C.red}30`,borderRadius:12,padding:"16px 18px",marginBottom:16,textAlign:"left"}}>
                  <div style={{fontSize:"0.68rem",color:C.red,fontWeight:700,letterSpacing:"1px",marginBottom:6}}>⚠️ SECRET KEY — শুধুমাত্র একবার দেখাবে!</div>
                  <div style={{fontFamily:"monospace",fontSize:"1.1rem",fontWeight:900,color:C.goldLt,letterSpacing:"2px"}}>{generatedKey}</div>
                  <div style={{fontSize:"0.72rem",color:C.amber,marginTop:8,lineHeight:1.7}}>এই key সংরক্ষণ করুন। পাসওয়ার্ড ভুললে এটা দরকার হবে। আর কখনো দেখাবে না।</div>
                </div>
              )}
              <div style={{background:`${C.green}10`,border:`1px solid ${C.green}25`,borderRadius:10,padding:12,marginBottom:18,fontSize:"0.82rem",color:C.green,textAlign:"left"}}>
                ✅ আপনি সিস্টেমের প্রথম Admin। আপনি স্বয়ংক্রিয়ভাবে <strong>Chief Administrator</strong> হিসেবে সক্রিয় হয়েছেন।
              </div>
              <Btn onClick={onBack} style={{width:"100%"}}>← Login করুন</Btn>
            </>
          ) : (
            <>
              <div style={{fontSize:"3rem",marginBottom:16}}>⏳</div>
              <div style={{fontSize:"1.2rem",fontWeight:800,color:C.white,marginBottom:8}}>আবেদন জমা হয়েছে!</div>
              <div style={{background:C.mid,borderRadius:12,padding:"16px 18px",marginBottom:18,textAlign:"left"}}>
                <div style={{fontSize:"0.65rem",color:C.dim,letterSpacing:"1px",marginBottom:4}}>YOUR ADMIN ID</div>
                <div style={{fontFamily:"monospace",fontSize:"1rem",fontWeight:800,color:C.goldLt}}>{adminId}</div>
              </div>
              <div style={{background:`${C.amber}10`,border:`1px solid ${C.amber}25`,borderRadius:10,padding:14,marginBottom:20,fontSize:"0.82rem",color:C.amber,lineHeight:1.8,textAlign:"left"}}>
                ⚠️ আপনার Admin অ্যাকাউন্ট এখন <strong>Pending</strong>।<br/>
                Chief Administrator অ্যাপ্রুভ করলে Login করতে পারবেন।
              </div>
              <Btn onClick={onBack} style={{width:"100%"}}>← Login পেজে ফিরুন</Btn>
            </>
          )}
        </Card>
      </div>
    </div>
  );

  return (
    <div style={{minHeight:"100vh",background:`radial-gradient(ellipse at 30% 20%,${C.mid} 0%,${C.bg} 60%)`,display:"flex",alignItems:"center",justifyContent:"center",padding:16}}>
      <div style={{width:"100%",maxWidth:500}}>
        <div style={{textAlign:"center",marginBottom:20}}>
          <div style={{width:56,height:56,margin:"0 auto 10px",background:`linear-gradient(135deg,${C.skyDeep},${C.sky})`,borderRadius:14,display:"flex",alignItems:"center",justifyContent:"center"}}>
            <LogoImg size={44}/>
          </div>
          <div style={{fontSize:"1.25rem",fontWeight:900,color:C.white}}>🔐 Admin Registration</div>
          <div style={{fontSize:"0.72rem",color:C.amber,marginTop:2}}>Chief Administrator অ্যাপ্রুভাল প্রয়োজন</div>
        </div>
        <Card glow>
          <div style={{background:`${C.amber}10`,border:`1px solid ${C.amber}25`,borderRadius:10,padding:12,marginBottom:18,fontSize:"0.82rem",color:C.amber}}>
            ℹ️ Admin registration-এর পর Chief Admin অ্যাপ্রুভ করলে তবেই Login করতে পারবেন।
          </div>
          <Inp label="পুরো নাম (বাংলা)" value={form.nameBn} onChange={e=>f("nameBn",e.target.value)} placeholder="যেমন: মোঃ রফিকুল ইসলাম" required/>
          <Inp label="Full Name (English)" value={form.nameEn} onChange={e=>f("nameEn",e.target.value)} placeholder="e.g. Md. Rafiqul Islam" required/>
          <Inp label="Father's Name (English)" value={form.fatherName} onChange={e=>f("fatherName",e.target.value)} placeholder="e.g. Abdul Islam" required/>
          <Inp label="Mother's Name (English)" value={form.motherName} onChange={e=>f("motherName",e.target.value)} placeholder="e.g. Fatema Begum" required/>
          <Inp label="Date of Birth" value={form.dob} onChange={e=>f("dob",e.target.value)} type="date" required/>
          <Inp label="Mobile Number" value={form.mobile} onChange={e=>f("mobile",e.target.value)} placeholder="01XXXXXXXXX" required/>
          <Inp label="Email Address (optional)" value={form.email} onChange={e=>f("email",e.target.value)} type="email" placeholder="example@email.com"/>
          <PwdInp label="Password" value={form.password} onChange={e=>f("password",e.target.value)} placeholder="কমপক্ষে ৬ অক্ষর" required/>
          <PwdInp label="Confirm Password" value={form.confirmPwd} onChange={e=>f("confirmPwd",e.target.value)} required/>
          {err&&<div style={{color:C.red,fontSize:"0.8rem",marginBottom:10,background:`${C.red}10`,borderRadius:8,padding:"8px 12px"}}>⚠ {err}</div>}
          <div style={{background:`${C.sky}08`,border:`1px solid ${C.sky}20`,borderRadius:10,padding:12,marginBottom:14,fontSize:"0.8rem",color:C.silver}}>
            🆔 Admin ID: <strong style={{color:C.goldLt,fontFamily:"monospace"}}>{buildAdminId(today,nextUserId(users))}</strong><br/>
            <span style={{fontSize:"0.7rem",color:C.dim}}>Format: PP-YYYY-MM-DD-<span style={{color:C.green}}>USERID(Auto)</span></span>
          </div>
          <Btn onClick={submit} style={{width:"100%",padding:"12px"}}>📤 আবেদন জমা দিন</Btn>
        </Card>
        <div style={{textAlign:"center",marginTop:14}}>
          <button onClick={onBack} style={{background:"none",border:"none",color:C.dim,fontSize:"0.78rem",cursor:"pointer",fontFamily:"inherit"}}>← Login পেজে ফিরুন</button>
        </div>
      </div>
    </div>
  );
}

/* ════════════════════════════════════════════════════════════════
   REGISTER SELECTOR
   ════════════════════════════════════════════════════════════════ */
function RegisterSelector({onBack,onSuccess,users,setUsers}) {
  const [type,setType]=useState(null);
  const [pendingInfo,setPendingInfo]=useState(null);
  const handleSuccess=(screen,data)=>{
    if(screen==="pendingSuccess"){setPendingInfo(data);setType("pendingDone");}
    else onSuccess(screen,data);
  };
  if(type==="pendingDone"&&pendingInfo) return (
    <div style={{minHeight:"100vh",background:`radial-gradient(ellipse at 30% 20%,${C.mid} 0%,${C.bg} 60%)`,display:"flex",alignItems:"center",justifyContent:"center",padding:16}}>
      <div style={{width:"100%",maxWidth:460}}>
        <Card glow style={{textAlign:"center",padding:"40px 28px"}}>
          <div style={{fontSize:"3rem",marginBottom:14}}>✅</div>
          <div style={{fontSize:"1.15rem",fontWeight:900,color:C.green,marginBottom:10}}>আপনার নিবন্ধন সফলভাবে জমা হয়েছে।</div>
          <div style={{background:`${C.amber}10`,border:`1px solid ${C.amber}25`,borderRadius:12,padding:"16px 18px",marginBottom:16,fontSize:"0.85rem",color:C.amber,lineHeight:2,textAlign:"left"}}>
            আপনার অ্যাকাউন্ট বর্তমানে <strong>Admin Approval-এর অপেক্ষায়</strong> রয়েছে।<br/>
            অ্যাকাউন্ট অনুমোদিত হলে আপনি Login করতে পারবেন।<br/>
            <strong style={{color:C.goldLt}}>বর্তমান স্ট্যাটাস: ⏳ Pending Approval</strong>
          </div>
          <div style={{background:C.mid,borderRadius:10,padding:"12px 16px",marginBottom:18,fontSize:"0.8rem"}}>
            <div style={{color:C.dim,fontSize:"0.68rem",letterSpacing:"1px",marginBottom:4}}>YOUR USER ID</div>
            <div style={{fontFamily:"monospace",fontWeight:800,color:C.goldLt,fontSize:"1rem"}}>{pendingInfo.id}</div>
          </div>
          <Btn onClick={onBack} style={{width:"100%",padding:"12px"}}>← Login পেজে ফিরুন</Btn>
        </Card>
      </div>
    </div>
  );
  if(type==="student") return <RegisterStudent onBack={()=>setType(null)} onSuccess={handleSuccess} users={users} setUsers={setUsers}/>;
  if(type==="client")  return <RegisterClient  onBack={()=>setType(null)} onSuccess={handleSuccess} users={users} setUsers={setUsers}/>;
  if(type==="admin")   return <RegisterAdmin   onBack={()=>setType(null)} users={users} setUsers={setUsers}/>;
  return (
    <div style={{minHeight:"100vh",background:`radial-gradient(ellipse at 30% 20%,${C.mid} 0%,${C.bg} 60%)`,display:"flex",alignItems:"center",justifyContent:"center",padding:16}}>
      <div style={{width:"100%",maxWidth:460}}>
        <div style={{textAlign:"center",marginBottom:24}}>
          <div style={{width:64,height:64,margin:"0 auto 12px",background:`linear-gradient(135deg,${C.skyDeep},${C.sky})`,borderRadius:18,display:"flex",alignItems:"center",justifyContent:"center"}}>
            <LogoImg size={50}/>
          </div>
          <div style={{fontSize:"1.4rem",fontWeight:900,color:C.white}}>নতুন অ্যাকাউন্ট তৈরি করুন</div>
          <div style={{fontSize:"0.73rem",color:C.dim,marginTop:2}}>প্রযুক্তিপুঞ্জ Registration</div>
        </div>
        <Card glow>
          <div style={{fontSize:"0.85rem",fontWeight:700,color:C.white,marginBottom:16}}>Account Type বেছে নিন:</div>
          {[
            {key:"student",icon:"🎓",label:"Student",sub:"কোর্স শিক্ষার্থী · Admin অনুমোদন প্রয়োজন",color:C.sky},
            {key:"client", icon:"🏢",label:"Client", sub:"সার্ভিস গ্রাহক · Admin অনুমোদন প্রয়োজন",color:C.green},
            {key:"admin",  icon:"🔐",label:"Admin",  sub:"প্রথম Admin = Chief Admin · পরবর্তীরা অ্যাপ্রুভাল প্রয়োজন",color:C.amber},
          ].map(t=>(
            <button key={t.key} onClick={()=>setType(t.key)} style={{display:"flex",alignItems:"center",gap:14,width:"100%",background:C.mid,border:`1px solid ${t.color}25`,borderRadius:12,padding:"16px 18px",cursor:"pointer",marginBottom:10,textAlign:"left",transition:"all 0.15s"}}>
              <span style={{fontSize:"1.8rem"}}>{t.icon}</span>
              <div style={{flex:1}}>
                <div style={{fontWeight:700,color:t.color,fontSize:"0.95rem"}}>{t.label}</div>
                <div style={{fontSize:"0.73rem",color:C.dim,marginTop:2}}>{t.sub}</div>
              </div>
              <span style={{color:C.dim,fontSize:"1.2rem"}}>→</span>
            </button>
          ))}
        </Card>
        <div style={{textAlign:"center",marginTop:14}}>
          <button onClick={onBack} style={{background:"none",border:"none",color:C.dim,fontSize:"0.78rem",cursor:"pointer",fontFamily:"inherit"}}>← ইতিমধ্যে অ্যাকাউন্ট আছে? Login করুন</button>
        </div>
      </div>
    </div>
  );
}

/* ════════════════════════════════════════════════════════════════
   FIRST ADMIN SETUP — Chief Administrator তৈরি (v18 Multi-Step)
   Step 1: ফর্ম (নাম, email, secret email) → Next
   Step 2: System-generated 16-digit secret code দেখানো (একবারই)
   Step 3: সেই code বসিয়ে verify করুন
   Step 4: "Submit Successful! Please set up your password"
   Step 5: Password set → Account তৈরি → Login
   ════════════════════════════════════════════════════════════════ */
function FirstAdminSetup({onDone,users,setUsers}) {
  const [checking,setChecking]=useState(true);
  const [hasAdmin,setHasAdmin]=useState(false);
  const [step,setStep]=useState(1); // 1,2,3,4,5
  const [form,setForm]=useState({fullName:"",email:"",secretEmail:""});
  const [password,setPassword]=useState("");
  const [confirmPwd,setConfirmPwd]=useState("");
  const handleFocus=(e)=>{/* scroll removed — prevents keyboard jump on mobile */};
  const [err,setErr]=useState("");
  const [loading,setLoading]=useState(false);
  const [generatedCode,setGeneratedCode]=useState(""); // system-issued 16-char code
  const [codeInput,setCodeInput]=useState("");         // user types back the code
  const [savedCopy,setSavedCopy]=useState(false);      // checkbox — I have saved this
  const [adminId,setAdminId]=useState("");
  const f=(k,v)=>setForm(p=>({...p,[k]:v}));

  // Firebase + local check
  useEffect(()=>{
    const check=async()=>{
      const localChief=users.find(u=>!u.isDemo&&(u.role===ROLES.CHIEF_ADMIN||u.isMainAdmin));
      if(localChief){setHasAdmin(true);setChecking(false);return;}
      const fbData=await fbGet("chief_admin");
      if(fbData&&fbData.userId) setHasAdmin(true);
      setChecking(false);
    };
    check();
  },[]);

  /* ── Step 1 → 2 : validate form + check secret email ── */
  const handleNext=()=>{
    setErr("");
    if(!form.fullName.trim()){setErr("Full Name দিন।");return;}
    if(!form.email.trim()){setErr("Email দিন।");return;}
    if(!form.secretEmail.trim()){setErr("Secret Email দিন।");return;}
    if(form.secretEmail.trim().toLowerCase()!==CHIEF_SECRET_EMAIL.toLowerCase()){
      setErr("Secret Email সঠিক নয়। সিস্টেম অ্যাক্সেস অস্বীকৃত।");return;
    }
    // Generate 16-digit code
    const code=genKey16();
    setGeneratedCode(code);
    setStep(2);
  };

  /* ── Step 2 → 3 : user confirms they saved the code ── */
  const handleCodeSaved=()=>{
    setErr("");
    if(!savedCopy){setErr("নিশ্চিত করুন যে আপনি Secret Code সংরক্ষণ করেছেন।");return;}
    setStep(3);
  };

  /* ── Step 3 → 4 : verify typed code matches issued code ── */
  const handleVerifyCode=()=>{
    setErr("");
    if(codeInput.trim().toUpperCase()!==generatedCode.toUpperCase()){
      setErr("Secret Code মিলছে না। সঠিক code টাইপ করুন।");return;
    }
    setStep(4);
  };

  /* ── Step 5 : set password & create account ── */
  const handleCreateAccount=async()=>{
    setErr("");
    if(!password||password.length<8){setErr("Password কমপক্ষে ৮ অক্ষর হতে হবে।");return;}
    if(password!==confirmPwd){setErr("Password দুটো মিলছে না।");return;}
    setLoading(true);
    const today=todayStr();
    const uid3=nextUserId(users);
    const id=buildAdminId(today,uid3);
    setAdminId(id);
    const newUser={
      userId:id, fullNameBn:form.fullName, fullNameEn:form.fullName,
      fatherName:"", motherName:"", dob:"", mobile:"",
      email:form.email, password:password,
      role:ROLES.CHIEF_ADMIN, status:STATUS.ACTIVE,
      regDate:today, isDemo:false, isMainAdmin:true,
      secretKey:generatedCode, title:"Chief Administrator",
      createdAt:new Date().toISOString(),
    };
    await fbSet("chief_admin",{userId:id,email:form.email,createdAt:Date.now(),status:"active"});
    // Also save to users/ path so notifyAllAdmins can find this admin
    await fbSet(`users/${id.replace(/[.#$[\]/]/g,"-")}`, {...newUser});
    const demoAdmSlots=users.filter(u=>u.isDemo&&u.role===ROLES.ADMIN);
    let newUsers=[...users];
    if(demoAdmSlots.length>0){
      const idx=newUsers.findIndex(u=>u.userId===demoAdmSlots[0].userId);
      newUsers[idx]=newUser;
    } else { newUsers.push(newUser); }
    setUsers(newUsers);
    setLoading(false);
    setStep(6); // success
  };

  /* ── System loading ── */
  if(checking) return (
    <div style={{minHeight:"100vh",background:`radial-gradient(ellipse at center,${C.mid} 0%,${C.bg} 60%)`,display:"flex",alignItems:"center",justifyContent:"center"}}>
      <div style={{textAlign:"center"}}>
        <div style={{fontSize:"2rem",marginBottom:12,animation:"spin 1s linear infinite",display:"inline-block"}}>⚙️</div>
        <div style={{color:C.silver,fontSize:"0.9rem"}}>System initializing...</div>
      </div>
    </div>
  );

  /* ── Already has chief admin ── */
  if(hasAdmin) return (
    <div style={{minHeight:"100vh",background:`radial-gradient(ellipse at center,${C.mid} 0%,${C.bg} 60%)`,display:"flex",alignItems:"center",justifyContent:"center",padding:16}}>
      <div style={{width:"100%",maxWidth:440}}>
        <Card glow style={{textAlign:"center",padding:"40px 30px"}}>
          <div style={{fontSize:"2.5rem",marginBottom:14}}>🔒</div>
          <div style={{fontSize:"1.1rem",fontWeight:800,color:C.white,marginBottom:8}}>Chief Admin ইতিমধ্যে বিদ্যমান</div>
          <div style={{fontSize:"0.83rem",color:C.silver,marginBottom:20,lineHeight:1.8}}>
            Case B: সিস্টেমে Chief Administrator আগে থেকেই আছেন।<br/>নতুন Chief Admin তৈরি করা সম্ভব নয়।
          </div>
          <Btn onClick={onDone} style={{width:"100%"}}>← Login পেজে যান</Btn>
        </Card>
      </div>
    </div>
  );

  const STEPS=["তথ্য","Secret Code","যাচাই","Password","সম্পন্ন"];

  const Wrap=({children})=>(
    <div style={{background:`radial-gradient(ellipse at center,${C.mid} 0%,${C.bg} 60%)`,padding:"24px 16px 120px",overflowY:"auto",WebkitOverflowScrolling:"touch",minHeight:"100%",boxSizing:"border-box"}}>
      <div style={{width:"100%",maxWidth:500,margin:"0 auto"}}>
        {/* Header */}
        <div style={{textAlign:"center",marginBottom:22}}>
          <div style={{width:64,height:64,margin:"0 auto 12px",background:`linear-gradient(135deg,#a07010,${C.gold})`,borderRadius:18,display:"flex",alignItems:"center",justifyContent:"center",boxShadow:`0 8px 30px ${C.gold}30`}}>
            <LogoImg size={50}/>
          </div>
          <div style={{fontSize:"1.4rem",fontWeight:900,color:C.white}}>First Admin Setup</div>
          <div style={{fontSize:"0.73rem",color:C.gold,marginTop:3}}>Chief Administrator Registration · OWNER Account</div>
        </div>
        <Card glow>
          <StepBar steps={STEPS} current={Math.min(step-1,4)}/>
          {children}
        </Card>
        <div style={{textAlign:"center",marginTop:14}}>
          <button onClick={onDone} style={{background:"none",border:"none",color:C.dim,fontSize:"0.78rem",cursor:"pointer",fontFamily:"inherit"}}>← Login পেজে ফিরুন</button>
        </div>
      </div>
    </div>
  );

  /* ── STEP 1: Form ── */
  if(step===1) return (
    <Wrap>
      <div style={{background:`${C.gold}08`,border:`1px solid ${C.gold}20`,borderRadius:10,padding:"12px 14px",marginBottom:20,fontSize:"0.82rem",color:C.amber,lineHeight:1.8}}>
        ℹ️ <strong>Case A:</strong> সিস্টেমে কোনো Admin নেই। প্রথম Admin তৈরি করুন।<br/>
        এই account স্বয়ংক্রিয়ভাবে <strong>Chief Administrator (OWNER)</strong> হবে।
      </div>
      <div style={{marginBottom:14}}>
        <div style={{fontSize:"0.72rem",fontWeight:700,color:C.dim,letterSpacing:"1px",textTransform:"uppercase",marginBottom:5}}>Full Name <span style={{color:C.red}}>*</span></div>
        <input value={form.fullName} onChange={e=>f("fullName",e.target.value)} onFocus={handleFocus} placeholder="e.g. Md. Fakhrul Islam Sagor" inputMode="text" autoComplete="off" style={{width:"100%",background:"rgba(255,255,255,0.05)",border:`1px solid ${C.border}`,color:C.white,borderRadius:8,padding:"9px 12px",fontFamily:"inherit",fontSize:"1rem",outline:"none",boxSizing:"border-box"}}/>
      </div>
      <div style={{marginBottom:14}}>
        <div style={{fontSize:"0.72rem",fontWeight:700,color:C.dim,letterSpacing:"1px",textTransform:"uppercase",marginBottom:5}}>Email <span style={{color:C.red}}>*</span></div>
        <input type="email" value={form.email} onChange={e=>f("email",e.target.value)} onFocus={handleFocus} placeholder="admin@example.com" inputMode="email" autoComplete="off" style={{width:"100%",background:"rgba(255,255,255,0.05)",border:`1px solid ${C.border}`,color:C.white,borderRadius:8,padding:"9px 12px",fontFamily:"inherit",fontSize:"1rem",outline:"none",boxSizing:"border-box"}}/>
      </div>
      <div style={{marginBottom:14}}>
        <div style={{fontSize:"0.72rem",fontWeight:700,color:C.red,letterSpacing:"1px",textTransform:"uppercase",marginBottom:5}}>🔒 Secret Email (System Verification) <span style={{color:C.red}}>*</span></div>
        <input type="email" value={form.secretEmail} onChange={e=>f("secretEmail",e.target.value)} onFocus={handleFocus} placeholder="System secret email দিন" inputMode="email" autoComplete="off" style={{width:"100%",background:"rgba(255,0,0,0.05)",border:`1px solid ${C.red}30`,color:C.white,borderRadius:8,padding:"9px 12px",fontFamily:"inherit",fontSize:"1rem",outline:"none",boxSizing:"border-box"}}/>
        <div style={{fontSize:"0.68rem",color:C.dim,marginTop:4}}>👉 Server-side verification। ভুল হলে এগোনো যাবে না।</div>
      </div>
      {err&&<div style={{color:C.red,fontSize:"0.8rem",marginBottom:12,background:`${C.red}10`,border:`1px solid ${C.red}25`,borderRadius:8,padding:"10px 12px"}}>⚠ {err}</div>}
      <Btn onClick={handleNext} variant="gold" style={{width:"100%",padding:"12px",fontSize:"0.95rem"}}>
        পরবর্তী →
      </Btn>
    </Wrap>
  );

  /* ── STEP 2: Show generated 16-digit code (once only) ── */
  if(step===2) return (
    <Wrap>
      <div style={{background:`${C.sky}08`,border:`1px solid ${C.sky}20`,borderRadius:10,padding:"10px 14px",marginBottom:16,fontSize:"0.8rem",color:C.sky}}>
        ✅ Email যাচাই সফল। সিস্টেম আপনার জন্য একটি <strong>16-digit Secret Code</strong> তৈরি করেছে।
      </div>
      <div style={{background:"#0d0d0d",border:`2px solid ${C.red}50`,borderRadius:14,padding:"20px",marginBottom:16}}>
        <div style={{display:"flex",alignItems:"center",gap:8,marginBottom:12}}>
          <span style={{fontSize:"1.3rem"}}>🔑</span>
          <div>
            <div style={{fontSize:"0.72rem",color:C.red,fontWeight:700,letterSpacing:"1px",textTransform:"uppercase"}}>Secret Code — শুধুমাত্র একবারই দেখাবে!</div>
            <div style={{fontSize:"0.65rem",color:C.dim,marginTop:2}}>এটা আর কখনো দেখা যাবে না। এখনই সংরক্ষণ করুন।</div>
          </div>
        </div>
        <div style={{fontFamily:"monospace",fontSize:"1.4rem",fontWeight:900,color:C.goldLt,letterSpacing:"4px",textAlign:"center",padding:"14px 10px",background:"rgba(0,0,0,0.5)",borderRadius:10,border:`1px solid ${C.gold}30`,userSelect:"text"}}>
          {generatedCode}
        </div>
        <div style={{fontSize:"0.7rem",color:C.amber,marginTop:10,lineHeight:1.8,textAlign:"center"}}>
          ⚠️ এই Code account recovery-তে লাগবে।<br/>
          হারিয়ে গেলে account পুনরুদ্ধার সম্ভব নয়।
        </div>
      </div>
      {/* Confirm saved checkbox */}
      <label style={{display:"flex",alignItems:"flex-start",gap:10,cursor:"pointer",marginBottom:18,padding:"12px 14px",background:`${C.amber}08`,border:`1px solid ${C.amber}25`,borderRadius:10}}>
        <input type="checkbox" checked={savedCopy} onChange={e=>setSavedCopy(e.target.checked)} style={{marginTop:3,accentColor:C.gold,width:16,height:16,flexShrink:0}}/>
        <span style={{fontSize:"0.82rem",color:C.amber,lineHeight:1.6}}>
          আমি এই Secret Code একটি নিরাপদ জায়গায় সংরক্ষণ করেছি এবং বুঝতে পেরেছি যে এটা আর দেখা যাবে না।
        </span>
      </label>
      {err&&<div style={{color:C.red,fontSize:"0.8rem",marginBottom:12,background:`${C.red}10`,border:`1px solid ${C.red}25`,borderRadius:8,padding:"10px 12px"}}>⚠ {err}</div>}
      <Btn onClick={handleCodeSaved} variant="gold" style={{width:"100%",padding:"12px",fontSize:"0.95rem"}}>
        পরবর্তী →
      </Btn>
    </Wrap>
  );

  /* ── STEP 3: Verify code ── */
  if(step===3) return (
    <Wrap>
      <div style={{background:`${C.mid}`,borderRadius:10,padding:"12px 14px",marginBottom:18,fontSize:"0.82rem",color:C.silver,lineHeight:1.7}}>
        🔐 নিশ্চিত করতে উপরে দেওয়া <strong style={{color:C.goldLt}}>16-digit Secret Code</strong>টি হুবহু নিচে টাইপ করুন।
      </div>
      <div style={{marginBottom:16}}>
        <div style={{fontSize:"0.72rem",fontWeight:700,color:C.dim,letterSpacing:"1px",textTransform:"uppercase",marginBottom:6}}>Secret Code লিখুন <span style={{color:C.red}}>*</span></div>
        <input
          value={codeInput}
          onChange={e=>setCodeInput(e.target.value.toUpperCase())}
          placeholder="16-digit code এখানে লিখুন"
          style={{width:"100%",background:"rgba(255,255,0,0.03)",border:`1px solid ${C.gold}40`,color:C.goldLt,borderRadius:8,padding:"12px 14px",fontFamily:"monospace",fontSize:"1rem",fontWeight:700,outline:"none",boxSizing:"border-box",letterSpacing:"2px",textAlign:"center"}}
        />
        <div style={{fontSize:"0.68rem",color:C.dim,marginTop:4,textAlign:"center"}}>
          শুধুমাত্র uppercase — যেমন: ABCD1234EFGH5678
        </div>
      </div>
      {err&&<div style={{color:C.red,fontSize:"0.8rem",marginBottom:12,background:`${C.red}10`,border:`1px solid ${C.red}25`,borderRadius:8,padding:"10px 12px"}}>⚠ {err}</div>}
      <Btn onClick={handleVerifyCode} variant="gold" style={{width:"100%",padding:"12px",fontSize:"0.95rem"}}>
        যাচাই করুন →
      </Btn>
    </Wrap>
  );

  /* ── STEP 4: Submit Successful — set password ── */
  if(step===4) return (
    <Wrap>
      <div style={{textAlign:"center",marginBottom:20}}>
        <div style={{fontSize:"2.5rem",marginBottom:8}}>✅</div>
        <div style={{fontSize:"1.1rem",fontWeight:800,color:C.green,marginBottom:4}}>Submit Successful!</div>
        <div style={{fontSize:"0.85rem",color:C.silver,lineHeight:1.7}}>Please set up your password।<br/>এরপর আপনার account সক্রিয় হবে।</div>
      </div>
      <PwdInp label="নতুন Password" value={password} onChange={e=>setPassword(e.target.value)} placeholder="কমপক্ষে ৮ অক্ষর" required/>
      <PwdInp label="Confirm Password" value={confirmPwd} onChange={e=>setConfirmPwd(e.target.value)} required/>
      {err&&<div style={{color:C.red,fontSize:"0.8rem",marginBottom:12,background:`${C.red}10`,border:`1px solid ${C.red}25`,borderRadius:8,padding:"10px 12px"}}>⚠ {err}</div>}
      <Btn onClick={handleCreateAccount} disabled={loading} variant="gold" style={{width:"100%",padding:"12px",fontSize:"0.95rem"}}>
        {loading?"Creating...":"✅ Account তৈরি করুন"}
      </Btn>
    </Wrap>
  );

  /* ── STEP 6: All done ── */
  return (
    <div style={{minHeight:"100vh",background:`radial-gradient(ellipse at center,${C.mid} 0%,${C.bg} 60%)`,display:"flex",alignItems:"center",justifyContent:"center",padding:16}}>
      <div style={{width:"100%",maxWidth:500}}>
        <Card glow style={{padding:"36px 32px"}}>
          <div style={{textAlign:"center",marginBottom:20}}>
            <div style={{fontSize:"3rem",marginBottom:10}}>🎉</div>
            <div style={{fontSize:"1.3rem",fontWeight:900,color:C.white}}>Chief Administrator তৈরি সফল!</div>
            <div style={{fontSize:"0.78rem",color:C.sky,marginTop:4}}>role: OWNER · title: Chief Administrator</div>
          </div>
          <div style={{background:C.mid,borderRadius:12,padding:"16px 18px",marginBottom:16}}>
            <div style={{fontSize:"0.65rem",color:C.dim,letterSpacing:"1px",marginBottom:4}}>CHIEF ADMIN ID</div>
            <div style={{fontFamily:"monospace",fontSize:"1rem",fontWeight:800,color:C.goldLt}}>{adminId}</div>
          </div>
          <div style={{background:`${C.green}08`,border:`1px solid ${C.green}20`,borderRadius:10,padding:12,marginBottom:16,fontSize:"0.8rem",color:C.green,lineHeight:1.8}}>
            ✅ Status: ACTIVE<br/>
            ✅ Role: Chief Administrator (OWNER)<br/>
            ✅ Login করতে পারবেন: User ID / Secret Email / Mobile + Password<br/>
            🔒 Recovery-তে Secret Code প্রয়োজন হবে
          </div>
          <div style={{background:`${C.amber}10`,border:`1px solid ${C.amber}25`,borderRadius:10,padding:"10px 14px",marginBottom:20,fontSize:"0.78rem",color:C.amber,lineHeight:1.7}}>
            ⚠️ Login করুন: আপনার <strong>User ID</strong> অথবা <strong>Email</strong> এবং নতুন <strong>Password</strong> দিয়ে।<br/>
            Recovery-তে সেই <strong>Secret Code</strong> লাগবে — যা আপনি সংরক্ষণ করেছেন।
          </div>
          <Btn onClick={onDone} style={{width:"100%",padding:"13px",fontSize:"0.95rem"}}>← Login করুন</Btn>
        </Card>
      </div>
    </div>
  );
}


/* ════════════════════════════════════════════════════════════════
   PENDING REGISTRATIONS PANEL — Admin & Chief Admin
   Approve / Reject pending Student & Client registrations
   ════════════════════════════════════════════════════════════════ */
function PendingRegistrationsPanel({users,setUsers,currentUser}) {
  const isChief=currentUser?.isMainAdmin||currentUser?.role===ROLES.CHIEF_ADMIN;
  const [search,setSearch]=useState("");
  const [rejectModal,setRejectModal]=useState(null);
  const [rejectNote,setRejectNote]=useState("");
  const [fbPending,setFbPending]=useState([]);

  // Load directly from Firebase pending_registrations every 8s
  useEffect(()=>{
    const load=async()=>{
      const d=await fbGet("pending_registrations");
      if(d){
        const arr=Object.entries(d).map(([k,v])=>({...v,_fbKey:k}))
          .filter(u=>u.status==="pending"&&(u.role===ROLES.STUDENT||u.role===ROLES.CLIENT));
        setFbPending(arr);
        // also sync to parent users state
        setUsers(prev=>{
          const prevIds=new Set(prev.map(u=>u.userId));
          const newOnes=arr.filter(u=>!prevIds.has(u.userId));
          return newOnes.length>0?[...prev,...newOnes]:prev;
        });
      }
    };
    load();
    const i=setInterval(load,8000);
    return()=>clearInterval(i);
  },[]);

  // Merge in-memory + Firebase pending, dedupe
  const allPending=[...users.filter(u=>!u.isDemo&&u.status===STATUS.PENDING&&(u.role===ROLES.STUDENT||u.role===ROLES.CLIENT))];
  const inMemIds=new Set(allPending.map(u=>u.userId));
  const merged=[...allPending,...fbPending.filter(u=>!inMemIds.has(u.userId))];
  const pending=merged.filter(u=>!search||u.fullNameEn?.toLowerCase().includes(search.toLowerCase())||u.userId?.includes(search)||u.mobile?.includes(search));

  const approve=async(userId)=>{
    setUsers(prev=>prev.map(u=>u.userId===userId?{...u,status:STATUS.ACTIVE}:u));
    const fbEntry=fbPending.find(u=>u.userId===userId);
    const fbKey=fbEntry?._fbKey||safeId(userId);
    await fbPatch(`pending_registrations/${fbKey}`,{status:"approved",approvedAt:Date.now(),approvedBy:currentUser?.id});
    await fbPatch(`users/${safeId(userId)}`,{status:STATUS.ACTIVE,approvedAt:Date.now(),approvedBy:currentUser?.id});
    await fbPush("logs",{action:"REG_APPROVED",userId,by:currentUser?.id,at:Date.now()});
    await sendNotification(userId,{type:"reg_approved",icon:"✅",color:"#4ade80",title:"নিবন্ধন অনুমোদিত হয়েছে!",body:"আপনার অ্যাকাউন্ট সক্রিয় হয়েছে। এখন লগইন করুন।"});
  };
  const reject=async(userId)=>{
    setUsers(prev=>prev.map(u=>u.userId===userId?{...u,status:STATUS.REJECTED,rejectNote:rejectNote.trim()}:u));
    const fbEntry=fbPending.find(u=>u.userId===userId);
    const fbKey=fbEntry?._fbKey||safeId(userId);
    await fbPatch(`pending_registrations/${fbKey}`,{status:"rejected",adminNote:rejectNote.trim(),rejectedAt:Date.now(),by:currentUser?.id});
    await fbPatch(`users/${safeId(userId)}`,{status:STATUS.REJECTED,adminNote:rejectNote.trim(),rejectedAt:Date.now()});
    await fbPush("logs",{action:"REG_REJECTED",userId,note:rejectNote,by:currentUser?.id,at:Date.now()});
    await sendNotification(userId,{type:"reg_rejected",icon:"❌",color:"#f87171",title:"নিবন্ধন প্রত্যাখ্যাত হয়েছে",body:`কারণ: ${rejectNote.trim()||"Admin কর্তৃক প্রত্যাখ্যাত।"} প্রয়োজনে Admin-এর সাথে যোগাযোগ করুন।`});
    setRejectModal(null); setRejectNote("");
  };

  const REJECT_REASONS=["তথ্য অসম্পূর্ণ","ডুপ্লিকেট অ্যাকাউন্ট","সন্দেহজনক তথ্য","অনুমোদিত নয়"];

  return (
    <PageWrap>
      <Modal open={!!rejectModal} onClose={()=>{setRejectModal(null);setRejectNote("");}} title="❌ নিবন্ধন প্রত্যাখ্যান">
        <div style={{marginBottom:14}}>
          {REJECT_REASONS.map(r=>(
            <button key={r} onClick={()=>setRejectNote(r)} style={{display:"block",width:"100%",background:rejectNote===r?`${C.red}18`:"rgba(255,255,255,0.04)",border:`1px solid ${rejectNote===r?C.red+"55":C.border}`,color:rejectNote===r?C.red:C.silver,borderRadius:8,padding:"9px 14px",marginBottom:7,cursor:"pointer",textAlign:"left",fontFamily:"inherit",fontSize:"0.83rem",fontWeight:rejectNote===r?700:400}}>
              {rejectNote===r?"● ":""}{r}
            </button>
          ))}
          <Inp label="অথবা কাস্টম কারণ" value={rejectNote} onChange={e=>setRejectNote(e.target.value)} placeholder="কারণ লিখুন..."/>
        </div>
        <div style={{display:"flex",gap:10}}>
          <Btn onClick={()=>reject(rejectModal)} variant="danger" style={{flex:1}} disabled={!rejectNote.trim()}>❌ Reject করুন</Btn>
          <Btn onClick={()=>{setRejectModal(null);setRejectNote("");}} variant="ghost" style={{flex:1}}>Cancel</Btn>
        </div>
      </Modal>

      <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",flexWrap:"wrap",gap:10,marginBottom:22}}>
        <SectionHeader eye="PENDING APPROVAL" title={<>Pending Registrations {pending.length>0&&<Badge label={pending.length} color={C.amber}/>}</>} sub="নতুন Student ও Client নিবন্ধন অনুমোদন বা প্রত্যাখ্যান করুন"/>
      </div>

      {/* Stats */}
      <div style={{display:"grid",gridTemplateColumns:"repeat(auto-fit,minmax(130px,1fr))",gap:12,marginBottom:20}}>
        {[
          ["⏳","মোট Pending",users.filter(u=>!u.isDemo&&u.status===STATUS.PENDING&&(u.role===ROLES.STUDENT||u.role===ROLES.CLIENT)).length,C.amber],
          ["✅","মোট Approved",users.filter(u=>!u.isDemo&&u.status===STATUS.ACTIVE&&!u.isDemo).length,C.green],
          ["❌","মোট Rejected",users.filter(u=>!u.isDemo&&u.status===STATUS.REJECTED).length,C.red],
        ].map(([ico,lbl,val,col])=>(
          <Card key={lbl} style={{textAlign:"center",padding:"14px 10px"}}>
            <div style={{fontSize:"1.5rem",marginBottom:4}}>{ico}</div>
            <div style={{fontSize:"1.4rem",fontWeight:800,color:col}}>{val}</div>
            <div style={{fontSize:"0.72rem",color:C.silver,marginTop:2}}>{lbl}</div>
          </Card>
        ))}
      </div>

      <div style={{marginBottom:14}}>
        <input value={search} onChange={e=>setSearch(e.target.value)} placeholder="🔍 নাম, ID বা Mobile দিয়ে খুঁজুন…" style={{width:"100%",maxWidth:320,background:"rgba(255,255,255,0.04)",border:`1px solid ${C.border}`,color:C.white,borderRadius:9,padding:"9px 14px",fontFamily:"inherit",fontSize:"0.87rem",outline:"none"}}/>
      </div>

      {pending.length===0
        ?<Card style={{textAlign:"center",padding:44}}><div style={{fontSize:"2.5rem",marginBottom:12}}>✅</div><div style={{color:C.dim,fontSize:"0.87rem"}}>কোনো pending registration নেই।</div></Card>
        :<div style={{display:"flex",flexDirection:"column",gap:12}}>
          {pending.map(u=>(
            <Card key={u.userId} style={{border:`1px solid ${C.amber}30`}}>
              <div style={{display:"flex",alignItems:"flex-start",gap:14,flexWrap:"wrap"}}>
                <div style={{width:48,height:48,borderRadius:12,background:u.role===ROLES.STUDENT?`${C.sky}15`:`${C.green}15`,display:"flex",alignItems:"center",justifyContent:"center",fontSize:"1.5rem",flexShrink:0}}>{u.role===ROLES.STUDENT?"🎓":"🏢"}</div>
                <div style={{flex:1,minWidth:180}}>
                  <div style={{fontWeight:700,fontSize:"0.95rem",marginBottom:2}}>{u.fullNameEn}</div>
                  <div style={{fontSize:"0.72rem",color:C.sky,fontFamily:"monospace",marginBottom:6}}>{u.userId}</div>
                  <div style={{display:"flex",gap:8,flexWrap:"wrap",marginBottom:6}}>
                    <Badge label={u.role===ROLES.STUDENT?"🎓 STUDENT":"🏢 CLIENT"} color={u.role===ROLES.STUDENT?C.sky:C.green}/>
                    <Badge label="⏳ PENDING" color={C.amber}/>
                  </div>
                  <div style={{fontSize:"0.75rem",color:C.silver}}>📱 {fmtPhone(u.mobile)} · 📅 {u.regDate||"—"}</div>
                  {u.email&&<div style={{fontSize:"0.72rem",color:C.dim,marginTop:2}}>📧 {u.email}</div>}
                  {u.course&&<div style={{fontSize:"0.72rem",color:C.dim,marginTop:2}}>📚 {courseById(u.course)?.en||u.course}</div>}
                </div>
                <div style={{display:"flex",flexDirection:"column",gap:8,flexShrink:0}}>
                  <button onClick={()=>approve(u.userId)} style={{background:`${C.green}15`,border:`1px solid ${C.green}30`,color:C.green,borderRadius:8,padding:"8px 16px",fontSize:"0.82rem",cursor:"pointer",fontFamily:"inherit",fontWeight:700}}>✅ Approve</button>
                  <button onClick={()=>setRejectModal(u.userId)} style={{background:`${C.red}10`,border:`1px solid ${C.red}25`,color:C.red,borderRadius:8,padding:"8px 16px",fontSize:"0.82rem",cursor:"pointer",fontFamily:"inherit"}}>❌ Reject</button>
                </div>
              </div>
            </Card>
          ))}
        </div>}
    </PageWrap>
  );
}

/* ════════════════════════════════════════════════════════════════
   USER MANAGEMENT — Chief Admin Panel
   Block / Suspend / Remove / Restore
   ════════════════════════════════════════════════════════════════ */
function UserManagementPanel({users,setUsers,currentUser}) {
  const [tab,setTab]=useState("all");
  const [search,setSearch]=useState("");
  const [confirmAction,setConfirmAction]=useState(null); // {userId, action}
  const [confirmInp,setConfirmInp]=useState("");

  const isChief=currentUser?.isMainAdmin||currentUser?.role===ROLES.CHIEF_ADMIN;

  // Chief Admin কে কেউ action করতে পারবে না
  const canAction=(target)=>{
    if(!target) return false;
    if(target.isMainAdmin||target.role===ROLES.CHIEF_ADMIN) return false; // Protected
    return isChief;
  };

  const doAction=()=>{
    if(!confirmAction) return;
    if(confirmInp.trim().toUpperCase()!=="YES") return;
    const {userId,action}=confirmAction;
    setUsers(prev=>prev.map(u=>{
      if(u.userId!==userId) return u;
      if(action==="block")   return {...u,status:"blocked"};
      if(action==="suspend") return {...u,status:"suspended"};
      if(action==="reject")  return {...u,status:STATUS.REJECTED};
      if(action==="restore") return {...u,status:STATUS.ACTIVE};
      if(action==="remove")  return {...u,status:"removed",role:"removed"};
      return u;
    }));
    // Firebase update — both log AND user status
    const newStatus = action==="block"?"blocked":action==="suspend"?"suspended":action==="reject"?STATUS.REJECTED:action==="restore"?STATUS.ACTIVE:action==="remove"?"removed":null;
    if(newStatus) fbPatch(`users/${safeId(userId)}`,{status:newStatus,...(action==="remove"?{role:"removed"}:{})});
    fbPatch(`user_actions/${safeId(userId)}`,{action,by:currentUser.id,at:Date.now()});
    setConfirmAction(null); setConfirmInp("");
  };

  const TABS=[
    {key:"all",    label:"সব",          filter:u=>true},
    {key:"student",label:"Students",    filter:u=>u.role===ROLES.STUDENT},
    {key:"client", label:"Clients",     filter:u=>u.role===ROLES.CLIENT},
    {key:"admin",  label:"Admins",      filter:u=>u.role===ROLES.ADMIN||u.role===ROLES.PENDING_ADMIN},
    {key:"blocked",label:"Blocked",     filter:u=>u.status==="blocked"||u.status==="suspended"||u.status==="removed"},
  ];

  const ACTION_COLORS={block:C.amber,suspend:C.red,reject:C.red,restore:C.green,remove:"#7f1d1d"};
  const ACTION_LABELS={block:"🚫 Block",suspend:"⏸ Suspend",reject:"❌ Reject",restore:"✅ Restore",remove:"🗑 Remove"};

  const filtered=users
    .filter(TABS.find(t=>t.key===tab)?.filter||Boolean)
    .filter(u=>!search||u.fullNameEn?.toLowerCase().includes(search.toLowerCase())||u.userId?.includes(search)||u.mobile?.includes(search));

  return (
    <PageWrap>
      <SectionHeader eye="CHIEF ADMIN · OWNER" title="User Management" sub="সকল ব্যবহারকারী নিয়ন্ত্রণ · Block · Suspend · Reject · Remove"/>

      <Modal open={!!confirmAction} onClose={()=>{setConfirmAction(null);setConfirmInp("");}} title={`⚠️ ${ACTION_LABELS[confirmAction?.action]||"Action"}`}>
        <div style={{background:`${C.red}08`,border:`1px solid ${C.red}25`,borderRadius:10,padding:14,marginBottom:18,fontSize:"0.85rem",color:C.amber,lineHeight:1.8}}>
          <strong>User:</strong> {users.find(u=>u.userId===confirmAction?.userId)?.fullNameEn}<br/>
          <strong>Action:</strong> {ACTION_LABELS[confirmAction?.action]}<br/>
          এই কাজটি পূর্বাবস্থায় ফেরানো যাবে (Restore ছাড়া Remove)।
        </div>
        <Inp label='নিশ্চিত করতে "YES" লিখুন' value={confirmInp} onChange={e=>setConfirmInp(e.target.value)} placeholder="YES"/>
        <div style={{display:"flex",gap:10}}>
          <Btn onClick={doAction} variant="danger" style={{flex:1}} disabled={confirmInp.trim().toUpperCase()!=="YES"}>নিশ্চিত করুন</Btn>
          <Btn onClick={()=>{setConfirmAction(null);setConfirmInp("");}} variant="ghost" style={{flex:1}}>Cancel</Btn>
        </div>
      </Modal>

      {/* Tabs */}
      <div style={{display:"flex",gap:8,flexWrap:"wrap",marginBottom:18}}>
        {TABS.map(t=>(
          <button key={t.key} onClick={()=>setTab(t.key)} style={{background:tab===t.key?`linear-gradient(135deg,${C.skyDeep},${C.sky})`:"rgba(255,255,255,0.05)",border:"none",borderRadius:8,padding:"7px 14px",color:tab===t.key?"#fff":C.silver,fontSize:"0.82rem",fontWeight:tab===t.key?700:500,cursor:"pointer",fontFamily:"inherit"}}>
            {t.label} <span style={{fontSize:"0.72rem",opacity:0.7}}>({users.filter(t.filter).length})</span>
          </button>
        ))}
      </div>

      <div style={{marginBottom:16}}>
        <input value={search} onChange={e=>setSearch(e.target.value)} placeholder="🔍 Search by name, ID, mobile…" style={{width:320,background:"rgba(255,255,255,0.04)",border:`1px solid ${C.border}`,color:C.white,borderRadius:9,padding:"9px 14px",fontFamily:"inherit",fontSize:"0.87rem",outline:"none"}}/>
      </div>

      <Card style={{padding:0,overflow:"hidden"}}>
        <div style={{overflowX:"auto"}}>
          <table style={{width:"100%",borderCollapse:"collapse"}}>
            <thead>
              <tr style={{borderBottom:`1px solid ${C.border}`}}>
                {["User ID","Name","Role","Status","Actions"].map(h=>(
                  <th key={h} style={{padding:"11px 16px",textAlign:"left",fontSize:"0.68rem",fontWeight:700,color:C.dim,letterSpacing:"1px",textTransform:"uppercase",whiteSpace:"nowrap"}}>{h}</th>
                ))}
              </tr>
            </thead>
            <tbody>
              {filtered.map((u,i)=>{
                const isProtected=u.isMainAdmin||u.role===ROLES.CHIEF_ADMIN;
                const isActive=u.status===STATUS.ACTIVE;
                const isBlocked=u.status==="blocked"||u.status==="suspended";
                return (
                  <tr key={u.userId} style={{borderBottom:`1px solid ${C.border}`,background:isProtected?`${C.gold}05`:u.isDemo?"rgba(255,255,255,0.005)":"transparent"}}>
                    <td style={{padding:"11px 16px",fontFamily:"monospace",fontSize:"0.72rem",color:isProtected?C.goldLt:C.sky}}>{u.userId}</td>
                    <td style={{padding:"11px 16px"}}>
                      <div style={{fontSize:"0.87rem",fontWeight:600}}>{u.fullNameEn}</div>
                      <div style={{fontSize:"0.7rem",color:C.dim}}>{fmtPhone(u.mobile)||u.email||"—"}</div>
                      {u.isDemo&&<span style={{fontSize:"0.62rem",color:C.dim}}>(demo)</span>}
                    </td>
                    <td style={{padding:"11px 16px"}}>
                      <Badge label={isProtected?"👑 CHIEF ADMIN":u.role.replace("_"," ").toUpperCase()} color={isProtected?C.gold:u.role===ROLES.ADMIN?C.purple:u.role===ROLES.STUDENT?C.sky:C.green}/>
                    </td>
                    <td style={{padding:"11px 16px"}}>
                      <Badge label={u.status?.toUpperCase()||"—"} color={u.status===STATUS.ACTIVE?C.green:u.status==="blocked"?C.red:u.status==="suspended"?C.amber:u.status==="removed"?"#7f1d1d":C.dim}/>
                    </td>
                    <td style={{padding:"11px 16px"}}>
                      {isProtected ? (
                        <div style={{fontSize:"0.72rem",color:C.gold,fontWeight:700}}>🔒 Protected</div>
                      ) : canAction(u) ? (
                        <div style={{display:"flex",gap:6,flexWrap:"wrap"}}>
                          {isBlocked ? (
                            <button onClick={()=>setConfirmAction({userId:u.userId,action:"restore"})} style={{background:`${C.green}15`,border:`1px solid ${C.green}30`,color:C.green,borderRadius:6,padding:"4px 9px",fontSize:"0.72rem",cursor:"pointer",fontFamily:"inherit",fontWeight:700}}>✅ Restore</button>
                          ) : (
                            <>
                              <button onClick={()=>setConfirmAction({userId:u.userId,action:"block"})} style={{background:`${C.amber}12`,border:`1px solid ${C.amber}30`,color:C.amber,borderRadius:6,padding:"4px 9px",fontSize:"0.72rem",cursor:"pointer",fontFamily:"inherit"}}>🚫 Block</button>
                              <button onClick={()=>setConfirmAction({userId:u.userId,action:"suspend"})} style={{background:`${C.red}10`,border:`1px solid ${C.red}25`,color:C.red,borderRadius:6,padding:"4px 9px",fontSize:"0.72rem",cursor:"pointer",fontFamily:"inherit"}}>⏸ Suspend</button>
                            </>
                          )}
                          {u.role===ROLES.PENDING_ADMIN&&<button onClick={()=>setConfirmAction({userId:u.userId,action:"reject"})} style={{background:"rgba(127,29,29,0.2)",border:"1px solid rgba(127,29,29,0.4)",color:"#fca5a5",borderRadius:6,padding:"4px 9px",fontSize:"0.72rem",cursor:"pointer",fontFamily:"inherit"}}>❌ Reject</button>}
                          <button onClick={()=>setConfirmAction({userId:u.userId,action:"remove"})} style={{background:"rgba(127,29,29,0.15)",border:"1px solid rgba(127,29,29,0.3)",color:"#ef4444",borderRadius:6,padding:"4px 9px",fontSize:"0.72rem",cursor:"pointer",fontFamily:"inherit"}}>🗑</button>
                        </div>
                      ) : (
                        <div style={{fontSize:"0.72rem",color:C.dim}}>—</div>
                      )}
                    </td>
                  </tr>
                );
              })}
            </tbody>
          </table>
          {filtered.length===0&&<div style={{padding:40,textAlign:"center",color:C.dim}}>কোনো ব্যবহারকারী পাওয়া যায়নি।</div>}
        </div>
      </Card>
    </PageWrap>
  );
}


/* ════════════════════════════════════════════════════════════════
   FORGOT PASSWORD — APPROVAL BASED FULL FLOW (6 Steps)
   Step 1: Enter ID/Mobile/Email → NEXT
   Step 2: Full Verification Form (no profile pic)
   Step 3: Pending (24hr wait)
   Step 4: Admin approves/rejects
   Step 5: New Password Form (if approved)
   Step 6: Done / Rejected with reason
   ════════════════════════════════════════════════════════════════ */
function ForgotPassword({onBack,users,setUsers}) {
  const STEPS=["অ্যাকাউন্ট খুঁজুন","তথ্য যাচাই","অপেক্ষা করুন","নতুন পাসওয়ার্ড"];
  const [step,setStep]=useState(0);
  const [searchId,setSearchId]=useState("");
  const [found,setFound]=useState(null);
  const [err,setErr]=useState("");
  const [reqId,setReqId]=useState(null);
  const [reqStatus,setReqStatus]=useState("pending"); // pending/approved/rejected
  const [rejectReason,setRejectReason]=useState("");
  const [newPw,setNewPw]=useState("");
  const [confPw,setConfPw]=useState("");
  const [loading,setLoading]=useState(false);
  const [done,setDone]=useState(false);
  const [form,setForm]=useState({fullNameBn:"",fullNameEn:"",fatherName:"",motherName:"",dob:"",mobile:"",email:"",userId:""});
  const pollRef=useRef(null);
  useEffect(()=>()=>{ if(pollRef.current) clearInterval(pollRef.current); },[]);
  const f=(k,v)=>setForm(p=>({...p,[k]:v}));

  /* ── Step 1: Find Account ── */
  const findAccount=()=>{
    setErr("");
    const v=searchId.trim();
    if(!v){setErr("User ID, Mobile বা Email দিন।");return;}
    const u=users.find(x=>x.userId===v||x.mobile===v||x.email===v);
    if(!u){setErr("অ্যাকাউন্ট পাওয়া যায়নি। সঠিক তথ্য দিন।");return;}
    if(u.status===STATUS.PENDING){setErr("⏳ আপনার অ্যাকাউন্ট এখনো Pending। Password Reset করতে পারবেন না।");return;}
    if(u.status===STATUS.REJECTED){setErr("❌ আপনার অ্যাকাউন্ট Rejected। Password Reset করতে পারবেন না।");return;}
    if(u.status===STATUS.BLOCKED||u.status==="blocked"){setErr("🚫 আপনার অ্যাকাউন্ট Blocked। Password Reset করতে পারবেন না।");return;}
    setFound(u);
    setForm({fullNameBn:u.fullNameBn||"",fullNameEn:u.fullNameEn||"",fatherName:u.fatherName||"",motherName:u.motherName||"",dob:u.dob||"",mobile:u.mobile||"",email:u.email||"",userId:u.userId});
    setStep(1);
  };

  /* ── Step 2: Submit Request with Full Form ── */
  const submitRequest=async()=>{
    setErr("");
    if(!form.fullNameBn||!form.fullNameEn||!form.fatherName||!form.motherName||!form.dob||!form.mobile){
      setErr("সকল প্রয়োজনীয় তথ্য পূরণ করুন।");return;
    }
    setLoading(true);
    const rId=`pwreset_${Date.now()}_${found.userId.replace(/[^a-zA-Z0-9]/g,"")}`;
    const reqData={
      userId:found.userId, userName:found.fullNameEn, userRole:found.role,
      submittedFullNameBn:form.fullNameBn, submittedFullNameEn:form.fullNameEn,
      submittedFatherName:form.fatherName, submittedMotherName:form.motherName,
      submittedDob:form.dob, submittedMobile:form.mobile, submittedEmail:form.email,
      status:"pending", adminNote:"", createdAt:Date.now(), updatedAt:Date.now(),
    };
    await fbSet(`password_reset_requests/${safeId(rId)}`,reqData);
    setReqId(rId); setReqStatus("pending");
    setLoading(false);
    setStep(2);
    /* Poll Firebase every 5s */
    pollRef.current=setInterval(async()=>{
      const data=await fbGet(`password_reset_requests/${safeId(rId)}`);
      if(!data) return;
      if(data.status==="approved"){clearInterval(pollRef.current);pollRef.current=null;setReqStatus("approved");setStep(3);}
      if(data.status==="rejected"){clearInterval(pollRef.current);pollRef.current=null;setReqStatus("rejected");setRejectReason(data.adminNote||"");setStep(3);}
    },5000);
  };

  /* ── Step 4: Save New Password (approved) ── */
  const savePassword=()=>{
    setErr("");
    if(!newPw||newPw.length<6){setErr("কমপক্ষে ৬ অক্ষর দিন।");return;}
    if(newPw!==confPw){setErr("পাসওয়ার্ড মিলছে না।");return;}
    setUsers(prev=>prev.map(u=>u.userId===found.userId?{...u,password:newPw}:u));
    if(reqId) fbPatch(`password_reset_requests/${safeId(reqId)}`,{status:"completed",completedAt:Date.now()});
    setDone(true);
  };

  if(done) return (
    <div style={{minHeight:"100vh",background:`radial-gradient(ellipse at 30% 20%,${C.mid} 0%,${C.bg} 60%)`,display:"flex",alignItems:"center",justifyContent:"center",padding:16}}>
      <div style={{width:"100%",maxWidth:420}}>
        <Card glow style={{textAlign:"center",padding:"44px 32px"}}>
          <div style={{fontSize:"3.5rem",marginBottom:14}}>🎉</div>
          <div style={{fontSize:"1.2rem",fontWeight:900,color:C.white,marginBottom:8}}>পাসওয়ার্ড সফলভাবে পরিবর্তন হয়েছে!</div>
          <div style={{background:`${C.green}10`,border:`1px solid ${C.green}25`,borderRadius:10,padding:14,marginBottom:22,fontSize:"0.83rem",color:C.green,lineHeight:1.8}}>
            ✅ নতুন পাসওয়ার্ড দিয়ে এখন Login করুন।<br/>User ID: <span style={{fontFamily:"monospace",color:C.goldLt}}>{found?.userId}</span>
          </div>
          <Btn onClick={onBack} style={{width:"100%",padding:"12px"}}>← Login করুন</Btn>
        </Card>
      </div>
    </div>
  );

  return (
    <div style={{minHeight:"100vh",background:`radial-gradient(ellipse at 30% 20%,${C.mid} 0%,${C.bg} 60%)`,display:"flex",alignItems:"center",justifyContent:"center",padding:16,overflowY:"auto"}}>
      <div style={{width:"100%",maxWidth:520}}>
        <div style={{textAlign:"center",marginBottom:18}}>
          <div style={{width:56,height:56,margin:"0 auto 10px",background:`linear-gradient(135deg,${C.skyDeep},${C.sky})`,borderRadius:14,display:"flex",alignItems:"center",justifyContent:"center"}}>
            <LogoImg size={44}/>
          </div>
          <div style={{fontSize:"1.25rem",fontWeight:900,color:C.white}}>🔑 পাসওয়ার্ড পুনরুদ্ধার</div>
          <div style={{fontSize:"0.72rem",color:C.dim,marginTop:2}}>Admin Approval Required · ন্যূনতম ২৪ ঘণ্টা অপেক্ষা</div>
        </div>

        <Card glow>
          <StepBar steps={STEPS} current={step}/>

          {/* ── STEP 0: Find Account ── */}
          {step===0&&(
            <div>
              <div style={{background:`${C.sky}08`,border:`1px solid ${C.sky}20`,borderRadius:10,padding:"11px 14px",marginBottom:18,fontSize:"0.82rem",color:C.silver,lineHeight:1.8}}>
                ℹ️ আপনার <strong style={{color:C.sky}}>User ID</strong>, <strong style={{color:C.sky}}>Mobile</strong> বা <strong style={{color:C.sky}}>Email</strong> দিয়ে অ্যাকাউন্ট খুঁজুন।
              </div>
              <Inp label="User ID / Mobile Number / Email" value={searchId} onChange={e=>setSearchId(e.target.value)} placeholder="PP-2026-... / 01XXXXXXXXX / email@gmail.com" required/>
              {err&&<div style={{color:C.red,fontSize:"0.8rem",marginBottom:12,background:`${C.red}10`,borderRadius:8,padding:"9px 12px"}}>⚠ {err}</div>}
              <Btn onClick={findAccount} style={{width:"100%",padding:"11px"}}>পরবর্তী →</Btn>
            </div>
          )}

          {/* ── STEP 1: Full Verification Form ── */}
          {step===1&&(
            <div>
              <div style={{background:C.mid,borderRadius:10,padding:"11px 14px",marginBottom:16,display:"flex",alignItems:"center",gap:10}}>
                <div style={{flex:1}}>
                  <div style={{fontSize:"0.65rem",color:C.dim,letterSpacing:"1px",marginBottom:2}}>ACCOUNT FOUND</div>
                  <div style={{fontWeight:700,color:C.white}}>{found?.fullNameEn}</div>
                  <div style={{fontSize:"0.7rem",color:C.sky,fontFamily:"monospace"}}>{found?.userId}</div>
                </div>
                <Badge label={found?.role?.toUpperCase()||""} color={C.sky}/>
              </div>
              <div style={{background:`${C.amber}09`,border:`1px solid ${C.amber}25`,borderRadius:10,padding:"11px 14px",marginBottom:16,fontSize:"0.8rem",color:C.amber,lineHeight:1.8}}>
                ⚠️ নিচের ফর্মটি সম্পূর্ণ পূরণ করুন। Admin আপনার মূল তথ্যের সাথে মিলিয়ে যাচাই করবেন।<br/>
                <strong>Profile Picture প্রয়োজন নেই।</strong>
              </div>
              <Inp label="পুরো নাম (বাংলা)" value={form.fullNameBn} onChange={e=>f("fullNameBn",e.target.value)} placeholder="বাংলায় নাম লিখুন" required/>
              <Inp label="Full Name (English)" value={form.fullNameEn} onChange={e=>f("fullNameEn",e.target.value)} placeholder="English name" required/>
              <Inp label="Father's Name" value={form.fatherName} onChange={e=>f("fatherName",e.target.value)} placeholder="পিতার নাম" required/>
              <Inp label="Mother's Name" value={form.motherName} onChange={e=>f("motherName",e.target.value)} placeholder="মাতার নাম" required/>
              <Inp label="Date of Birth" value={form.dob} onChange={e=>f("dob",e.target.value)} type="date" required/>
              <Inp label="Mobile Number" value={form.mobile} onChange={e=>f("mobile",e.target.value)} placeholder="01XXXXXXXXX" required/>
              <Inp label="Email Address" value={form.email} onChange={e=>f("email",e.target.value)} type="email" placeholder="email@gmail.com"/>
              <Inp label="User ID" value={form.userId} disabled helper="স্বয়ংক্রিয়ভাবে পূরণ হয়েছে"/>
              {err&&<div style={{color:C.red,fontSize:"0.8rem",marginBottom:12,background:`${C.red}10`,borderRadius:8,padding:"9px 12px"}}>⚠ {err}</div>}
              <div style={{display:"flex",gap:10}}>
                <Btn onClick={()=>setStep(0)} variant="ghost" style={{flex:1}}>← ফিরুন</Btn>
                <Btn onClick={submitRequest} disabled={loading} style={{flex:1}}>{loading?"পাঠানো হচ্ছে...":"📤 Request জমা দিন"}</Btn>
              </div>
            </div>
          )}

          {/* ── STEP 2: Pending ── */}
          {step===2&&(
            <div style={{textAlign:"center",padding:"10px 0"}}>
              <div style={{fontSize:"3rem",marginBottom:16}}>⏳</div>
              <div style={{fontSize:"1.1rem",fontWeight:800,color:C.white,marginBottom:8}}>Request জমা হয়েছে!</div>
              <div style={{background:`${C.amber}10`,border:`1px solid ${C.amber}30`,borderRadius:12,padding:"16px 18px",marginBottom:18,textAlign:"left",fontSize:"0.83rem",color:C.amber,lineHeight:1.9}}>
                🕐 আপনাকে অন্তত <strong>২৪ ঘণ্টা</strong> অপেক্ষা করতে হবে।<br/>
                Admin আপনার তথ্য যাচাই করবেন এবং Approve/Reject করবেন।<br/>
                স্বয়ংক্রিয়ভাবে পরবর্তী ধাপে যাবে।
              </div>
              <div style={{background:C.mid,borderRadius:10,padding:"12px 16px",marginBottom:16,display:"inline-flex",alignItems:"center",gap:10}}>
                <Badge label="⏳ PENDING" color={C.amber}/>
                <div style={{fontSize:"0.78rem",color:C.dim}}>অনুমোদন প্রতীক্ষায়...</div>
              </div>

              <div style={{fontSize:"0.73rem",color:C.dim,lineHeight:1.8}}>
                যোগাযোগ: 📞 +8801612745977 · 📧 info@projuktipunjo.com
              </div>
            </div>
          )}

          {/* ── STEP 3: Approved → New Password / Rejected ── */}
          {step===3&&reqStatus==="approved"&&(
            <div>
              <div style={{background:`${C.green}10`,border:`1px solid ${C.green}25`,borderRadius:10,padding:12,marginBottom:18,fontSize:"0.83rem",color:C.green}}>
                ✅ আপনার request অনুমোদিত হয়েছে! নতুন পাসওয়ার্ড সেট করুন।
              </div>
              <PwdInp label="নতুন পাসওয়ার্ড" value={newPw} onChange={e=>setNewPw(e.target.value)} placeholder="কমপক্ষে ৬ অক্ষর" required/>
              <PwdInp label="Confirm পাসওয়ার্ড" value={confPw} onChange={e=>setConfPw(e.target.value)} required/>
              {newPw&&confPw&&newPw===confPw&&<div style={{color:C.green,fontSize:"0.78rem",marginTop:-8,marginBottom:10}}>✓ পাসওয়ার্ড মিলেছে</div>}
              {err&&<div style={{color:C.red,fontSize:"0.8rem",marginBottom:10,background:`${C.red}10`,borderRadius:8,padding:"8px 12px"}}>⚠ {err}</div>}
              <Btn onClick={savePassword} variant="success" style={{width:"100%",padding:"11px"}}>💾 পাসওয়ার্ড সেভ করুন</Btn>
            </div>
          )}

          {step===3&&reqStatus==="rejected"&&(
            <div style={{textAlign:"center",padding:"10px 0"}}>
              <div style={{fontSize:"3rem",marginBottom:14}}>❌</div>
              <div style={{fontSize:"1.1rem",fontWeight:800,color:C.red,marginBottom:8}}>Request প্রত্যাখ্যান হয়েছে</div>
              {rejectReason&&(
                <div style={{background:`${C.red}10`,border:`1px solid ${C.red}25`,borderRadius:10,padding:"12px 16px",marginBottom:16,fontSize:"0.83rem",color:C.amber,textAlign:"left",lineHeight:1.8}}>
                  <strong style={{color:C.red}}>কারণ:</strong><br/>{rejectReason}
                </div>
              )}
              <div style={{background:C.mid,borderRadius:10,padding:"12px 16px",marginBottom:20,fontSize:"0.8rem",color:C.silver,lineHeight:1.9}}>
                সাহায্যের জন্য যোগাযোগ করুন:<br/>
                📞 <strong style={{color:C.sky}}>+8801612745977</strong><br/>
                📧 <strong style={{color:C.sky}}>info@projuktipunjo.com</strong>
              </div>
              <Btn onClick={onBack} variant="ghost" style={{width:"100%"}}>← Login পেজে ফিরুন</Btn>
            </div>
          )}
        </Card>

        <div style={{textAlign:"center",marginTop:14}}>
          <button onClick={onBack} style={{background:"none",border:"none",color:C.dim,fontSize:"0.78rem",cursor:"pointer",fontFamily:"inherit"}}>← Login পেজে ফিরুন</button>
        </div>
        <style>{`@keyframes bounce{0%,80%,100%{transform:translateY(0)}40%{transform:translateY(-8px)}}`}</style>
      </div>
    </div>
  );
}

/* ════════════════════════════════════════════════════════════════
   SIDEBAR
   ════════════════════════════════════════════════════════════════ */
function ContactModal() {
  const [open,setOpen]=useState(false);
  const items=[
    {icon:<svg width="16" height="16" viewBox="0 0 24 24" fill="#25d366"><path d="M17.472 14.382c-.297-.149-1.758-.867-2.03-.967-.273-.099-.471-.148-.67.15-.197.297-.767.966-.94 1.164-.173.199-.347.223-.644.075-.297-.15-1.255-.463-2.39-1.475-.883-.788-1.48-1.761-1.653-2.059-.173-.297-.018-.458.13-.606.134-.133.298-.347.446-.52.149-.174.198-.298.298-.497.099-.198.05-.371-.025-.52-.075-.149-.669-1.612-.916-2.207-.242-.579-.487-.5-.669-.51-.173-.008-.371-.01-.57-.01-.198 0-.52.074-.792.372-.272.297-1.04 1.016-1.04 2.479 0 1.462 1.065 2.875 1.213 3.074.149.198 2.096 3.2 5.077 4.487.709.306 1.262.489 1.694.625.712.227 1.36.195 1.871.118.571-.085 1.758-.719 2.006-1.413.248-.694.248-1.289.173-1.413-.074-.124-.272-.198-.57-.347m-5.421 7.403h-.004a9.87 9.87 0 01-5.031-1.378l-.361-.214-3.741.982.998-3.648-.235-.374a9.86 9.86 0 01-1.51-5.26c.001-5.45 4.436-9.884 9.888-9.884 2.64 0 5.122 1.03 6.988 2.898a9.825 9.825 0 012.893 6.994c-.003 5.45-4.437 9.884-9.885 9.884m8.413-18.297A11.815 11.815 0 0012.05 0C5.495 0 .16 5.335.157 11.892c0 2.096.547 4.142 1.588 5.945L.057 24l6.305-1.654a11.882 11.882 0 005.683 1.448h.005c6.554 0 11.89-5.335 11.893-11.893a11.821 11.821 0 00-3.48-8.413z"/></svg>, label:"WhatsApp", sub:"গ্রুপে যুক্ত হন", href:CONTACT.whatsapp, color:"#25d366", bg:"rgba(37,211,102,0.07)", border:"rgba(37,211,102,0.25)"},
    {icon:<svg width="16" height="16" viewBox="0 0 24 24" fill="#0088cc"><path d="M11.944 0A12 12 0 0 0 0 12a12 12 0 0 0 12 12 12 12 0 0 0 12-12A12 12 0 0 0 12 0a12 12 0 0 0-.056 0zm4.962 7.224c.1-.002.321.023.465.14a.506.506 0 0 1 .171.325c.016.093.036.306.02.472-.18 1.898-.962 6.502-1.36 8.627-.168.9-.499 1.201-.82 1.23-.696.065-1.225-.46-1.9-.902-1.056-.693-1.653-1.124-2.678-1.8-1.185-.78-.417-1.21.258-1.91.177-.184 3.247-2.977 3.307-3.23.007-.032.014-.15-.056-.212s-.174-.041-.249-.024c-.106.024-1.793 1.14-5.061 3.345-.48.33-.913.49-1.302.48-.428-.008-1.252-.241-1.865-.44-.752-.245-1.349-.374-1.297-.789.027-.216.325-.437.893-.663 3.498-1.524 5.83-2.529 6.998-3.014 3.332-1.386 4.025-1.627 4.476-1.635z"/></svg>, label:"Telegram", sub:"চ্যানেল ফলো করুন", href:CONTACT.telegram, color:"#0088cc", bg:"rgba(0,136,204,0.07)", border:"rgba(0,136,204,0.25)"},
    {icon:<svg width="16" height="16" viewBox="0 0 24 24" fill="#1877f2"><path d="M24 12.073c0-6.627-5.373-12-12-12s-12 5.373-12 12c0 5.99 4.388 10.954 10.125 11.854v-8.385H7.078v-3.47h3.047V9.43c0-3.007 1.792-4.669 4.533-4.669 1.312 0 2.686.235 2.686.235v2.953H15.83c-1.491 0-1.956.925-1.956 1.874v2.25h3.328l-.532 3.47h-2.796v8.385C19.612 23.027 24 18.062 24 12.073z"/></svg>, label:"Facebook", sub:"পেজ লাইক করুন", href:CONTACT.facebook, color:"#1877f2", bg:"rgba(24,119,242,0.07)", border:"rgba(24,119,242,0.25)"},
    {icon:<svg width="16" height="16" viewBox="0 0 24 24" fill="none"><path d="M20 4H4C2.9 4 2 4.9 2 6v12c0 1.1.9 2 2 2h16c1.1 0 2-.9 2-2V6c0-1.1-.9-2-2-2z" stroke="#ea4335" strokeWidth="2" fill="rgba(234,67,53,0.15)"/><path d="M2 6l10 7 10-7" stroke="#ea4335" strokeWidth="2" strokeLinecap="round"/></svg>, label:"Email", sub:CONTACT.emails[0], href:`mailto:${CONTACT.emails[0]}`, color:"#ea4335", bg:"rgba(234,67,53,0.07)", border:"rgba(234,67,53,0.25)", onClick:(e)=>{e.preventDefault();window.open(`mailto:${CONTACT.emails[0]}`,"_blank");}},
    {icon:<svg width="16" height="16" viewBox="0 0 24 24" fill="#2196f3"><path d="M6.62 10.79c1.44 2.83 3.76 5.14 6.59 6.59l2.2-2.2c.27-.27.67-.36 1.02-.24 1.12.37 2.33.57 3.57.57.55 0 1 .45 1 1V20c0 .55-.45 1-1 1-9.39 0-17-7.61-17-17 0-.55.45-1 1-1h3.5c.55 0 1 .45 1 1 0 1.25.2 2.45.57 3.57.11.35.03.74-.25 1.02l-2.2 2.2z"/></svg>, label:"কল করুন", sub:CONTACT.phone, href:`tel:${CONTACT.phone.replace(/\D/g,"")}`, color:"#2196f3", bg:"rgba(33,150,243,0.07)", border:"rgba(33,150,243,0.25)", onClick:(e)=>{e.preventDefault();window.open(`tel:${CONTACT.phone.replace(/\D/g,"")}`);}},
  ];
  return (
    <div style={{position:"relative"}}>
      <button onClick={()=>setOpen(v=>!v)} style={{width:"100%",display:"flex",alignItems:"center",justifyContent:"center",gap:8,background:open?`${C.sky}20`:`rgba(255,255,255,0.05)`,border:`1px solid ${open?C.sky+"50":C.border}`,color:open?C.sky:C.silver,borderRadius:8,padding:"9px 12px",fontSize:"0.83rem",fontWeight:700,cursor:"pointer",fontFamily:"inherit",transition:"all 0.15s"}}>
        <svg width="15" height="15" viewBox="0 0 24 24" fill={open?C.sky:C.silver}><path d="M6.62 10.79c1.44 2.83 3.76 5.14 6.59 6.59l2.2-2.2c.27-.27.67-.36 1.02-.24 1.12.37 2.33.57 3.57.57.55 0 1 .45 1 1V20c0 .55-.45 1-1 1-9.39 0-17-7.61-17-17 0-.55.45-1 1-1h3.5c.55 0 1 .45 1 1 0 1.25.2 2.45.57 3.57.11.35.03.74-.25 1.02l-2.2 2.2z"/></svg>
        Contact Us
        <span style={{marginLeft:"auto",fontSize:"0.7rem"}}>{open?"▲":"▼"}</span>
      </button>
      {open&&(
        <div style={{position:"absolute",bottom:"110%",left:0,right:0,background:C.navy,border:`1px solid ${C.sky}30`,borderRadius:12,padding:"10px 8px",boxShadow:"0 -8px 32px rgba(0,0,0,0.6)",zIndex:500}}>
          <div style={{fontSize:"0.65rem",color:C.dim,fontWeight:700,letterSpacing:"1px",textTransform:"uppercase",marginBottom:8,paddingLeft:4}}>Contact Us</div>
          {items.map(item=>(
            <a key={item.label} href={item.href} target={item.label==="কল করুন"||item.label==="Email"?"_self":"_blank"} rel="noopener" onClick={item.onClick} style={{display:"flex",alignItems:"center",gap:10,padding:"9px 10px",borderRadius:9,background:item.bg,border:`1px solid ${item.border}`,marginBottom:6,textDecoration:"none",cursor:"pointer"}}>
              <span style={{flexShrink:0}}>{item.icon}</span>
              <div style={{flex:1,minWidth:0}}>
                <div style={{fontSize:"0.78rem",fontWeight:700,color:item.color,lineHeight:1.2}}>{item.label}</div>
                <div style={{fontSize:"0.67rem",color:C.dim,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap",lineHeight:1.3}}>{item.sub}</div>
              </div>
              <span style={{fontSize:"0.7rem",color:C.dim}}>›</span>
            </a>
          ))}
        </div>
      )}
    </div>
  );
}

function Sidebar({nav,active,onNav,user,onLogout}) {
  const [open,setOpen]=useState(false);
  const sc=useResponsive();
  const isMob=sc==="mobile"||sc==="tablet";
  // Close sidebar when route changes on mobile
  const handleNav=(id)=>{onNav(id);if(isMob)setOpen(false);};
  return (
    <>
      {isMob&&(
        <button onClick={()=>setOpen(!open)} style={{position:"fixed",top:12,left:12,zIndex:1001,width:42,height:42,borderRadius:10,background:open?C.mid:C.sky,border:`1px solid ${open?C.border:C.sky}`,color:"#fff",fontSize:"1.1rem",cursor:"pointer",display:"flex",alignItems:"center",justifyContent:"center",boxShadow:`0 2px 12px ${C.sky}40`,transition:"all 0.2s"}}>
          {open?"✕":"☰"}
        </button>
      )}
      {/* Overlay */}
      {isMob&&open&&<div onClick={()=>setOpen(false)} style={{position:"fixed",inset:0,background:"rgba(0,0,0,0.6)",zIndex:998,backdropFilter:"blur(2px)"}}/>}
      {/* Sidebar panel */}
      <div style={{
        width:220,minHeight:"100vh",background:C.navy,borderRight:`1px solid ${C.border}`,
        display:"flex",flexDirection:"column",
        position:isMob?"fixed":"sticky",
        top:0,left:isMob?(open?"0":"-240px"):"0",
        height:"100vh",overflowY:"auto",flexShrink:0,zIndex:999,
        transition:isMob?"left 0.28s cubic-bezier(0.4,0,0.2,1)":"none",
        boxShadow:isMob&&open?`4px 0 24px rgba(0,0,0,0.5)`:"none",
      }}>
        <div style={{padding:"20px 16px",borderBottom:`1px solid ${C.border}`}}>
          <div style={{display:"flex",alignItems:"center",gap:10}}>
            <LogoImg size={38}/>
            <div>
              <div style={{fontSize:"0.9rem",fontWeight:800,color:C.white,lineHeight:1}}>প্রযুক্তিপুঞ্জ</div>
              <div style={{fontSize:"0.65rem",color:C.sky,fontWeight:600}}>ProjuktiPunjo</div>
            </div>
          </div>
          <div style={{marginTop:14,display:"flex",alignItems:"center",gap:9}}>
            <div style={{width:30,height:30,borderRadius:"50%",background:`${C.gold}20`,border:`1px solid ${C.gold}40`,display:"flex",alignItems:"center",justifyContent:"center",color:C.gold,fontSize:"0.85rem",fontWeight:700,flexShrink:0}}>{user.name[0]}</div>
            <div>
              <div style={{fontSize:"0.78rem",fontWeight:700,color:C.white,maxWidth:130,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{user.name}</div>
              <div style={{fontSize:"0.63rem",color:C.dim,textTransform:"capitalize"}}>{user.role.replace("_"," ")}</div>
            </div>
          </div>
        </div>
        <nav style={{padding:"10px 8px"}}>
          {nav.map(n=>(
            <button key={n.id} onClick={()=>handleNav(n.id)} style={{display:"flex",alignItems:"center",gap:10,width:"100%",padding:"9px 12px",borderRadius:8,border:"none",background:active===n.id?`${C.sky}18`:"transparent",color:active===n.id?C.sky:C.silver,fontWeight:active===n.id?700:500,fontSize:"0.83rem",marginBottom:2,transition:"all 0.15s",textAlign:"left",cursor:"pointer"}}>
              <span style={{fontSize:"0.95rem"}}>{n.icon}</span>{n.label}
              {n.badge>0&&<span style={{marginLeft:"auto",background:C.red,color:"#fff",borderRadius:99,padding:"1px 6px",fontSize:"0.65rem",fontWeight:700}}>{n.badge}</span>}
            </button>
          ))}
        </nav>
        <div style={{padding:"14px 16px",borderTop:`1px solid ${C.border}`}}>
          {/* ── যোগাযোগ বাটন ── */}
          <ContactModal/>
          <button onClick={onLogout} style={{width:"100%",background:"rgba(248,113,113,0.08)",border:`1px solid rgba(248,113,113,0.2)`,color:C.red,borderRadius:8,padding:"8px",fontSize:"0.8rem",fontWeight:700,cursor:"pointer",fontFamily:"inherit",marginTop:8}}>🚪 Logout</button>
        </div>
      </div>
    </>
  );
}

/* ════════════════════════════════════════════════════════════════
   ADMIN DASHBOARD
   ════════════════════════════════════════════════════════════════ */
function AdminDashboard({students,payments,users}) {
  const pendingRegCount=users.filter(u=>!u.isDemo&&u.status===STATUS.PENDING&&(u.role===ROLES.STUDENT||u.role===ROLES.CLIENT)).length;
  const sc=useResponsive();
  const isMob=sc==="mobile"||sc==="tablet";
  const active=useMemo(()=>students.filter(s=>s.status==="active").length,[students]);
  const sMap=useMemo(()=>Object.fromEntries(students.map(s=>[s.id,s])),[students]);
  const pendingP=useMemo(()=>payments.filter(p=>p.status===PAY_STATUS.PENDING),[payments]);
  const revenue=useMemo(()=>payments.filter(p=>p.status===PAY_STATUS.APPROVED).reduce((a,p)=>a+p.amount,0),[payments]);
  const pendingAdm=useMemo(()=>users.filter(u=>u.role===ROLES.PENDING_ADMIN&&!u.isDemo).length,[users]);
  const enroll=useMemo(()=>Object.fromEntries(COURSES.map(c=>[c.id,students.filter(s=>s.course===c.id).length])),[students]);
  return (
    <div style={{padding:isMob?"16px 14px":"28px 30px"}}>
      <SectionHeader eye="ADMIN PANEL" title="Dashboard Overview" sub="Real-time system overview · ProjuktiPunjo"/>
      <div style={{display:"grid",gridTemplateColumns:isMob?"1fr 1fr":"repeat(auto-fit,minmax(180px,1fr))",gap:isMob?10:14,marginBottom:26}}>
        <StatBox icon="👥" label="Total Students" value={students.length} sub={`${active} active`} color={C.sky}/>
        <StatBox icon="⏳" label="Pending Payments" value={pendingP.length} sub="needs approval" color={C.amber}/>
        <StatBox icon="💰" label="Total Revenue" value={fmt(revenue)} sub="approved" color={C.green}/>
        <StatBox icon="📚" label="Courses" value={COURSES.length} color={C.gold}/>
        {pendingAdm>0&&<StatBox icon="🔐" label="Admin Requests" value={pendingAdm} sub="awaiting approval" color={C.purple}/>}
        {pendingRegCount>0&&<StatBox icon="🔔" label="Pending Reg" value={pendingRegCount} sub="নতুন নিবন্ধন" color={C.amber}/>}
        <StatBox icon="✅" label="Approved Users" value={users.filter(u=>!u.isDemo&&u.status===STATUS.ACTIVE).length} color={C.green}/>
        <StatBox icon="❌" label="Rejected Users" value={users.filter(u=>!u.isDemo&&u.status===STATUS.REJECTED).length} color={C.red}/>
      </div>
      <div style={{display:"grid",gridTemplateColumns:isMob?"1fr":"1fr 1fr",gap:18}}>
        <Card>
          <div style={{fontWeight:700,marginBottom:14,fontSize:"0.92rem"}}>⚠️ Pending Payments</div>
          {pendingP.length===0?<div style={{color:C.dim,fontSize:"0.83rem",textAlign:"center",padding:"20px 0"}}>✅ All caught up!</div>
            :pendingP.map(p=>{const s=sMap[p.studentId];return(<div key={p.id} style={{display:"flex",alignItems:"center",gap:10,padding:"9px 0",borderBottom:`1px solid ${C.border}`}}><div style={{flex:1}}><div style={{fontSize:"0.83rem",fontWeight:600}}>{s?.name}</div><div style={{fontSize:"0.73rem",color:C.dim}}>{p.method} · {fmt(p.amount)}</div></div><Badge label="PENDING" color={C.amber}/></div>);})}
        </Card>
        <Card>
          <div style={{fontWeight:700,marginBottom:14,fontSize:"0.92rem"}}>📈 Course Enrollment</div>
          {COURSES.map(c=>{const n=enroll[c.id]||0;return(<div key={c.id} style={{display:"flex",alignItems:"center",gap:10,marginBottom:10}}><span style={{fontSize:"1.1rem"}}>{c.icon}</span><div style={{flex:1}}><div style={{fontSize:"0.78rem",fontWeight:600,marginBottom:3}}>{c.en}</div><div style={{height:5,background:C.border,borderRadius:99,overflow:"hidden"}}><div style={{height:"100%",width:`${Math.min((n/(students.length||1))*200,100)}%`,background:`linear-gradient(90deg,${C.skyDeep},${C.sky})`,borderRadius:99}}/></div></div><Badge label={n} color={C.sky}/></div>);})}
        </Card>
      </div>
    </div>
  );
}

/* ════════════════════════════════════════════════════════════════
   ADMIN APPROVAL PANEL (Chief Admin approves pending admins)
   ════════════════════════════════════════════════════════════════ */
function AdminApprovalPanel({users,setUsers}) {
  const pending=users.filter(u=>u.role===ROLES.PENDING_ADMIN&&!u.isDemo);
  const allAdm=users.filter(u=>(u.role===ROLES.ADMIN||u.role===ROLES.PENDING_ADMIN||u.role===ROLES.CHIEF_ADMIN)&&!u.isDemo);
  const [conf,setConf]=useState(null);
  const [inp,setInp]=useState("");

  const approve=async()=>{
    if(inp.trim().toUpperCase()!=="YES") return;
    const approvedUser = users.find(u=>u.userId===conf);
    setUsers(prev=>prev.map(u=>u.userId===conf?{...u,role:ROLES.ADMIN,status:STATUS.ACTIVE}:u));
    const safeKey = conf.replace(/[.#$[\]/]/g,"-");
    await fbPatch(`pending_admins/${safeKey}`,{status:"approved",role:ROLES.ADMIN});
    // Save to users/ path so notifyAllAdmins can find this admin
    if(approvedUser){
      await fbSet(`users/${safeKey}`, {...approvedUser, role:ROLES.ADMIN, status:STATUS.ACTIVE});
    }
    setConf(null);setInp("");
  };
  const reject=(id)=>{
    setUsers(prev=>prev.map(u=>u.userId===id?{...u,role:"rejected_admin",status:STATUS.REJECTED}:u));
    fbPatch(`pending_admins/${id.replace(/[.#$[\]/]/g,"-")}`,{status:"rejected"});
  };

  return (
    <PageWrap>
      <SectionHeader eye="CHIEF ADMIN" title="Admin Approval" sub="Pending admin registration requests"/>
      <Modal open={!!conf} onClose={()=>{setConf(null);setInp("");}} title="⚠️ Admin অ্যাপ্রুভ করুন">
        <div style={{background:`${C.amber}10`,border:`1px solid ${C.amber}30`,borderRadius:10,padding:14,marginBottom:18,fontSize:"0.85rem",color:C.amber}}>এই Admin সম্পূর্ণ Dashboard access পাবেন।</div>
        <Inp label='নিশ্চিত করতে "YES" লিখুন' value={inp} onChange={e=>setInp(e.target.value)} placeholder="YES"/>
        <div style={{display:"flex",gap:10}}>
          <Btn onClick={approve} variant="success" style={{flex:1}} disabled={inp.trim().toUpperCase()!=="YES"}>✅ APPROVE</Btn>
          <Btn onClick={()=>{setConf(null);setInp("");}} variant="ghost" style={{flex:1}}>Cancel</Btn>
        </div>
      </Modal>
      <div style={{marginBottom:26}}>
        <div style={{fontWeight:700,fontSize:"0.92rem",color:C.white,marginBottom:14}}>⏳ Pending Requests {pending.length>0&&<Badge label={pending.length} color={C.amber}/>}</div>
        {pending.length===0?<Card><div style={{color:C.dim,textAlign:"center",padding:"20px 0",fontSize:"0.85rem"}}>✅ কোনো pending request নেই।</div></Card>
          :<div style={{display:"flex",flexDirection:"column",gap:12}}>
            {pending.map(u=>(
              <Card key={u.userId} style={{border:`1px solid ${C.amber}30`}}>
                <div style={{display:"flex",alignItems:"flex-start",gap:14}}>
                  <div style={{width:48,height:48,borderRadius:12,background:`${C.amber}15`,display:"flex",alignItems:"center",justifyContent:"center",fontSize:"1.4rem",flexShrink:0}}>🔐</div>
                  <div style={{flex:1}}>
                    <div style={{fontWeight:700,fontSize:"0.95rem",marginBottom:2}}>{u.fullNameEn}</div>
                    <div style={{fontSize:"0.72rem",color:C.sky,fontFamily:"monospace",marginBottom:6}}>{u.userId}</div>
                    <div style={{fontSize:"0.78rem",color:C.silver}}>📱 {fmtPhone(u.mobile)} &nbsp;·&nbsp; 📧 {u.email||"—"}</div>
                    <div style={{marginTop:6}}><Badge label="PENDING APPROVAL" color={C.amber}/></div>
                  </div>
                  <div style={{display:"flex",flexDirection:"column",gap:8,flexShrink:0}}>
                    <button onClick={()=>setConf(u.userId)} style={{background:`${C.green}15`,border:`1px solid ${C.green}30`,color:C.green,borderRadius:8,padding:"7px 14px",fontSize:"0.78rem",cursor:"pointer",fontFamily:"inherit",fontWeight:700}}>✓ Approve</button>
                    <button onClick={()=>reject(u.userId)} style={{background:`${C.red}10`,border:`1px solid ${C.red}25`,color:C.red,borderRadius:8,padding:"7px 14px",fontSize:"0.78rem",cursor:"pointer",fontFamily:"inherit"}}>✕ Reject</button>
                  </div>
                </div>
              </Card>
            ))}
          </div>}
      </div>
      <div>
        <div style={{fontWeight:700,fontSize:"0.92rem",color:C.white,marginBottom:14}}>📋 All Admin Accounts</div>
        <Card style={{padding:0,overflow:"hidden"}}>
          <div style={{overflowX:"auto"}}>
            <table style={{width:"100%",borderCollapse:"collapse"}}>
              <thead><tr style={{borderBottom:`1px solid ${C.border}`}}>{["Admin ID","Name","Mobile","Email","Role","Status"].map(h=><th key={h} style={{padding:"10px 14px",textAlign:"left",fontSize:"0.67rem",fontWeight:700,color:C.dim,letterSpacing:"1px",textTransform:"uppercase"}}>{h}</th>)}</tr></thead>
              <tbody>
                {allAdm.map((u,i)=>(
                  <tr key={u.userId} style={{borderBottom:`1px solid ${C.border}`,background:i%2===0?"transparent":"rgba(255,255,255,0.01)"}}>
                    <td style={{padding:"10px 14px",fontFamily:"monospace",fontSize:"0.75rem",color:C.sky}}>{u.userId}</td>
                    <td style={{padding:"10px 14px",fontSize:"0.85rem",fontWeight:600}}>{u.fullNameEn}</td>
                    <td style={{padding:"10px 14px",fontSize:"0.78rem",color:C.silver}}>{fmtPhone(u.mobile)}</td>
                    <td style={{padding:"10px 14px",fontSize:"0.78rem",color:C.silver}}>{u.email||"—"}</td>
                    <td style={{padding:"10px 14px"}}><Badge label={u.role.replace("_"," ").toUpperCase()} color={u.role===ROLES.CHIEF_ADMIN?C.gold:C.sky}/></td>
                    <td style={{padding:"10px 14px"}}><Badge label={u.status?.toUpperCase()||"PENDING"} color={u.status==="active"?C.green:u.status==="rejected"?C.red:C.amber}/></td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </Card>
      </div>
    </PageWrap>
  );
}

/* ════════════════════════════════════════════════════════════════
   RESET APPROVAL — Admin Panel
   Shows pending password reset requests with full form data
   ════════════════════════════════════════════════════════════════ */
function ResetApproval({user}) {
  const [reqs,setReqs]=useState({});
  const [selReq,setSelReq]=useState(null);
  const [rejectNote,setRejectNote]=useState("");
  const [showRejectModal,setShowRejectModal]=useState(null);
  const isChief=user?.isMainAdmin||user?.role===ROLES.CHIEF_ADMIN;

  const load=async()=>{
    const d=await fbGet("password_reset_requests");
    if(d){
      const pending=Object.entries(d).filter(([,r])=>r.status==="pending");
      setReqs(Object.fromEntries(pending));
    } else setReqs({});
  };

  useEffect(()=>{load();const i=setInterval(load,5000);return()=>clearInterval(i);},[]);

  const REJECT_REASONS=["তথ্য মিলছে না (Data Mismatch)","Invalid User ID","ভুল Email","ভুল Mobile Number","সন্দেহজনক Request"];

  const approve=async id=>{
    await fbPatch(`password_reset_requests/${safeId(id)}`,{status:"approved",approvedAt:Date.now(),approvedBy:user.id,updatedAt:Date.now()});
    load();
  };
  const reject=async(id,note)=>{
    await fbPatch(`password_reset_requests/${safeId(id)}`,{status:"rejected",adminNote:note,rejectedAt:Date.now(),rejectedBy:user.id,updatedAt:Date.now()});
    setShowRejectModal(null);setRejectNote("");load();
  };

  const list=Object.entries(reqs);

  return (
    <PageWrap>
      <Modal open={!!showRejectModal} onClose={()=>{setShowRejectModal(null);setRejectNote("");}} title="❌ Request প্রত্যাখ্যান করুন">
        <div style={{marginBottom:14}}>
          <div style={{fontSize:"0.72rem",fontWeight:700,color:C.dim,letterSpacing:"1px",textTransform:"uppercase",marginBottom:8}}>প্রত্যাখ্যানের কারণ নির্বাচন করুন</div>
          {REJECT_REASONS.map(r=>(
            <button key={r} onClick={()=>setRejectNote(r)} style={{display:"block",width:"100%",background:rejectNote===r?`${C.red}18`:"rgba(255,255,255,0.04)",border:`1px solid ${rejectNote===r?C.red+"55":C.border}`,color:rejectNote===r?C.red:C.silver,borderRadius:8,padding:"9px 14px",marginBottom:7,cursor:"pointer",textAlign:"left",fontFamily:"inherit",fontSize:"0.83rem",fontWeight:rejectNote===r?700:400}}>
              {rejectNote===r?"● ":""}{r}
            </button>
          ))}
          <Inp label="অথবা কাস্টম কারণ লিখুন" value={rejectNote} onChange={e=>setRejectNote(e.target.value)} placeholder="কারণ লিখুন..."/>
        </div>
        <div style={{display:"flex",gap:10}}>
          <Btn onClick={()=>reject(showRejectModal,rejectNote)} variant="danger" style={{flex:1}} disabled={!rejectNote.trim()}>❌ Reject করুন</Btn>
          <Btn onClick={()=>{setShowRejectModal(null);setRejectNote("");}} variant="ghost" style={{flex:1}}>Cancel</Btn>
        </div>
      </Modal>

      <Modal open={!!selReq} onClose={()=>setSelReq(null)} title="🔑 Reset Request Details" width={540}>
        {selReq&&(()=>{const r=reqs[selReq];if(!r)return null;return(
          <div>
            <div style={{background:C.mid,borderRadius:10,padding:"12px 16px",marginBottom:14}}>
              <div style={{fontSize:"0.63rem",color:C.dim,letterSpacing:"1px",marginBottom:4}}>USER INFO</div>
              <div style={{fontWeight:700,color:C.white,marginBottom:2}}>{r.userName}</div>
              <div style={{fontSize:"0.72rem",color:C.sky,fontFamily:"monospace",marginBottom:6}}>{r.userId}</div>
              <Badge label={r.userRole?.toUpperCase()||""} color={C.purple}/>
            </div>
            <div style={{fontWeight:700,fontSize:"0.85rem",marginBottom:10,color:C.amber}}>📋 জমাকৃত তথ্য (Submitted Data):</div>
            {[
              ["পুরো নাম (বাংলা)",r.submittedFullNameBn],
              ["Full Name (English)",r.submittedFullNameEn],
              ["Father's Name",r.submittedFatherName],
              ["Mother's Name",r.submittedMotherName],
              ["Date of Birth",r.submittedDob],
              ["Mobile",r.submittedMobile],
              ["Email",r.submittedEmail||"—"],
            ].map(([k,v])=>(
              <div key={k} style={{display:"flex",justifyContent:"space-between",padding:"7px 0",borderBottom:`1px solid ${C.border}`,fontSize:"0.83rem"}}>
                <span style={{color:C.dim}}>{k}</span>
                <span style={{fontWeight:600,color:C.text}}>{v}</span>
              </div>
            ))}
            <div style={{fontSize:"0.72rem",color:C.dim,marginTop:10,marginBottom:16}}>
              📅 Request করা হয়েছে: {r.createdAt?new Date(r.createdAt).toLocaleString("bn-BD"):"—"}
            </div>
            <div style={{display:"flex",gap:10}}>
              <Btn onClick={()=>{approve(selReq);setSelReq(null);}} variant="success" style={{flex:1}}>✅ Approve</Btn>
              <Btn onClick={()=>{setSelReq(null);setShowRejectModal(selReq);}} variant="danger" style={{flex:1}}>❌ Reject</Btn>
            </div>
          </div>
        );})()}
      </Modal>

      <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",marginBottom:22,flexWrap:"wrap",gap:10}}>
        <SectionHeader eye="PASSWORD RESET · APPROVAL" title="Reset Requests" sub="পাসওয়ার্ড রিসেট অনুরোধ যাচাই ও অনুমোদন"/>
        <button onClick={load} style={{background:"rgba(255,255,255,0.05)",border:`1px solid ${C.border}`,color:C.silver,borderRadius:9,padding:"8px 16px",cursor:"pointer",fontFamily:"inherit",fontSize:"0.83rem"}}>🔄 Refresh</button>
      </div>

      {list.length===0
        ?<Card style={{textAlign:"center",padding:44}}><div style={{fontSize:"2.5rem",marginBottom:12}}>✅</div><div style={{color:C.dim,fontSize:"0.87rem"}}>কোনো pending reset request নেই।</div></Card>
        :<div style={{display:"flex",flexDirection:"column",gap:14}}>
          {list.map(([id,r])=>(
            <Card key={id} style={{border:`1px solid ${C.amber}30`}}>
              <div style={{display:"flex",alignItems:"flex-start",gap:14}}>
                <div style={{width:48,height:48,borderRadius:12,background:`${C.amber}15`,display:"flex",alignItems:"center",justifyContent:"center",fontSize:"1.4rem",flexShrink:0}}>🔑</div>
                <div style={{flex:1}}>
                  <div style={{fontWeight:700,fontSize:"0.95rem",marginBottom:3}}>{r.userName}</div>
                  <div style={{fontSize:"0.72rem",color:C.sky,fontFamily:"monospace",marginBottom:6}}>{r.userId}</div>
                  <div style={{display:"flex",gap:8,flexWrap:"wrap",marginBottom:6}}>
                    <Badge label="⏳ PENDING" color={C.amber}/>
                    <Badge label={r.userRole?.toUpperCase()||""} color={C.purple}/>
                  </div>
                  <div style={{fontSize:"0.72rem",color:C.dim}}>📅 {r.createdAt?new Date(r.createdAt).toLocaleString("bn-BD"):"—"}</div>
                </div>
                <div style={{display:"flex",flexDirection:"column",gap:8,flexShrink:0}}>
                  <button onClick={()=>setSelReq(id)} style={{background:`${C.sky}12`,border:`1px solid ${C.sky}30`,color:C.sky,borderRadius:8,padding:"7px 12px",fontSize:"0.78rem",cursor:"pointer",fontFamily:"inherit",fontWeight:600}}>👁 বিস্তারিত</button>
                  <button onClick={()=>approve(id)} style={{background:`${C.green}15`,border:`1px solid ${C.green}30`,color:C.green,borderRadius:8,padding:"7px 12px",fontSize:"0.78rem",cursor:"pointer",fontFamily:"inherit",fontWeight:700}}>✓ Approve</button>
                  <button onClick={()=>setShowRejectModal(id)} style={{background:`${C.red}10`,border:`1px solid ${C.red}25`,color:C.red,borderRadius:8,padding:"7px 12px",fontSize:"0.78rem",cursor:"pointer",fontFamily:"inherit"}}>✕ Reject</button>
                </div>
              </div>
            </Card>
          ))}
        </div>}
    </PageWrap>
  );
}

/* ════════════════════════════════════════════════════════════════
   PROFILE UPDATE APPROVAL — Admin Panel
   ════════════════════════════════════════════════════════════════ */
function ProfileUpdateApproval({user}) {
  const [reqs,setReqs]=useState({});
  const [histReqs,setHistReqs]=useState({});
  const [showHistory,setShowHistory]=useState(false);
  const [selReq,setSelReq]=useState(null);
  const [rejectNote,setRejectNote]=useState("");
  const [showRejectModal,setShowRejectModal]=useState(null);

  const load=async()=>{
    const d=await fbGet("profile_update_requests");
    const merged = {...(window._ppProfileReqs||{})};
    if(d){ Object.entries(d).forEach(([k,v])=>{ merged[k]=v; }); }
    if(d) window._ppProfileReqs = {...merged};
    const pending=Object.entries(merged).filter(([,r])=>r.status==="pending");
    const history=Object.entries(merged).filter(([,r])=>r.status==="approved"||r.status==="rejected");
    setReqs(Object.fromEntries(pending));
    setHistReqs(Object.fromEntries(history.sort(([,a],[,b])=>(b.updatedAt||0)-(a.updatedAt||0))));
  };
  useEffect(()=>{
    load();
    const i=setInterval(load,2000);
    const j=setInterval(()=>{ if(window._ppProfileReqDirty){ window._ppProfileReqDirty=false; load(); } },200);
    return()=>{ clearInterval(i); clearInterval(j); };
  },[]);

  const REJECT_REASONS=["তথ্য সঠিক নয় (Invalid Information)","তথ্য পরিবর্তনের অনুমতি নেই","Data Mismatch","Suspicious Request"];

  const approve=async(id,r)=>{
    await fbPatch(`users/${safeId(r.userId)}`,r.newData);
    await fbPatch(`profile_update_requests/${safeId(id)}`,{status:"approved",approvedAt:Date.now(),approvedBy:user.id,updatedAt:Date.now()});
    if(window._ppProfileReqs&&window._ppProfileReqs[id]) window._ppProfileReqs[id]={...window._ppProfileReqs[id],status:"approved"};
    // ── Notify the user ──
    await sendNotification(r.userId,{
      type:"profile_update_approved", icon:"✅", color:"#22c55e",
      title:"Profile Update অনুমোদিত!",
      body:"আপনার profile update request অনুমোদন করা হয়েছে। পরিবর্তন কার্যকর হয়েছে।"
    });
    load();
  };
  const reject=async(id,note)=>{
    const r=(reqs[id]||window._ppProfileReqs?.[id]||{});
    await fbPatch(`profile_update_requests/${safeId(id)}`,{status:"rejected",adminNote:note,rejectedAt:Date.now(),updatedAt:Date.now()});
    if(window._ppProfileReqs&&window._ppProfileReqs[id]) window._ppProfileReqs[id]={...window._ppProfileReqs[id],status:"rejected",adminNote:note};
    // ── Notify the user ──
    if(r.userId) await sendNotification(r.userId,{
      type:"profile_update_rejected", icon:"❌", color:"#ef4444",
      title:"Profile Update প্রত্যাখ্যাত",
      body:`আপনার profile update request প্রত্যাখ্যান করা হয়েছে।${note?` কারণ: ${note}`:""}`
    });
    setShowRejectModal(null);setRejectNote("");load();
  };

  const list=Object.entries(reqs);
  const FIELD_LABELS={fullNameBn:"নাম (বাংলা)",fullNameEn:"Name (English)",mobile:"Mobile",email:"Email",fatherName:"Father's Name",motherName:"Mother's Name",dob:"Date of Birth"};

  return (
    <PageWrap>
      <Modal open={!!showRejectModal} onClose={()=>{setShowRejectModal(null);setRejectNote("");}} title="❌ Profile Update প্রত্যাখ্যান">
        <div style={{marginBottom:14}}>
          {REJECT_REASONS.map(r=>(
            <button key={r} onClick={()=>setRejectNote(r)} style={{display:"block",width:"100%",background:rejectNote===r?`${C.red}18`:"rgba(255,255,255,0.04)",border:`1px solid ${rejectNote===r?C.red+"55":C.border}`,color:rejectNote===r?C.red:C.silver,borderRadius:8,padding:"9px 14px",marginBottom:7,cursor:"pointer",textAlign:"left",fontFamily:"inherit",fontSize:"0.83rem",fontWeight:rejectNote===r?700:400}}>
              {rejectNote===r?"● ":""}{r}
            </button>
          ))}
          <Inp label="অথবা কাস্টম কারণ" value={rejectNote} onChange={e=>setRejectNote(e.target.value)} placeholder="কারণ লিখুন..."/>
        </div>
        <div style={{display:"flex",gap:10}}>
          <Btn onClick={()=>reject(showRejectModal,rejectNote)} variant="danger" style={{flex:1}} disabled={!rejectNote.trim()}>❌ Reject</Btn>
          <Btn onClick={()=>{setShowRejectModal(null);setRejectNote("");}} variant="ghost" style={{flex:1}}>Cancel</Btn>
        </div>
      </Modal>

      <Modal open={!!selReq} onClose={()=>setSelReq(null)} title="📝 Profile Update Details" width={560}>
        {selReq&&(()=>{const r=reqs[selReq];if(!r)return null;
          const oldD=r.oldData||{};const newD=r.newData||{};
          const changed=Object.keys({...oldD,...newD}).filter(k=>oldD[k]!==newD[k]&&k in FIELD_LABELS);
          return(
            <div>
              <div style={{background:C.mid,borderRadius:10,padding:"11px 14px",marginBottom:14}}>
                <div style={{fontSize:"0.63rem",color:C.dim,letterSpacing:"1px",marginBottom:4}}>USER</div>
                <div style={{fontWeight:700}}>{r.userName}</div>
                <div style={{fontSize:"0.72rem",color:C.sky,fontFamily:"monospace"}}>{r.userId}</div>
              </div>
              <div style={{fontWeight:700,fontSize:"0.85rem",marginBottom:10,color:C.amber}}>🔄 পরিবর্তিত তথ্য (Comparison):</div>
              <div style={{background:"rgba(255,255,255,0.02)",borderRadius:10,overflow:"hidden",marginBottom:16}}>
                <div style={{display:"grid",gridTemplateColumns:"auto 1fr 1fr",gap:0}}>
                  <div style={{padding:"8px 12px",fontSize:"0.68rem",fontWeight:700,color:C.dim,letterSpacing:"1px",background:"rgba(255,255,255,0.04)",borderBottom:`1px solid ${C.border}`}}>Field</div>
                  <div style={{padding:"8px 12px",fontSize:"0.68rem",fontWeight:700,color:C.red,letterSpacing:"1px",background:`${C.red}08`,borderBottom:`1px solid ${C.border}`}}>পুরনো তথ্য</div>
                  <div style={{padding:"8px 12px",fontSize:"0.68rem",fontWeight:700,color:C.green,letterSpacing:"1px",background:`${C.green}08`,borderBottom:`1px solid ${C.border}`}}>নতুন তথ্য</div>
                  {changed.map(k=>(
                    <div key={k} style={{display:"contents"}}>
                      <div style={{padding:"9px 12px",fontSize:"0.8rem",color:C.silver,borderBottom:`1px solid ${C.border}`,background:"rgba(255,255,255,0.01)"}}>{FIELD_LABELS[k]||k}</div>
                      <div style={{padding:"9px 12px",fontSize:"0.83rem",color:C.red,borderBottom:`1px solid ${C.border}`,background:`${C.red}04`}}>{oldD[k]||"—"}</div>
                      <div style={{padding:"9px 12px",fontSize:"0.83rem",color:C.green,fontWeight:600,borderBottom:`1px solid ${C.border}`,background:`${C.green}04`}}>{newD[k]||"—"}</div>
                    </div>
                  ))}
                </div>
              </div>
              <div style={{display:"flex",gap:10}}>
                <Btn onClick={()=>{approve(selReq,r);setSelReq(null);}} variant="success" style={{flex:1}}>✅ Approve</Btn>
                <Btn onClick={()=>{setSelReq(null);setShowRejectModal(selReq);}} variant="danger" style={{flex:1}}>❌ Reject</Btn>
              </div>
            </div>
          );
        })()}
      </Modal>

      <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",marginBottom:22,flexWrap:"wrap",gap:10}}>
        <SectionHeader eye="PROFILE UPDATE · APPROVAL" title="Update Requests" sub="Profile পরিবর্তনের অনুরোধ যাচাই ও অনুমোদন"/>
        <button onClick={load} style={{background:"rgba(255,255,255,0.05)",border:`1px solid ${C.border}`,color:C.silver,borderRadius:9,padding:"8px 16px",cursor:"pointer",fontFamily:"inherit",fontSize:"0.83rem"}}>🔄 Refresh</button>
      </div>

      {list.length===0
        ?<Card style={{textAlign:"center",padding:44}}><div style={{fontSize:"2.5rem",marginBottom:12}}>✅</div><div style={{color:C.dim,fontSize:"0.87rem"}}>কোনো pending profile update request নেই।</div></Card>
        :<div style={{display:"flex",flexDirection:"column",gap:14}}>
          {list.map(([id,r])=>(
            <Card key={id} style={{border:`1px solid ${C.sky}30`}}>
              <div style={{display:"flex",alignItems:"flex-start",gap:14}}>
                <div style={{width:48,height:48,borderRadius:12,background:`${C.sky}15`,display:"flex",alignItems:"center",justifyContent:"center",fontSize:"1.4rem",flexShrink:0}}>📝</div>
                <div style={{flex:1}}>
                  <div style={{fontWeight:700,fontSize:"0.95rem",marginBottom:3}}>{r.userName}</div>
                  <div style={{fontSize:"0.72rem",color:C.sky,fontFamily:"monospace",marginBottom:6}}>{r.userId}</div>
                  <div style={{display:"flex",gap:8,flexWrap:"wrap",marginBottom:6}}>
                    <Badge label="⏳ PENDING" color={C.amber}/>
                    <Badge label={`${Object.keys(r.newData||{}).length} টি পরিবর্তন`} color={C.sky}/>
                  </div>
                  <div style={{fontSize:"0.72rem",color:C.dim}}>📅 {r.createdAt?new Date(r.createdAt).toLocaleString("bn-BD"):"—"}</div>
                </div>
                <div style={{display:"flex",flexDirection:"column",gap:8,flexShrink:0}}>
                  <button onClick={()=>setSelReq(id)} style={{background:`${C.sky}12`,border:`1px solid ${C.sky}30`,color:C.sky,borderRadius:8,padding:"7px 12px",fontSize:"0.78rem",cursor:"pointer",fontFamily:"inherit",fontWeight:600}}>👁 বিস্তারিত</button>
                  <button onClick={()=>approve(id,r)} style={{background:`${C.green}15`,border:`1px solid ${C.green}30`,color:C.green,borderRadius:8,padding:"7px 12px",fontSize:"0.78rem",cursor:"pointer",fontFamily:"inherit",fontWeight:700}}>✓ Approve</button>
                  <button onClick={()=>setShowRejectModal(id)} style={{background:`${C.red}10`,border:`1px solid ${C.red}25`,color:C.red,borderRadius:8,padding:"7px 12px",fontSize:"0.78rem",cursor:"pointer",fontFamily:"inherit"}}>✕ Reject</button>
                </div>
              </div>
            </Card>
          ))}
        </div>}

      {/* ── History Section ── */}
      <div style={{marginTop:28}}>
        <button onClick={()=>setShowHistory(h=>!h)} style={{background:"rgba(255,255,255,0.05)",border:`1px solid ${C.border}`,color:C.silver,borderRadius:9,padding:"9px 18px",cursor:"pointer",fontFamily:"inherit",fontSize:"0.83rem",marginBottom:14}}>
          {showHistory?"▲ ইতিহাস লুকান":"📋 অনুমোদন/প্রত্যাখ্যান ইতিহাস দেখুন"} ({Object.keys(histReqs).length})
        </button>
        {showHistory&&(
          Object.keys(histReqs).length===0
            ?<Card style={{textAlign:"center",padding:28,color:C.dim,fontSize:"0.85rem"}}>কোনো ইতিহাস নেই।</Card>
            :<div style={{display:"flex",flexDirection:"column",gap:12}}>
              {Object.entries(histReqs).map(([id,r])=>(
                <Card key={id} style={{border:`1px solid ${r.status==="approved"?C.green+"30":C.red+"30"}`}}>
                  <div style={{display:"flex",alignItems:"flex-start",gap:12,flexWrap:"wrap"}}>
                    <div style={{width:40,height:40,borderRadius:10,background:r.status==="approved"?`${C.green}15`:`${C.red}10`,display:"flex",alignItems:"center",justifyContent:"center",fontSize:"1.2rem",flexShrink:0}}>{r.status==="approved"?"✅":"❌"}</div>
                    <div style={{flex:1}}>
                      <div style={{fontWeight:700,fontSize:"0.9rem",marginBottom:2}}>{r.userName}</div>
                      <div style={{fontSize:"0.7rem",color:C.sky,fontFamily:"monospace",marginBottom:4}}>{r.userId}</div>
                      <div style={{display:"flex",gap:6,flexWrap:"wrap",marginBottom:4}}>
                        <Badge label={r.status==="approved"?"✅ APPROVED":"❌ REJECTED"} color={r.status==="approved"?C.green:C.red}/>
                        <Badge label={`${Object.keys(r.newData||{}).length} টি পরিবর্তন`} color={C.sky}/>
                      </div>
                      {r.status==="rejected"&&r.adminNote&&<div style={{fontSize:"0.75rem",color:C.amber,background:`${C.amber}10`,borderRadius:6,padding:"4px 8px",marginBottom:4}}>📋 কারণ: {r.adminNote}</div>}
                      <div style={{fontSize:"0.68rem",color:C.dim}}>
                        📅 জমা: {r.createdAt?new Date(r.createdAt).toLocaleString("bn-BD"):"—"}
                        {r.updatedAt&&<> · 🔄 {r.status==="approved"?"অনুমোদন":"প্রত্যাখ্যান"}: {new Date(r.updatedAt).toLocaleString("bn-BD")}</>}
                      </div>
                    </div>
                  </div>
                </Card>
              ))}
            </div>
        )}
      </div>
    </PageWrap>
  );
}
function StudentManagement({students,setStudents,users,setUsers,currentUser}) {
  const [search,setSearch]=useState("");
  const [tab,setTab]=useState("all");
  const [confirmAction,setConfirmAction]=useState(null);
  const [confirmInp,setConfirmInp]=useState("");
  const [viewId,setViewId]=useState(null);
  const courseMap=useMemo(()=>Object.fromEntries(COURSES.map(c=>[c.id,c])),[]);
  const stuMap=useMemo(()=>Object.fromEntries(students.map(s=>[s.id,s])),[students]);
  const sc=useResponsive();
  const isMob=sc==="mobile"||sc==="tablet";

  const isChief=currentUser?.isMainAdmin||currentUser?.role===ROLES.CHIEF_ADMIN;

  const canAct=(u)=>{
    if(!u) return false;
    if(u.isMainAdmin||u.role===ROLES.CHIEF_ADMIN) return false;
    if(!isChief && u.role!==ROLES.STUDENT && u.role!==ROLES.CLIENT) return false;
    return true;
  };

  const doAction=async()=>{
    if(!confirmAction||confirmInp.trim().toUpperCase()!=="YES") return;
    const {userId,action}=confirmAction;
    const targetUser = users.find(u=>u.userId===userId);
    let newStatus = null;
    if(action==="suspend") newStatus="suspended";
    if(action==="block")   newStatus="blocked";
    if(action==="reject")  newStatus=STATUS.REJECTED;
    if(action==="restore") newStatus=STATUS.ACTIVE;
    if(action==="remove")  newStatus="removed";
    // Update local state
    if(action==="remove"){
      setUsers(prev=>prev.filter(u=>u.userId!==userId));
      setStudents(prev=>prev.filter(s=>s.id!==userId));
    } else {
      setUsers(prev=>prev.map(u=>{
        if(u.userId!==userId) return u;
        return {...u, status:newStatus||u.status};
      }));
    }
    // Update Firebase — try both paths
    if(targetUser && !targetUser.isDemo){
      const sid = safeId(userId);
      if(action==="remove"){
        // Permanently delete from Firebase
        await fbDelete(`users/${sid}`);
        await fbDelete(`pending_registrations/${sid}`);
      } else {
        await fbPatch(`users/${sid}`, {status:newStatus});
        await fbPatch(`pending_registrations/${sid}`, {status:newStatus});
      }
    }
    fbPatch(`user_actions/${safeId(userId)}`,{action,by:currentUser?.id,at:Date.now()});
    setConfirmAction(null); setConfirmInp(""); setViewId(null);
  };

  const allMembers=users.filter(u=>{
    if(tab==="student") return u.role===ROLES.STUDENT;
    if(tab==="client")  return u.role===ROLES.CLIENT;
    return u.role===ROLES.STUDENT||u.role===ROLES.CLIENT;
  }).filter(u=>
    !search||
    u.fullNameEn?.toLowerCase().includes(search.toLowerCase())||
    u.fullNameBn?.toLowerCase().includes(search.toLowerCase())||
    u.userId?.includes(search)||u.mobile?.includes(search)
  );

  const TABS=[
    {key:"all",    label:"সব",     count:users.filter(u=>u.role===ROLES.STUDENT||u.role===ROLES.CLIENT).length},
    {key:"student",label:"🎓 Student",count:users.filter(u=>u.role===ROLES.STUDENT).length},
    {key:"client", label:"🏢 Client", count:users.filter(u=>u.role===ROLES.CLIENT).length},
  ];

  const viewU=viewId?users.find(u=>u.userId===viewId):null;
  const viewStu=viewId?stuMap[viewId]:null;

  const ActBtns=({u,small=false})=>{
    if(!canAct(u)) return null;
    const isRestricted=u.status==="suspended"||u.status==="blocked"||u.status===STATUS.REJECTED||u.status==="removed";
    const p=small?"3px 7px":"6px 12px", fs=small?"0.68rem":"0.78rem";
    return (
      <div style={{display:"flex",gap:5,flexWrap:"wrap",marginTop:small?0:4}}>
        {isRestricted?(
          <button onClick={()=>setConfirmAction({userId:u.userId,action:"restore",name:u.fullNameEn})}
            style={{background:`${C.green}18`,border:`1px solid ${C.green}40`,color:C.green,borderRadius:7,padding:p,fontSize:fs,cursor:"pointer",fontFamily:"inherit",fontWeight:700}}>
            ✅ Restore
          </button>
        ):(
          <>
            <button onClick={()=>setConfirmAction({userId:u.userId,action:"suspend",name:u.fullNameEn})}
              style={{background:`${C.amber}15`,border:`1px solid ${C.amber}40`,color:C.amber,borderRadius:7,padding:p,fontSize:fs,cursor:"pointer",fontFamily:"inherit",fontWeight:600}}>
              ⏸ Suspend
            </button>
            <button onClick={()=>setConfirmAction({userId:u.userId,action:"block",name:u.fullNameEn})}
              style={{background:`${C.red}12`,border:`1px solid ${C.red}35`,color:C.red,borderRadius:7,padding:p,fontSize:fs,cursor:"pointer",fontFamily:"inherit"}}>
              🚫 Block
            </button>
            <button onClick={()=>setConfirmAction({userId:u.userId,action:"reject",name:u.fullNameEn})}
              style={{background:"rgba(200,50,50,0.1)",border:"1px solid rgba(200,50,50,0.3)",color:"#fca5a5",borderRadius:7,padding:p,fontSize:fs,cursor:"pointer",fontFamily:"inherit"}}>
              ❌ Reject
            </button>
          </>
        )}
        <button onClick={()=>setConfirmAction({userId:u.userId,action:"remove",name:u.fullNameEn})}
          style={{background:"rgba(127,29,29,0.18)",border:"1px solid rgba(127,29,29,0.35)",color:"#ef4444",borderRadius:7,padding:p,fontSize:fs,cursor:"pointer",fontFamily:"inherit"}}>
          🗑 Remove
        </button>
      </div>
    );
  };

  return (
    <PageWrap>
      <SectionHeader title="Student & Client Management" sub="Suspend · Block · Reject · Restore · Remove"/>

      {/* Confirm Modal */}
      <Modal open={!!confirmAction} onClose={()=>{setConfirmAction(null);setConfirmInp("");}} title="⚠️ নিশ্চিত করুন">
        <div style={{background:`${C.red}08`,border:`1px solid ${C.red}25`,borderRadius:10,padding:14,marginBottom:16,fontSize:"0.85rem",color:C.amber,lineHeight:1.8}}>
          <strong>User:</strong> {confirmAction?.name}<br/>
          <strong>Action:</strong> {confirmAction?.action?.toUpperCase()}
        </div>
        <Inp label='নিশ্চিত করতে "YES" লিখুন' value={confirmInp} onChange={e=>setConfirmInp(e.target.value)} placeholder="YES"/>
        <div style={{display:"flex",gap:10}}>
          <Btn onClick={doAction} variant="danger" style={{flex:1}} disabled={confirmInp.trim().toUpperCase()!=="YES"}>নিশ্চিত করুন</Btn>
          <Btn onClick={()=>{setConfirmAction(null);setConfirmInp("");}} variant="ghost" style={{flex:1}}>Cancel</Btn>
        </div>
      </Modal>

      {/* View Details Modal */}
      <Modal open={!!viewId} onClose={()=>setViewId(null)} title="User Details" width={520}>
        {viewU&&(
          <div>
            <div style={{display:"flex",gap:14,marginBottom:18}}>
              <div style={{width:56,height:56,borderRadius:"50%",background:`linear-gradient(135deg,${C.skyDeep},${C.sky})`,display:"flex",alignItems:"center",justifyContent:"center",fontSize:"1.5rem",fontWeight:700,color:"#fff",flexShrink:0}}>{(viewU.fullNameEn||"?")[0]}</div>
              <div>
                <div style={{fontSize:"1.05rem",fontWeight:800}}>{viewU.fullNameEn}</div>
                <div style={{fontSize:"0.75rem",color:C.sky,fontFamily:"monospace"}}>{viewU.userId}</div>
                <div style={{marginTop:5,display:"flex",gap:6,flexWrap:"wrap"}}>
                  <Badge label={(viewU.status||"—").toUpperCase()} color={statusColor(viewU.status)}/>
                  <Badge label={viewU.role===ROLES.STUDENT?"🎓 Student":"🏢 Client"} color={viewU.role===ROLES.STUDENT?C.sky:C.green}/>
                </div>
              </div>
            </div>
            <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:9,marginBottom:16}}>
              {[["Mobile",fmtPhone(viewU.mobile)],["Email",viewU.email||"—"],["Course",courseMap[viewU.course]?.en||"—"],["Reg Date",viewU.regDate||"—"],["Paid",fmt(viewStu?.paid||0)],["Balance",fmt(viewStu?.balance||0)]].map(([k,v])=>(
                <div key={k} style={{background:"rgba(255,255,255,0.03)",borderRadius:8,padding:"9px 11px"}}>
                  <div style={{fontSize:"0.64rem",color:C.dim,fontWeight:700,marginBottom:2}}>{k.toUpperCase()}</div>
                  <div style={{fontSize:"0.82rem",fontWeight:600}}>{v}</div>
                </div>
              ))}
            </div>
            <ActBtns u={viewU}/>
          </div>
        )}
      </Modal>

      {/* Tabs */}
      <div style={{display:"flex",gap:8,marginBottom:14,flexWrap:"wrap"}}>
        {TABS.map(t=>(
          <button key={t.key} onClick={()=>setTab(t.key)} style={{background:tab===t.key?`linear-gradient(135deg,${C.skyDeep},${C.sky})`:"rgba(255,255,255,0.05)",border:"none",borderRadius:8,padding:"7px 14px",color:tab===t.key?"#fff":C.silver,fontSize:"0.82rem",fontWeight:tab===t.key?700:500,cursor:"pointer",fontFamily:"inherit"}}>
            {t.label} <span style={{fontSize:"0.72rem",opacity:0.7}}>({t.count})</span>
          </button>
        ))}
      </div>

      <div style={{marginBottom:14}}>
        <input value={search} onChange={e=>setSearch(e.target.value)} placeholder="🔍 নাম, ID বা Mobile…" style={{width:"100%",maxWidth:320,background:"rgba(255,255,255,0.04)",border:`1px solid ${C.border}`,color:C.white,borderRadius:9,padding:"9px 14px",fontFamily:"inherit",fontSize:"0.87rem",outline:"none"}}/>
      </div>

      {/* ── MOBILE: card layout ── */}
      {isMob?(
        <div style={{display:"flex",flexDirection:"column",gap:10}}>
          {allMembers.map(u=>{
            const c2=courseMap[u.course];
            const isRestricted=u.status==="suspended"||u.status==="blocked"||u.status===STATUS.REJECTED||u.status==="removed";
            return (
              <div key={u.userId} style={{background:isRestricted?`${C.red}06`:C.card,border:`1px solid ${isRestricted?C.red+"25":C.border}`,borderRadius:14,padding:"14px 16px"}}>
                {/* Top row: avatar + name + status */}
                <div style={{display:"flex",alignItems:"flex-start",gap:12,marginBottom:10}}>
                  <div style={{width:44,height:44,borderRadius:10,background:u.role===ROLES.STUDENT?`${C.sky}20`:`${C.green}20`,display:"flex",alignItems:"center",justifyContent:"center",fontSize:"1.3rem",flexShrink:0}}>{u.role===ROLES.STUDENT?"🎓":"🏢"}</div>
                  <div style={{flex:1,minWidth:0}}>
                    <div style={{fontWeight:700,fontSize:"0.92rem",marginBottom:2,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{u.fullNameEn}</div>
                    <div style={{fontSize:"0.7rem",color:C.dim,marginBottom:4}}>{u.fullNameBn||""}</div>
                    <div style={{fontFamily:"monospace",fontSize:"0.65rem",color:C.sky}}>{u.userId}</div>
                  </div>
                  <Badge label={(u.status||"—").toUpperCase()} color={statusColor(u.status)}/>
                </div>
                {/* Info row */}
                <div style={{display:"flex",gap:10,flexWrap:"wrap",marginBottom:10,fontSize:"0.75rem",color:C.silver}}>
                  {u.mobile&&<span>📱 {fmtPhone(u.mobile)}</span>}
                  {c2&&<span>📚 {c2.en}</span>}
                </div>
                {/* Action buttons */}
                <ActBtns u={u} small={true}/>
              </div>
            );
          })}
          {allMembers.length===0&&<div style={{padding:40,textAlign:"center",color:C.dim}}>কোনো সদস্য পাওয়া যায়নি।</div>}
        </div>
      ):(
        /* ── DESKTOP: table layout ── */
        <Card style={{padding:0,overflow:"hidden"}}>
          <div style={{overflowX:"auto"}}>
            <table style={{width:"100%",borderCollapse:"collapse",minWidth:700}}>
              <thead>
                <tr style={{borderBottom:`1px solid ${C.border}`}}>
                  {["ID","নাম","Role","Mobile","Course","Status","Actions"].map(h=>(
                    <th key={h} style={{padding:"11px 14px",textAlign:"left",fontSize:"0.68rem",fontWeight:700,color:C.dim,letterSpacing:"1px",textTransform:"uppercase",whiteSpace:"nowrap"}}>{h}</th>
                  ))}
                </tr>
              </thead>
              <tbody>
                {allMembers.map((u,i)=>{
                  const c2=courseMap[u.course];
                  const isRestricted=u.status==="suspended"||u.status==="blocked"||u.status===STATUS.REJECTED||u.status==="removed";
                  return(
                    <tr key={u.userId} style={{borderBottom:`1px solid ${C.border}`,background:isRestricted?`${C.red}05`:i%2===0?"transparent":"rgba(255,255,255,0.01)"}}>
                      <td style={{padding:"10px 14px",fontSize:"0.72rem",fontFamily:"monospace",color:C.sky,whiteSpace:"nowrap"}}>{u.userId}</td>
                      <td style={{padding:"10px 14px"}}>
                        <div style={{fontWeight:600,fontSize:"0.87rem"}}>{u.fullNameEn}</div>
                        <div style={{fontSize:"0.7rem",color:C.dim}}>{u.fullNameBn}</div>
                      </td>
                      <td style={{padding:"10px 14px"}}>
                        <Badge label={u.role===ROLES.STUDENT?"🎓 Student":"🏢 Client"} color={u.role===ROLES.STUDENT?C.sky:C.green}/>
                      </td>
                      <td style={{padding:"10px 14px",fontSize:"0.8rem",color:C.silver}}>{fmtPhone(u.mobile)}</td>
                      <td style={{padding:"10px 14px",fontSize:"0.78rem"}}>{c2?`${c2.icon} ${c2.en}`:"—"}</td>
                      <td style={{padding:"10px 14px"}}>
                        <Badge label={(u.status||"—").toUpperCase()} color={statusColor(u.status)}/>
                      </td>
                      <td style={{padding:"10px 14px"}}>
                        <div style={{display:"flex",gap:5,alignItems:"center"}}>
                          <button onClick={()=>setViewId(u.userId)} style={{background:"none",border:`1px solid ${C.border}`,color:C.sky,borderRadius:6,padding:"4px 9px",fontSize:"0.7rem",cursor:"pointer",fontFamily:"inherit"}}>👁</button>
                          <ActBtns u={u} small={true}/>
                        </div>
                      </td>
                    </tr>
                  );
                })}
              </tbody>
            </table>
            {allMembers.length===0&&<div style={{padding:40,textAlign:"center",color:C.dim}}>কোনো সদস্য পাওয়া যায়নি।</div>}
          </div>
        </Card>
      )}

      {/* Legend */}
      <div style={{display:"flex",gap:12,flexWrap:"wrap",marginTop:14,fontSize:"0.7rem",color:C.dim}}>
        <span>🚫 Block = সম্পূর্ণ নিষিদ্ধ</span>
        <span>⏸ Suspend = সাময়িক বন্ধ</span>
        <span>❌ Reject = বাতিল</span>
        <span>🗑 Remove = মুছে দিন</span>
        <span>✅ Restore = পুনরায় সক্রিয়</span>
      </div>
    </PageWrap>
  );
}

/* ════════════════════════════════════════════════════════════════
   ADMIN: POINT REQUESTS PANEL — Earn & Redeem Approval
   ════════════════════════════════════════════════════════════════ */
function PointRequestsPanel({students=[], setStudents}) {
  const [reqs, setReqs]       = useState([]);
  const [tab, setTab]         = useState("pending");
  const [processing, setProcessing] = useState(null);
  const [rejectModal, setRejectModal] = useState(null);
  const [rejectNote, setRejectNote]   = useState("");
  const sc = useResponsive(); const mob = sc==="mobile";

  // track permanently deleted keys so they never reload (persisted in localStorage)
  _initPpCache();

  const load = async () => {
    _initPpCache();
    // ── fetch from Firebase ──
    const data = await fbGet("pointRequests");
    const fbReqs = data
      ? Object.entries(data).map(([k,v])=>({...v,_key:k}))
          .filter(r=>!window._ppDeletedPtReqs.has(r._key))
      : [];
    // ── merge Demo requests (memory-only) that are not deleted ──
    const fbKeys = new Set(fbReqs.map(r=>r._key));
    const demoReqs = DEMO_POINT_REQUESTS
      .filter(r => !window._ppDeletedPtReqs.has(r._key) && !fbKeys.has(r._key))
      .map(r => {
        // Apply any locally-stored status overrides (from approve/reject actions)
        const override = window._ppDemoStatus[r._key];
        return override ? {...r, ...override} : r;
      });
    const allReqs = [...fbReqs, ...demoReqs];
    window._ppAllReqs = allReqs;
    setReqs([...allReqs].sort((a,b)=>(b.createdAt||0)-(a.createdAt||0)));
  };

  const [deleteTarget, setDeleteTarget] = useState(null);

  const deleteReq = async (req) => {
    ppAddDeletedPtReq(req._key);
    // Always delete from Firebase (demo requests are seeded there too)
    await fbDelete(`pointRequests/${req._key}`);
    ppDelPtStatus(req._key);
    window._ppAllReqs = (window._ppAllReqs||[]).filter(r=>r._key!==req._key);
    setReqs(prev=>prev.filter(r=>r._key!==req._key));
    window._ppPtReqDirty = true;
    setDeleteTarget(null);
  };

  useEffect(()=>{
    load();
    // Poll every 3s AND react immediately to dirty flag (set when student submits)
    const i=setInterval(load, 3000);
    const j=setInterval(()=>{ if(window._ppPtReqDirty){ window._ppPtReqDirty=false; load(); } }, 500);
    return()=>{ clearInterval(i); clearInterval(j); };
  },[]);

  const filtered = tab==="pending" ? reqs.filter(r=>r.status==="pending")
                 : tab==="earn"    ? reqs.filter(r=>r.type==="earn")
                 : tab==="redeem"  ? reqs.filter(r=>r.type==="redeem")
                 : reqs;

  const approve = async (req) => {
    setProcessing(req._key);
    // Always patch Firebase (demo requests are seeded there too)
    await fbPatch(`pointRequests/${req._key}`, {status:"approved", approvedAt:Date.now()});
    if(req.isDemo){ ppSetPtStatus(req._key, {status:"approved"}); }
    // update user wallet in Firebase
    const userData = await fbGet(`users/${safeId(req.userId)}`);
    if(userData){
      if(req.type==="earn"){
        const newPts = (userData.points||0) + req.points;
        await fbPatch(`users/${safeId(req.userId)}`,{points:newPts});
      } else {
        const newUsed = (userData.usedPoints||0) + req.points;
        await fbPatch(`users/${safeId(req.userId)}`,{usedPoints:newUsed});
      }
    }
    // ── update local students state (covers demo users not in Firebase) ──
    if(setStudents){
      setStudents(prev=>prev.map(s=>{
        if(s.id!==req.userId) return s;
        if(req.type==="earn") return {...s, points:(s.points||0)+req.points};
        else return {...s, usedPoints:(s.usedPoints||0)+req.points};
      }));
    }
    // ── notify user ──
    if(req.userId){
      if(req.type==="earn"){
        await sendNotification(req.userId, {
          type:"earn_approved", icon:"🟢", color:"#4ade80",
          title:"পয়েন্ট অর্জনের অনুরোধ অনুমোদিত!",
          body:`${req.serviceName||"সেবা"} — +${req.points} পয়েন্ট আপনার ওয়ালেটে যোগ হয়েছে।`
        });
      } else {
        await sendNotification(req.userId, {
          type:"redeem_approved", icon:"🔴", color:"#60a5fa",
          title:"পয়েন্ট Redeem অনুমোদিত!",
          body:`${req.serviceName||"সেবা"} — ${req.points} পয়েন্ট ব্যবহার অনুমোদিত হয়েছে।`
        });
      }
    }
    setReqs(prev=>prev.map(r=>r._key===req._key?{...r,status:"approved"}:r));
    if(window._ppAllReqs){ const i=window._ppAllReqs.findIndex(r=>r._key===req._key); if(i>=0) window._ppAllReqs[i]={...window._ppAllReqs[i],status:"approved"}; }
    window._ppPtReqDirty = true;
    setProcessing(null);
  };

  const reject = async () => {
    if(!rejectModal) return;
    setProcessing(rejectModal._key);
    // Always patch Firebase (demo requests are seeded there too)
    await fbPatch(`pointRequests/${rejectModal._key}`, {status:"rejected", rejectNote:rejectNote, rejectedAt:Date.now()});
    if(rejectModal.isDemo){ ppSetPtStatus(rejectModal._key, {status:"rejected",rejectNote}); }
    // ── notify user ──
    if(rejectModal.userId){
      if(rejectModal.type==="earn"){
        await sendNotification(rejectModal.userId, {
          type:"earn_rejected", icon:"❌", color:"#f87171",
          title:"পয়েন্ট অর্জনের অনুরোধ প্রত্যাখ্যাত",
          body:`${rejectModal.serviceName||"সেবা"} — ${rejectNote?`কারণ: ${rejectNote}`:"Admin কর্তৃক প্রত্যাখ্যাত।"}`
        });
      } else {
        await sendNotification(rejectModal.userId, {
          type:"redeem_rejected", icon:"🚫", color:"#f87171",
          title:"পয়েন্ট Redeem প্রত্যাখ্যাত",
          body:`${rejectModal.serviceName||"সেবা"} — ${rejectNote?`কারণ: ${rejectNote}`:"Admin কর্তৃক প্রত্যাখ্যাত।"}`
        });
      }
    }
    setReqs(prev=>prev.map(r=>r._key===rejectModal._key?{...r,status:"rejected"}:r));
    if(window._ppAllReqs){ const i=window._ppAllReqs.findIndex(r=>r._key===rejectModal._key); if(i>=0) window._ppAllReqs[i]={...window._ppAllReqs[i],status:"rejected",rejectNote}; }
    window._ppPtReqDirty = true;
    setProcessing(null); setRejectModal(null); setRejectNote("");
  };

  const pendingCount = reqs.filter(r=>r.status==="pending").length;

  return (
    <PageWrap>
      <SectionHeader eye="ADMIN PANEL" title="Point Requests" sub={`মোট ${reqs.length} টি অনুরোধ — ${pendingCount} টি অপেক্ষায়`}/>

      {/* Tabs */}
      <div style={{display:"flex",gap:8,flexWrap:"wrap",marginBottom:18}}>
        {[["pending",`⏳ Pending${pendingCount>0?" ("+pendingCount+")":""}`],["earn","🟢 Earn"],["redeem","🔴 Redeem"],["all","সব"]].map(([k,l])=>(
          <button key={k} onClick={()=>setTab(k)} style={{background:tab===k?`linear-gradient(135deg,${C.skyDeep},${C.sky})`:"rgba(255,255,255,0.05)",border:"none",borderRadius:8,padding:"7px 14px",color:tab===k?"#fff":C.silver,fontSize:"0.82rem",fontWeight:tab===k?700:500,cursor:"pointer",fontFamily:"inherit"}}>{l}</button>
        ))}
        <button onClick={load} style={{background:"rgba(255,255,255,0.05)",border:`1px solid ${C.border}`,color:C.silver,borderRadius:9,padding:"7px 14px",cursor:"pointer",fontFamily:"inherit",fontSize:"0.82rem",marginLeft:"auto"}}>🔄 Refresh</button>
      </div>

      {filtered.length===0&&(
        <div style={{textAlign:"center",padding:"40px 20px"}}>
          <div style={{fontSize:"2rem",marginBottom:8}}>📭</div>
          <div style={{color:C.dim,marginBottom:8}}>এই ট্যাবে কোনো অনুরোধ নেই।</div>
          <div style={{fontSize:"0.72rem",color:C.dim,marginBottom:14}}>মোট লোড হয়েছে: {reqs.length}টি</div>
          <Btn onClick={load} variant="ghost">🔄 রিফ্রেশ</Btn>
        </div>
      )}

      {filtered.map(r=>(
        <Card key={r._key} style={{marginBottom:8,padding:"10px 12px",border:`1px solid ${r.type==="earn"?C.green+"25":C.red+"25"}`}}>
          {/* Row 1: icon + service name + points badge */}
          <div style={{display:"flex",alignItems:"center",gap:8,marginBottom:6}}>
            <div style={{width:32,height:32,borderRadius:8,background:r.type==="earn"?`${C.green}15`:`${C.red}15`,display:"flex",alignItems:"center",justifyContent:"center",fontSize:"1rem",flexShrink:0}}>
              {r.type==="earn"?"🟢":"🔴"}
            </div>
            <div style={{flex:1,minWidth:0}}>
              <div style={{fontWeight:700,color:C.white,fontSize:"0.85rem",whiteSpace:"nowrap",overflow:"hidden",textOverflow:"ellipsis"}}>{r.serviceName}</div>
              <div style={{display:"flex",alignItems:"center",gap:5,marginTop:2,flexWrap:"wrap"}}>
                <Badge label={r.type==="earn"?"EARN +POINT":"REDEEM -POINT"} color={r.type==="earn"?C.green:C.red}/>
                <Badge label={r.status==="approved"?"✅ Approved":r.status==="rejected"?"❌ Rejected":"⏳ Pending"}
                  color={r.status==="approved"?C.green:r.status==="rejected"?C.red:C.amber}/>
              </div>
            </div>
            <div style={{fontWeight:800,fontSize:"0.92rem",color:r.type==="earn"?C.green:C.red,flexShrink:0}}>
              {r.type==="earn"?"+":"-"}{r.points?.toLocaleString()} pts
            </div>
          </div>

          {/* Row 2: student info */}
          <div style={{fontSize:"0.72rem",color:C.dim,marginBottom:6,paddingLeft:40}}>
            👤 {r.userName} &nbsp;|&nbsp; 📁 {r.category} &nbsp;|&nbsp; 📅 {r.date}
          </div>

          {r.type==="redeem"&&r.cashRequired!=null&&(
            <div style={{fontSize:"0.7rem",color:C.amber,marginBottom:6,paddingLeft:40}}>
              💵 Cash: <strong>৳{r.cashRequired.toLocaleString()}</strong> &nbsp;|&nbsp; মূল: <strong style={{color:C.silver}}>৳{r.originalPrice?.toLocaleString()}</strong>
              {r.dur&&<span> &nbsp;|&nbsp; ⏱ <strong style={{color:C.gold}}>{r.dur}</strong></span>}
            </div>
          )}
          {r.note&&<div style={{fontSize:"0.7rem",color:C.silver,marginBottom:6,paddingLeft:40}}>📝 {r.note}</div>}

          {/* Row 3: action buttons */}
          <div style={{display:"flex",gap:6,justifyContent:"flex-end"}}>
            {r.status==="pending"&&(<>
              <button onClick={()=>approve(r)} disabled={processing===r._key}
                style={{background:`${C.green}15`,border:`1px solid ${C.green}30`,color:C.green,borderRadius:7,padding:"5px 12px",fontSize:"0.75rem",cursor:"pointer",fontFamily:"inherit",fontWeight:700,opacity:processing===r._key?0.5:1}}>
                {processing===r._key?"...":"✅ Approve"}
              </button>
              <button onClick={()=>setRejectModal(r)}
                style={{background:`${C.red}10`,border:`1px solid ${C.red}25`,color:C.red,borderRadius:7,padding:"5px 12px",fontSize:"0.75rem",cursor:"pointer",fontFamily:"inherit"}}>
                ❌ Reject
              </button>
            </>)}
            <button onClick={()=>setDeleteTarget(r)}
              style={{background:"rgba(127,29,29,0.15)",border:"1px solid rgba(127,29,29,0.3)",color:"#ef4444",borderRadius:7,padding:"5px 9px",fontSize:"0.75rem",cursor:"pointer",fontFamily:"inherit"}} title="পার্মানেন্ট ডিলিট">
              🗑
            </button>
          </div>
        </Card>
      ))}

      {/* Reject Modal */}
      <Modal open={!!rejectModal} onClose={()=>{setRejectModal(null);setRejectNote("");}} title="❌ Reject কারণ">
        <div style={{fontSize:"0.85rem",color:C.silver,marginBottom:14}}>
          <strong style={{color:C.white}}>{rejectModal?.serviceName}</strong> — {rejectModal?.userName}
        </div>
        <div style={{marginBottom:10}}>
          {["পয়েন্ট পরিমাণ সঠিক নয়","সেবা বর্তমানে উপলব্ধ নয়","অপর্যাপ্ত একাউন্ট তথ্য","Admin অনুমোদিত নয়","অন্যান্য কারণ"].map(r=>(
            <button key={r} onClick={()=>setRejectNote(r)} style={{display:"block",width:"100%",background:rejectNote===r?`${C.red}18`:"rgba(255,255,255,0.04)",border:`1px solid ${rejectNote===r?C.red+"55":C.border}`,color:rejectNote===r?C.red:C.silver,borderRadius:8,padding:"8px 14px",marginBottom:6,cursor:"pointer",textAlign:"left",fontFamily:"inherit",fontSize:"0.82rem",fontWeight:rejectNote===r?700:400}}>
              {rejectNote===r?"● ":""}{r}
            </button>
          ))}
          <Inp label="অথবা কাস্টম কারণ লিখুন" value={rejectNote} onChange={e=>setRejectNote(e.target.value)} placeholder="কারণ লিখুন..."/>
        </div>
        <div style={{display:"flex",gap:10,marginTop:4}}>
          <Btn onClick={reject} variant="danger" style={{flex:1}} disabled={processing===rejectModal?._key||!rejectNote.trim()}>
            {processing===rejectModal?._key?"...":"❌ Reject করুন"}
          </Btn>
          <Btn onClick={()=>{setRejectModal(null);setRejectNote("");}} variant="ghost" style={{flex:1}}>বাতিল</Btn>
        </div>
      </Modal>
      <ConfirmDeleteModal open={!!deleteTarget} message={`"${deleteTarget?.serviceName||"এই request"}" পার্মানেন্টলি মুছে ফেলবেন?`} onConfirm={()=>deleteReq(deleteTarget)} onCancel={()=>setDeleteTarget(null)}/>
    </PageWrap>
  );
}

function PaymentManagement({payments,setPayments,students}) {
  const [confApprove,setConfApprove]=useState(null);
  const [confReject,setConfReject]=useState(null);
  const [rejectReason,setRejectReason]=useState("");
  const [viewPay,setViewPay]=useState(null);
  const [inp,setInp]=useState("");
  const [filter,setFilter]=useState("all");
  const [deletePayTarget,setDeletePayTarget]=useState(null);
  const sMap=useMemo(()=>Object.fromEntries(students.map(s=>[s.id,s])),[students]);

  const approve=async()=>{
    if(inp.trim().toUpperCase()!=="YES")return;
    const pay=payments.find(p=>p.id===confApprove);
    if(!pay) return;
    if(pay.firebaseKey){
      // Real Firebase entry — patch status
      await fbPatch(`payments/${pay.firebaseKey}`,{status:PAY_STATUS.APPROVED});
      setPayments(prev=>prev.map(p=>p.id===confApprove?{...p,status:PAY_STATUS.APPROVED}:p));
    } else {
      // Demo entry — push to Firebase as permanent real entry
      const payloadToSave={...pay, status:PAY_STATUS.APPROVED, isDemo:false, createdAt:pay.createdAt||Date.now()};
      const res=await fbPush("payments", payloadToSave);
      const newKey=res?.name||null;
      ppSetPayStatus(pay.id, {status:PAY_STATUS.APPROVED, firebaseKey:newKey});
      setPayments(prev=>prev.map(p=>p.id===confApprove?{...p,status:PAY_STATUS.APPROVED,firebaseKey:newKey,isDemo:false}:p));
    }
    // ── notify user ──
    if(pay.studentId){
      await sendNotification(pay.studentId, {
        type:"payment_approved",
        icon:"✅", color:"#4ade80",
        title:"পেমেন্ট অনুমোদিত হয়েছে!",
        body:`৳${(pay.amount||pay.amt||0).toLocaleString()} (${pay.method||""}) — আপনার পেমেন্ট অনুমোদন করা হয়েছে।`
      });
    }
    setConfApprove(null);setInp("");
  };
  const reject=async()=>{
    if(!rejectReason.trim()){return;}
    const pay=payments.find(p=>p.id===confReject);
    if(!pay) return;
    if(pay.firebaseKey){
      // Real Firebase entry — patch status
      await fbPatch(`payments/${pay.firebaseKey}`,{status:PAY_STATUS.REJECTED,adminNote:rejectReason.trim()});
      setPayments(prev=>prev.map(p=>p.id===confReject?{...p,status:PAY_STATUS.REJECTED,adminNote:rejectReason.trim()}:p));
    } else {
      // Demo entry — push to Firebase as permanent real entry
      const payloadToSave={...pay, status:PAY_STATUS.REJECTED, adminNote:rejectReason.trim(), isDemo:false, createdAt:pay.createdAt||Date.now()};
      const res=await fbPush("payments", payloadToSave);
      const newKey=res?.name||null;
      ppSetPayStatus(pay.id, {status:PAY_STATUS.REJECTED, adminNote:rejectReason.trim(), firebaseKey:newKey});
      setPayments(prev=>prev.map(p=>p.id===confReject?{...p,status:PAY_STATUS.REJECTED,adminNote:rejectReason.trim(),firebaseKey:newKey,isDemo:false}:p));
    }
    // ── notify user ──
    if(pay.studentId){
      await sendNotification(pay.studentId, {
        type:"payment_rejected",
        icon:"❌", color:"#f87171",
        title:"পেমেন্ট প্রত্যাখ্যাত হয়েছে",
        body:`৳${(pay.amount||pay.amt||0).toLocaleString()} (${pay.method||""}) — কারণ: ${rejectReason.trim()}`
      });
    }
    setConfReject(null);setRejectReason("");
  };

  const deletePayment=async(p)=>{
    if(p.firebaseKey) await fbDelete(`payments/${p.firebaseKey}`);
    if(p.firebaseKey) ppAddDeletedPayKey(p.firebaseKey);
    if(p.id && p.id!==p.firebaseKey) ppAddDeletedPayKey(p.id);
    setPayments(prev=>prev.filter(x=> x.id!==p.id || x.firebaseKey!==p.firebaseKey));
    setDeletePayTarget(null);
  };

  const filtered=filter==="all"?payments:payments.filter(p=>p.status===filter);
  const METHODS={bKash:"#E2136E",Rocket:"#8B1A8B",Bank:"#003F8A",Cash:C.gold};

  // Detail view of a payment
  const detailPay=viewPay?payments.find(p=>p.id===viewPay):null;
  const detailStu=detailPay?sMap[detailPay.studentId]:null;

  return (
    <PageWrap>
      <SectionHeader title="Payment Management" sub="Admin approval panel"/>

      {/* Approve Modal */}
      <Modal open={!!confApprove} onClose={()=>{setConfApprove(null);setInp("");}} title="⚠️ Confirm Approval">
        <div style={{background:`${C.amber}10`,border:`1px solid ${C.amber}30`,borderRadius:10,padding:14,marginBottom:18,fontSize:"0.85rem",color:C.amber}}>এই কাজ আর পূর্বাবস্থায় ফেরানো যাবে না।</div>
        <Inp label='নিশ্চিত করতে "YES" লিখুন' value={inp} onChange={e=>setInp(e.target.value)} placeholder="YES"/>
        <div style={{display:"flex",gap:10}}><Btn onClick={approve} variant="gold" style={{flex:1}} disabled={inp.trim().toUpperCase()!=="YES"}>✅ APPROVE</Btn><Btn onClick={()=>{setConfApprove(null);setInp("");}} variant="ghost" style={{flex:1}}>Cancel</Btn></div>
      </Modal>

      {/* Reject Modal with reason */}
      <Modal open={!!confReject} onClose={()=>{setConfReject(null);setRejectReason("");}} title="❌ Reject Payment">
        <div style={{background:`${C.red}10`,border:`1px solid ${C.red}25`,borderRadius:10,padding:14,marginBottom:14,fontSize:"0.83rem",color:C.red}}>
          রিজেক্ট করার কারণ স্টুডেন্টকে জানানো হবে।
        </div>
        <Inp label="রিজেক্টের কারণ লিখুন *" value={rejectReason} onChange={e=>setRejectReason(e.target.value)} placeholder="যেমন: ভুল ট্রানজেকশন আইডি / নম্বর মিলছে না..."/>
        <div style={{display:"flex",gap:10}}>
          <Btn onClick={reject} variant="danger" style={{flex:1}} disabled={!rejectReason.trim()}>❌ Reject</Btn>
          <Btn onClick={()=>{setConfReject(null);setRejectReason("");}} variant="ghost" style={{flex:1}}>Cancel</Btn>
        </div>
      </Modal>

      {/* Payment Detail Modal */}
      <Modal open={!!viewPay} onClose={()=>setViewPay(null)} title="💳 Payment Details">
        {detailPay&&(
          <div style={{fontSize:"0.84rem"}}>
            {[
              ["Student",detailStu?.name||detailPay.studentName||"—"],
              ["Student ID",detailPay.studentId],
              ["Method",detailPay.method],
              ["প্রেরকের নাম",detailPay.senderName||"—"],
              ["প্রেরকের নম্বর",detailPay.senderNum||detailPay.sender||"—"],
              ["Transaction ID",detailPay.txnId||"CASH"],
              ["Amount",fmt(detailPay.amount)],
              ["Date",detailPay.date],
              ["Status",(detailPay.status||"pending").toUpperCase()],
              ...(detailPay.adminNote?[["রিজেক্টের কারণ",detailPay.adminNote]]:[]),
            ].map(([k,v])=>(
              <div key={k} style={{display:"flex",justifyContent:"space-between",padding:"8px 0",borderBottom:`1px solid ${C.border}`,gap:10}}>
                <span style={{color:C.dim,flexShrink:0}}>{k}</span>
                <span style={{fontWeight:600,color:k==="Amount"?C.green:k==="রিজেক্টের কারণ"?C.red:C.text,textAlign:"right",fontFamily:k.includes("ID")?"monospace":"inherit",fontSize:k.includes("ID")?"0.74rem":"inherit",wordBreak:"break-all"}}>{v}</span>
              </div>
            ))}
            {detailPay.status==="pending"&&(
              <div style={{display:"flex",gap:10,marginTop:16}}>
                <Btn onClick={()=>{setViewPay(null);setConfApprove(detailPay.id);}} variant="gold" style={{flex:1}}>✅ Approve</Btn>
                <Btn onClick={()=>{setViewPay(null);setConfReject(detailPay.id);}} variant="danger" style={{flex:1}}>❌ Reject</Btn>
              </div>
            )}
          </div>
        )}
      </Modal>

      {/* Stats */}
      <div style={{display:"grid",gridTemplateColumns:"repeat(auto-fit,minmax(130px,1fr))",gap:12,marginBottom:20}}>
        {[["All",payments.length,C.sky],["Pending",payments.filter(p=>p.status==="pending").length,C.amber],["Approved",payments.filter(p=>p.status==="approved").length,C.green],["Rejected",payments.filter(p=>p.status==="rejected").length,C.red]].map(([l,v,col])=>(
          <button key={l} onClick={()=>setFilter(l.toLowerCase())} style={{background:filter===l.toLowerCase()?`${col}15`:C.card,border:`1px solid ${filter===l.toLowerCase()?col+"44":C.border}`,borderRadius:12,padding:"14px",cursor:"pointer",textAlign:"center"}}>
            <div style={{fontSize:"1.4rem",fontWeight:800,color:col}}>{v}</div>
            <div style={{fontSize:"0.73rem",color:C.silver,marginTop:3}}>{l}</div>
          </button>
        ))}
      </div>

      <Card style={{padding:0,overflow:"hidden"}}>
        <div style={{overflowX:"auto"}}>
          <table style={{width:"100%",borderCollapse:"collapse"}}>
            <thead>
              <tr style={{borderBottom:`1px solid ${C.border}`}}>
                {["TXN ID","Student","Sender","Method","Amount","Status","Actions"].map(h=>(
                  <th key={h} style={{padding:"11px 14px",textAlign:"left",fontSize:"0.68rem",fontWeight:700,color:C.dim,letterSpacing:"1px",textTransform:"uppercase",whiteSpace:"nowrap"}}>{h}</th>
                ))}
              </tr>
            </thead>
            <tbody>
              {filtered.map((p,i)=>{
                const s=sMap[p.studentId];
                const mColor=METHODS[p.method]||C.silver;
                return(
                  <tr key={p.id} style={{borderBottom:`1px solid ${C.border}`,background:i%2===0?"transparent":"rgba(255,255,255,0.01)",cursor:"pointer"}} onClick={()=>setViewPay(p.id)}>
                    <td style={{padding:"11px 14px",fontSize:"0.74rem",fontFamily:"monospace",color:C.sky}}>{p.txnId||"CASH"}</td>
                    <td style={{padding:"11px 14px",fontSize:"0.84rem",fontWeight:600}}>{s?.name||p.studentName||"—"}</td>
                    <td style={{padding:"11px 14px",fontSize:"0.78rem"}}>
                      <div style={{color:C.white,fontWeight:600}}>{p.senderName||"—"}</div>
                      <div style={{color:C.dim,fontSize:"0.7rem",fontFamily:"monospace"}}>{p.senderNum||p.sender||""}</div>
                    </td>
                    <td style={{padding:"11px 14px"}}><Badge label={p.method||"—"} color={mColor}/></td>
                    <td style={{padding:"11px 14px",fontWeight:700,color:C.green}}>{fmt(p.amount)}</td>
                    <td style={{padding:"11px 14px"}}><Badge label={(p.status||"pending").toUpperCase()} color={statusColor(p.status||"pending")}/></td>
                    <td style={{padding:"11px 14px"}} onClick={e=>e.stopPropagation()}>
                      {p.status==="pending"&&(
                        <div style={{display:"flex",gap:6}}>
                          <button onClick={()=>setConfApprove(p.id)} style={{background:`${C.green}15`,border:`1px solid ${C.green}30`,color:C.green,borderRadius:6,padding:"4px 9px",fontSize:"0.72rem",cursor:"pointer",fontFamily:"inherit",fontWeight:700}}>✓</button>
                          <button onClick={()=>setConfReject(p.id)} style={{background:`${C.red}10`,border:`1px solid ${C.red}25`,color:C.red,borderRadius:6,padding:"4px 9px",fontSize:"0.72rem",cursor:"pointer",fontFamily:"inherit"}}>✕</button>
                          <button onClick={()=>setDeletePayTarget(p)} style={{background:"rgba(127,29,29,0.15)",border:"1px solid rgba(127,29,29,0.3)",color:"#ef4444",borderRadius:6,padding:"4px 7px",fontSize:"0.72rem",cursor:"pointer",fontFamily:"inherit"}} title="পার্মানেন্ট ডিলিট">🗑</button>
                        </div>
                      )}
                      {p.status==="approved"&&<div style={{display:"flex",gap:6,alignItems:"center"}}><span style={{color:C.green,fontSize:"0.78rem"}}>✅</span><button onClick={()=>setDeletePayTarget(p)} style={{background:"rgba(127,29,29,0.15)",border:"1px solid rgba(127,29,29,0.3)",color:"#ef4444",borderRadius:6,padding:"3px 6px",fontSize:"0.7rem",cursor:"pointer",fontFamily:"inherit"}} title="পার্মানেন্ট ডিলিট">🗑</button></div>}
                      {p.status==="rejected"&&(
                        <div style={{display:"flex",gap:6,alignItems:"flex-start"}}>
                          <div>
                            <span style={{color:C.red,fontSize:"0.78rem"}}>❌</span>
                            {p.adminNote&&<div style={{fontSize:"0.65rem",color:C.red,maxWidth:90,lineHeight:1.3,marginTop:2}}>{p.adminNote}</div>}
                          </div>
                          <button onClick={()=>setDeletePayTarget(p)} style={{background:"rgba(127,29,29,0.15)",border:"1px solid rgba(127,29,29,0.3)",color:"#ef4444",borderRadius:6,padding:"3px 6px",fontSize:"0.7rem",cursor:"pointer",fontFamily:"inherit",flexShrink:0}} title="পার্মানেন্ট ডিলিট">🗑</button>
                        </div>
                      )}
                    </td>
                  </tr>
                );
              })}
            </tbody>
          </table>
        </div>
      </Card>
      <ConfirmDeleteModal open={!!deletePayTarget} message={`৳${((deletePayTarget?.amount||deletePayTarget?.amt)||0).toLocaleString()} পেমেন্ট পার্মানেন্টলি মুছে ফেলবেন?`} onConfirm={()=>deletePayment(deletePayTarget)} onCancel={()=>setDeletePayTarget(null)}/>
    </PageWrap>
  );
}

/* ════════════════════════════════════════════════════════════════
   ════════════════════════════════════════════════════════════════ */
// Global in-memory message store (persists during session across re-renders)
if(!window._ppMsgs)   window._ppMsgs={};   // convId → [{...msg}]
if(!window._ppConvs)  window._ppConvs={};   // admin_convs map
if(!window._ppUConvs) window._ppUConvs={};  // userId → convs map

function MessagingPage({user,isAdmin}) {
  const sc=useResponsive(); const isMob=sc==="mobile"||sc==="tablet";
  const [convs,setConvs]=useState({});
  const [selConv,setSelConv]=useState(null);
  const [msgs,setMsgs]=useState([]);
  const [inp,setInp]=useState("");
  const [loading,setLoading]=useState(false);
  const [showNew,setShowNew]=useState(false);
  const [newTarget,setNewTarget]=useState("");
  const [view,setView]=useState("list");
  const [toast,setToast]=useState(null); // {name, text}
  const [kbHeight,setKbHeight]=useState(0); // keyboard height
  const endRef=useRef(null);
  const inputRef=useRef(null);
  const uid=safeId(user.id);
  const prevMsgCount=useRef(0);

  // ── Keyboard height tracking (fixes input hiding on mobile) ──
  useEffect(()=>{
    const vv=window.visualViewport;
    if(!vv) return;
    const handler=()=>{
      const kb=window.innerHeight-vv.height-vv.offsetTop;
      setKbHeight(kb>50?kb:0);
    };
    vv.addEventListener("resize",handler);
    vv.addEventListener("scroll",handler);
    return()=>{vv.removeEventListener("resize",handler);vv.removeEventListener("scroll",handler);};
  },[]);

  // ── helpers: local store + Firebase sync ──
  const loadConvs=async()=>{
    const local=isAdmin?window._ppConvs:window._ppUConvs[uid]||{};
    const path=isAdmin?"messages/admin_convs":`messages/user_convs/${uid}`;
    const fb=await fbGet(path);
    const merged={...local,...(fb||{})};
    if(isAdmin) window._ppConvs={...window._ppConvs,...merged};
    else window._ppUConvs[uid]={...window._ppUConvs[uid],...merged};
    setConvs({...merged});
  };

  const loadMsgs=async cid=>{
    const localArr=window._ppMsgs[cid]||[];
    const fb=await fbGet(`messages/chats/${cid}`);
    let fbArr=[];
    if(fb) fbArr=Object.entries(fb).map(([k,v])=>({...v,key:k}));
    const seen=new Set();
    const all=[...localArr,...fbArr].filter(m=>{
      const k=m.key||m.timestamp+"_"+m.senderId;
      if(seen.has(k)) return false; seen.add(k); return true;
    }).sort((a,b)=>a.timestamp-b.timestamp);
    window._ppMsgs[cid]=all;
    // ── toast for new incoming message ──
    if(all.length>prevMsgCount.current){
      const newest=all[all.length-1];
      if(newest&&newest.senderId!==user.id){
        setToast({name:newest.senderName,text:newest.text});
        setTimeout(()=>setToast(null),3500);
      }
    }
    prevMsgCount.current=all.length;
    setMsgs([...all]);
  };

  useEffect(()=>{loadConvs();const i=setInterval(loadConvs,5000);return()=>clearInterval(i);},[]);
  useEffect(()=>{
    if(selConv){
      prevMsgCount.current=(window._ppMsgs[selConv]||[]).length;
      loadMsgs(selConv);
      const i=setInterval(()=>loadMsgs(selConv),3000);
      return()=>clearInterval(i);
    }
  },[selConv]);
  useEffect(()=>{endRef.current?.scrollIntoView({behavior:"smooth"});},[msgs]);

  const openConv=(id)=>{
    setSelConv(id);
    prevMsgCount.current=(window._ppMsgs[id]||[]).length;
    if(isMob) setView("chat");
    // mark as read
    if(isAdmin){
      if(window._ppConvs[id]) window._ppConvs[id].unread=false;
      fbPatch(`messages/admin_convs/${id}`,{unread:false});
    } else {
      const uid=user.id;
      if(window._ppUConvs?.[uid]?.[id]) window._ppUConvs[uid][id].unread=false;
      fbPatch(`messages/user_convs/${uid}/${id}`,{unread:false});
    }
  };

  const send=async()=>{
    if(!inp.trim()||!selConv) return;
    setLoading(true);
    const msg={text:inp.trim(),senderId:user.id,senderName:user.name,senderRole:user.role,timestamp:Date.now(),key:"loc_"+Date.now()};
    if(!window._ppMsgs[selConv]) window._ppMsgs[selConv]=[];
    window._ppMsgs[selConv].push(msg);
    const meta={lastMsg:inp.trim().substring(0,60),lastTime:Date.now(),lastSenderRole:user.role,unread:true};
    if(isAdmin){
      const uId=selConv.replace(/^conv_/,"");
      window._ppConvs[selConv]={...window._ppConvs[selConv],...meta,unread:false};
      if(!window._ppUConvs[uId]) window._ppUConvs[uId]={};
      window._ppUConvs[uId][selConv]={...window._ppUConvs[uId][selConv],...meta,unread:true};
      await fbPush(`messages/chats/${selConv}`,msg);
      await fbPatch(`messages/admin_convs/${selConv}`,{...meta,unread:false});
      await fbPatch(`messages/user_convs/${uId}/${selConv}`,{...meta,unread:true});
      // ── notify the user — use stored userId from conv metadata ──
      const convUserId = convs[selConv]?.userId || selConv.replace(/^conv_/,"");
      await sendNotification(convUserId, {
        type:"new_message", icon:"💬", color:"#60a5fa",
        title:"Admin থেকে নতুন বার্তা!",
        body:`প্রযুক্তিপুঞ্জ: ${inp.trim().substring(0,80)}`
      }).catch(()=>{});
    } else {
      if(!window._ppUConvs[uid]) window._ppUConvs[uid]={};
      window._ppUConvs[uid][selConv]={...window._ppUConvs[uid][selConv],...meta,unread:false};
      window._ppConvs[selConv]={...window._ppConvs[selConv],...meta,unread:true};
      await fbPush(`messages/chats/${selConv}`,msg);
      await fbPatch(`messages/user_convs/${uid}/${selConv}`,{...meta,unread:false});
      await fbPatch(`messages/admin_convs/${selConv}`,{...meta,unread:true});
      // ── notify all admins ──
      notifyAllAdmins({
        type:"new_message", icon:"💬", color:"#60a5fa",
        title:`${user.name} — নতুন বার্তা!`,
        body:inp.trim().substring(0,80)
      }).catch(()=>{});
    }
    prevMsgCount.current=window._ppMsgs[selConv].length;
    setInp(""); setLoading(false);
    setMsgs([...window._ppMsgs[selConv]]);
    loadConvs();
    setTimeout(()=>inputRef.current?.focus(),100);
  };

  const startConv=async()=>{
    if(!newTarget.trim()) return;
    const targetId=safeId(newTarget.trim());
    const cId=`conv_${targetId}`;
    const meta={userId:newTarget.trim(),userName:newTarget.trim(),userRole:"student",lastMsg:"কথোপকথন শুরু হয়েছে",lastTime:Date.now(),unread:false};
    window._ppConvs[cId]=meta;
    if(!window._ppUConvs[targetId]) window._ppUConvs[targetId]={};
    window._ppUConvs[targetId][cId]=meta;
    fbSet(`messages/admin_convs/${cId}`,meta);
    fbSet(`messages/user_convs/${targetId}/${cId}`,meta);
    setShowNew(false); setNewTarget(""); loadConvs(); openConv(cId);
  };

  const startAdminConv=async()=>{
    const cId=`conv_${uid}`;
    const meta={userId:user.id,userName:user.name,userRole:user.role,lastMsg:"নতুন কথোপকথন",lastTime:Date.now(),unread:false};
    window._ppConvs[cId]=meta;
    if(!window._ppUConvs[uid]) window._ppUConvs[uid]={};
    window._ppUConvs[uid][cId]=meta;
    fbSet(`messages/admin_convs/${cId}`,meta);
    fbSet(`messages/user_convs/${uid}/${cId}`,meta);
    loadConvs(); openConv(cId);
  };

  const convList=Object.entries(convs).sort((a,b)=>(b[1].lastTime||0)-(a[1].lastTime||0));
  const unreadCount=convList.filter(([,c])=>c.unread&&c.lastSenderRole!==user.role).length;

  /* ── TOAST NOTIFICATION ── */
  const Toast=()=>toast?(
    <div style={{position:"fixed",top:isMob?60:20,left:"50%",transform:"translateX(-50%)",zIndex:9999,background:C.navy,border:`1px solid ${C.sky}44`,borderRadius:14,padding:"10px 18px",display:"flex",alignItems:"center",gap:10,boxShadow:"0 4px 24px rgba(0,0,0,0.5)",maxWidth:"90vw",minWidth:220,animation:"fadeIn 0.2s ease"}}>
      <div style={{width:32,height:32,borderRadius:"50%",background:`${C.sky}20`,display:"flex",alignItems:"center",justifyContent:"center",flexShrink:0}}>💬</div>
      <div style={{flex:1,minWidth:0}}>
        <div style={{fontSize:"0.75rem",fontWeight:800,color:C.white,marginBottom:1}}>{toast.name}</div>
        <div style={{fontSize:"0.72rem",color:C.dim,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{toast.text}</div>
      </div>
    </div>
  ):null;

  /* ── CONVERSATION LIST PANEL ── */
  const ConvList=()=>(
    <div style={{display:"flex",flexDirection:"column",height:"100%"}}>
      <div style={{padding:"16px 16px 12px",borderBottom:`1px solid ${C.border}`,background:C.navy}}>
        <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",marginBottom:4}}>
          <div style={{display:"flex",alignItems:"center",gap:8}}>
            <div style={{fontSize:"1.1rem"}}>💬</div>
            <div style={{fontWeight:800,fontSize:"1rem",color:C.white}}>
              {isAdmin?"Student Messages":"Messages"}
            </div>
            {unreadCount>0&&<div style={{background:C.red,color:"#fff",borderRadius:99,padding:"1px 7px",fontSize:"0.65rem",fontWeight:700}}>{unreadCount}</div>}
          </div>
          {isAdmin&&(
            <button onClick={()=>setShowNew(v=>!v)} style={{background:`${C.sky}15`,border:`1px solid ${C.sky}30`,color:C.sky,borderRadius:8,padding:"6px 12px",fontSize:"0.78rem",fontWeight:700,cursor:"pointer",fontFamily:"inherit"}}>+ নতুন</button>
          )}
        </div>
        <div style={{fontSize:"0.68rem",color:C.dim}}>Firebase Realtime · প্রতি ৫ সেকেন্ডে আপডেট</div>
      </div>
      {showNew&&(
        <div style={{padding:"12px 16px",borderBottom:`1px solid ${C.border}`,background:C.mid}}>
          <div style={{fontSize:"0.75rem",color:C.dim,marginBottom:6,fontWeight:600}}>STUDENT ID দিন</div>
          <div style={{display:"flex",gap:8}}>
            <input value={newTarget} onChange={e=>setNewTarget(e.target.value)} onKeyDown={e=>e.key==="Enter"&&startConv()} placeholder="PP-2026-..." style={{flex:1,background:"rgba(255,255,255,0.06)",border:`1px solid ${C.border}`,color:C.white,borderRadius:8,padding:"8px 12px",fontFamily:"inherit",fontSize:"0.82rem",outline:"none"}}/>
            <button onClick={startConv} style={{background:`linear-gradient(135deg,${C.skyDeep},${C.sky})`,border:"none",color:"#fff",borderRadius:8,padding:"8px 14px",fontSize:"0.8rem",fontWeight:700,cursor:"pointer",fontFamily:"inherit"}}>Start</button>
            <button onClick={()=>setShowNew(false)} style={{background:"rgba(255,255,255,0.06)",border:`1px solid ${C.border}`,color:C.silver,borderRadius:8,padding:"8px 12px",fontSize:"0.8rem",cursor:"pointer",fontFamily:"inherit"}}>✕</button>
          </div>
        </div>
      )}
      <div style={{flex:1,overflowY:"auto"}}>
        {!isAdmin&&convList.length===0&&(
          <div style={{padding:"32px 20px",textAlign:"center"}}>
            <div style={{fontSize:"3rem",marginBottom:12}}>💬</div>
            <div style={{fontWeight:700,color:C.white,marginBottom:6}}>Admin-এর সাথে কথা বলুন</div>
            <div style={{fontSize:"0.8rem",color:C.dim,marginBottom:18,lineHeight:1.7}}>প্রযুক্তিপুঞ্জ টিম সবসময় সাহায্য করতে প্রস্তুত</div>
            <button onClick={startAdminConv} style={{background:`linear-gradient(135deg,${C.skyDeep},${C.sky})`,border:"none",color:"#fff",borderRadius:11,padding:"12px 24px",fontWeight:700,fontSize:"0.9rem",cursor:"pointer",fontFamily:"inherit",width:"100%"}}>💬 Message করুন</button>
          </div>
        )}
        {convList.map(([id,c])=>{
          const isUnread=c.unread&&c.lastSenderRole!==user.role;
          const active=selConv===id&&!isMob;
          return(
            <div key={id} onClick={()=>openConv(id)} style={{padding:"14px 16px",cursor:"pointer",background:active?`${C.sky}12`:isUnread?`${C.sky}06`:"transparent",borderBottom:`1px solid ${C.border}`,borderLeft:`3px solid ${active?C.sky:isUnread?C.sky+"60":"transparent"}`,transition:"all 0.15s"}}>
              <div style={{display:"flex",alignItems:"center",gap:10}}>
                <div style={{width:42,height:42,borderRadius:"50%",background:`linear-gradient(135deg,${C.skyDeep}40,${C.sky}30)`,border:`1px solid ${C.sky}30`,display:"flex",alignItems:"center",justifyContent:"center",fontSize:"1.1rem",flexShrink:0}}>
                  {isAdmin?"👤":"🔐"}
                </div>
                <div style={{flex:1,minWidth:0}}>
                  <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:3}}>
                    <div style={{fontWeight:isUnread?800:600,fontSize:"0.88rem",color:isUnread?C.white:C.text,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap",maxWidth:"70%"}}>
                      {isAdmin?(c.userName||c.userId||"Student"):"Admin · প্রযুক্তিপুঞ্জ"}
                    </div>
                    {c.lastTime&&<div style={{fontSize:"0.62rem",color:C.dim,flexShrink:0}}>{new Date(c.lastTime).toLocaleTimeString("bn-BD",{hour:"2-digit",minute:"2-digit"})}</div>}
                  </div>
                  <div style={{display:"flex",alignItems:"center",gap:6}}>
                    <div style={{fontSize:"0.75rem",color:isUnread?C.silver:C.dim,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap",flex:1}}>{c.lastMsg||"..."}</div>
                    {isUnread&&<div style={{width:8,height:8,borderRadius:"50%",background:C.sky,flexShrink:0}}/>}
                  </div>
                </div>
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );

  /* ── CHAT PANEL ── */
  const ChatPanel=()=>(
    <div style={{display:"flex",flexDirection:"column",height:"100%",paddingBottom:isMob?kbHeight:0}}>
      {/* Header */}
      <div style={{padding:"12px 16px",borderBottom:`1px solid ${C.border}`,background:C.navy,display:"flex",alignItems:"center",gap:10,flexShrink:0}}>
        {isMob&&(
          <button onClick={()=>setView("list")} style={{background:"rgba(255,255,255,0.06)",border:`1px solid ${C.border}`,color:C.silver,borderRadius:8,padding:"6px 10px",fontSize:"0.9rem",cursor:"pointer",fontFamily:"inherit"}}>←</button>
        )}
        <div style={{width:38,height:38,borderRadius:"50%",background:`${C.sky}20`,border:`1px solid ${C.sky}30`,display:"flex",alignItems:"center",justifyContent:"center",fontSize:"1rem",flexShrink:0}}>
          {isAdmin?"👤":"🔐"}
        </div>
        <div style={{flex:1,minWidth:0}}>
          <div style={{fontWeight:700,fontSize:"0.92rem",color:C.white,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>
            {isAdmin?(convs[selConv]?.userName||"Student"):"Admin · প্রযুক্তিপুঞ্জ"}
          </div>
          <div style={{fontSize:"0.66rem",color:C.green}}>● Online</div>
        </div>
      </div>
      {/* Messages */}
      <div style={{flex:1,overflowY:"auto",padding:"14px 14px 8px",display:"flex",flexDirection:"column",gap:8,background:C.bg}}>
        {msgs.length===0&&(
          <div style={{textAlign:"center",padding:"40px 20px"}}>
            <div style={{fontSize:"2.5rem",marginBottom:8}}>💬</div>
            <div style={{color:C.dim,fontSize:"0.82rem"}}>কথোপকথন শুরু করুন…</div>
          </div>
        )}
        {msgs.map((m,i)=>{
          const mine=m.senderId===user.id||(isAdmin&&(m.senderRole==="admin"||m.senderRole===ROLES.CHIEF_ADMIN));
          const time=m.timestamp?new Date(m.timestamp).toLocaleTimeString("bn-BD",{hour:"2-digit",minute:"2-digit"}):"";
          return(
            <div key={m.key||i} style={{display:"flex",justifyContent:mine?"flex-end":"flex-start"}}>
              <div style={{maxWidth:"78%"}}>
                <div style={{background:mine?`linear-gradient(135deg,${C.skyDeep},${C.sky})`:"rgba(255,255,255,0.07)",border:mine?"none":`1px solid ${C.border}`,borderRadius:mine?"16px 16px 4px 16px":"16px 16px 16px 4px",padding:"10px 14px",fontSize:"0.86rem",lineHeight:1.65,color:C.white,whiteSpace:"pre-wrap",wordBreak:"break-word"}}>{m.text}</div>
                <div style={{fontSize:"0.62rem",color:C.dim,marginTop:3,textAlign:mine?"right":"left"}}>{m.senderName} · {time}</div>
              </div>
            </div>
          );
        })}
        <div ref={endRef}/>
      </div>
      {/* Input — fixed bottom on mobile */}
      <div style={{
        padding:"10px 12px",
        borderTop:`1px solid ${C.border}`,
        background:C.navy,
        display:"flex",gap:8,alignItems:"flex-end",
        flexShrink:0,
        position:isMob?"sticky":"static",
        bottom:0,
        zIndex:10,
      }}>
        <textarea
          ref={inputRef}
          value={inp}
          onChange={e=>setInp(e.target.value)}
          onKeyDown={e=>{if(e.key==="Enter"&&!e.shiftKey){e.preventDefault();send();}}}
          onFocus={()=>setTimeout(()=>endRef.current?.scrollIntoView({behavior:"smooth"}),300)}
          placeholder="মেসেজ লিখুন…"
          rows={1}
          style={{flex:1,background:"rgba(255,255,255,0.08)",border:`1px solid ${C.borderHi||C.border}`,color:C.white,borderRadius:12,padding:"10px 14px",fontFamily:"inherit",fontSize:"0.87rem",outline:"none",resize:"none",lineHeight:1.5,maxHeight:100,overflowY:"auto"}}
        />
        <button
          onClick={send}
          disabled={loading||!inp.trim()}
          style={{background:inp.trim()?`linear-gradient(135deg,${C.skyDeep},${C.sky})`:"rgba(255,255,255,0.06)",border:"none",color:inp.trim()?"#fff":C.dim,borderRadius:12,width:44,height:44,fontSize:"1.1rem",cursor:inp.trim()?"pointer":"default",display:"flex",alignItems:"center",justifyContent:"center",flexShrink:0,transition:"all 0.15s"}}>
          {loading?"⏳":"📤"}
        </button>
      </div>
    </div>
  );

  const EmptyState=()=>(
    <div style={{flex:1,display:"flex",alignItems:"center",justifyContent:"center",flexDirection:"column",gap:10,background:C.bg}}>
      <div style={{fontSize:"3.5rem"}}>💬</div>
      <div style={{color:C.silver,fontSize:"0.9rem",fontWeight:600}}>একটি কথোপকথন বেছে নিন</div>
    </div>
  );

  /* ── MOBILE LAYOUT ── */
  if(isMob){
    // Use visualViewport height so input always sits above the keyboard
    const mobH = kbHeight > 0
      ? `calc(${window.visualViewport?.height || window.innerHeight}px)`
      : "100%";
    return(
      <div style={{position:"relative",height:mobH,display:"flex",flexDirection:"column",overflow:"hidden",transition:"height 0.1s"}}>
        <Toast/>
        {view==="list"&&<div style={{flex:1,overflow:"hidden",display:"flex",flexDirection:"column"}}><ConvList/></div>}
        {view==="chat"&&selConv&&(
          <div style={{flex:1,display:"flex",flexDirection:"column",overflow:"hidden",height:"100%"}}>
            {/* Header */}
            <div style={{padding:"12px 16px",borderBottom:`1px solid ${C.border}`,background:C.navy,display:"flex",alignItems:"center",gap:10,flexShrink:0}}>
              <button onClick={()=>setView("list")} style={{background:"rgba(255,255,255,0.06)",border:`1px solid ${C.border}`,color:C.silver,borderRadius:8,padding:"6px 10px",fontSize:"0.9rem",cursor:"pointer",fontFamily:"inherit"}}>←</button>
              <div style={{width:38,height:38,borderRadius:"50%",background:`${C.sky}20`,border:`1px solid ${C.sky}30`,display:"flex",alignItems:"center",justifyContent:"center",fontSize:"1rem",flexShrink:0}}>{isAdmin?"👤":"🔐"}</div>
              <div style={{flex:1,minWidth:0}}>
                <div style={{fontWeight:700,fontSize:"0.92rem",color:C.white,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{isAdmin?(convs[selConv]?.userName||"Student"):"Admin · প্রযুক্তিপুঞ্জ"}</div>
                <div style={{fontSize:"0.66rem",color:C.green}}>● Online</div>
              </div>
            </div>
            {/* Messages — takes remaining space above input */}
            <div style={{flex:1,overflowY:"auto",padding:"12px 12px 8px",display:"flex",flexDirection:"column",gap:8,background:C.bg}}>
              {msgs.length===0&&<div style={{textAlign:"center",padding:"30px 20px"}}><div style={{fontSize:"2.5rem",marginBottom:8}}>💬</div><div style={{color:C.dim,fontSize:"0.82rem"}}>কথোপকথন শুরু করুন…</div></div>}
              {msgs.map((m,i)=>{
                const mine=m.senderId===user.id||(isAdmin&&(m.senderRole==="admin"||m.senderRole===ROLES.CHIEF_ADMIN));
                const time=m.timestamp?new Date(m.timestamp).toLocaleTimeString("bn-BD",{hour:"2-digit",minute:"2-digit"}):"";
                return(
                  <div key={m.key||i} style={{display:"flex",justifyContent:mine?"flex-end":"flex-start"}}>
                    <div style={{maxWidth:"80%"}}>
                      <div style={{background:mine?`linear-gradient(135deg,${C.skyDeep},${C.sky})`:"rgba(255,255,255,0.07)",border:mine?"none":`1px solid ${C.border}`,borderRadius:mine?"16px 16px 4px 16px":"16px 16px 16px 4px",padding:"9px 13px",fontSize:"0.86rem",lineHeight:1.6,color:C.white,whiteSpace:"pre-wrap",wordBreak:"break-word"}}>{m.text}</div>
                      <div style={{fontSize:"0.6rem",color:C.dim,marginTop:2,textAlign:mine?"right":"left"}}>{m.senderName} · {time}</div>
                    </div>
                  </div>
                );
              })}
              <div ref={endRef}/>
            </div>
            {/* Input — always visible, never hidden behind keyboard */}
            <div style={{background:C.navy,borderTop:`1px solid ${C.border}`,padding:"8px 10px",paddingBottom:`max(8px, env(safe-area-inset-bottom, 8px))`,display:"flex",gap:8,alignItems:"flex-end",flexShrink:0}}>
              <input
                ref={inputRef}
                value={inp}
                onChange={e=>setInp(e.target.value)}
                onKeyDown={e=>{if(e.key==="Enter"){e.preventDefault();send();}}}
                onFocus={()=>setTimeout(()=>{endRef.current?.scrollIntoView({behavior:"smooth"});},400)}
                placeholder="মেসেজ লিখুন…"
                style={{flex:1,background:"rgba(255,255,255,0.08)",border:`1px solid ${C.sky}44`,color:C.white,borderRadius:24,padding:"11px 16px",fontFamily:"inherit",fontSize:"0.9rem",outline:"none"}}
              />
              <button
                onClick={send}
                disabled={loading||!inp.trim()}
                style={{background:inp.trim()?`linear-gradient(135deg,${C.skyDeep},${C.sky})`:"rgba(255,255,255,0.06)",border:"none",color:inp.trim()?"#fff":C.dim,borderRadius:"50%",width:44,height:44,fontSize:"1.1rem",cursor:inp.trim()?"pointer":"default",display:"flex",alignItems:"center",justifyContent:"center",flexShrink:0}}>
                {loading?"⏳":"➤"}
              </button>
            </div>
          </div>
        )}
      </div>
    );
  }

  /* ── DESKTOP LAYOUT ── */
  return(
    <div style={{height:"calc(100vh - 0px)",display:"flex",overflow:"hidden",position:"relative"}}>
      <Toast/>
      <div style={{width:300,flexShrink:0,borderRight:`1px solid ${C.border}`,display:"flex",flexDirection:"column",background:C.navy}}>
        <ConvList/>
      </div>
      <div style={{flex:1,display:"flex",flexDirection:"column",overflow:"hidden"}}>
        {selConv?<ChatPanel/>:<EmptyState/>}
      </div>
    </div>
  );
}

/* ════════════════════════════════════════════════════════════════
   REMAINING PAGES (Courses, Services, Tutorials, AI, Settings,
   Student Portal, Elite Pass, Wallet, Payment, Enroll, Profile)
   ════════════════════════════════════════════════════════════════ */
function CoursesPage() {
  return (<PageWrap><SectionHeader title="Courses & Packages" sub="All training programs"/>
    <div style={{display:"grid",gridTemplateColumns:"repeat(auto-fill,minmax(290px,1fr))",gap:16}}>
      {COURSES.map(c=>(<Card key={c.id}><div style={{display:"flex",justifyContent:"space-between",marginBottom:10}}><span style={{fontSize:"1.8rem"}}>{c.icon}</span><Badge label={c.dur} color={C.gold}/></div><div style={{fontWeight:700,marginBottom:3}}>{c.en}</div><div style={{fontSize:"0.78rem",color:C.dim,marginBottom:8}}>{c.name}</div>{c.topics&&<ul style={{margin:"0 0 10px",paddingLeft:14}}>{c.topics.slice(0,3).map(t=><li key={t} style={{fontSize:"0.72rem",color:C.silver,marginBottom:3}}>{t}</li>)}{c.topics.length>3&&<li style={{fontSize:"0.68rem",color:C.dim}}>+ {c.topics.length-3} আরও বিষয়</li>}</ul>}<div style={{display:"flex",gap:10,alignItems:"center"}}><span style={{fontSize:"1.2rem",fontWeight:800,color:C.sky}}>{fmt(c.fee)}</span><span style={{color:C.dim,textDecoration:"line-through",fontSize:"0.83rem"}}>{fmt(c.orig)}</span><Badge label={`${c.disc}% OFF`} color={C.green}/></div></Card>))}
    </div>
  </PageWrap>);
}
