function TutorialSystem() {
  const sc=useResponsive(); const isMob=sc==="mobile";

  // ── Static tutorial topics (original)
  const STATIC_CATS=[
    {id:"Windows",  icon:"🪟", label:"Windows"},
    {id:"Printer",  icon:"🖨️", label:"Printer"},
    {id:"Networking",icon:"🌐",label:"Networking"},
    {id:"Software", icon:"📦", label:"Software"},
    {id:"Hardware", icon:"🔩", label:"Hardware"},
    {id:"Security", icon:"🛡️", label:"Security"},
    {id:"Troubleshooting",icon:"🔧",label:"Troubleshooting"},
  ];
  const STATIC_DATA={
    Windows:["Windows 11 Installation","Windows 10 Setup Bangla","Bootable USB Rufus","BIOS Settings","Windows Activation Fix"],
    Printer:["HP Printer Setup","Epson Driver Install","Canon Wireless","Print from Mobile","Fix Paper Jam"],
    Networking:["WiFi Setup","Router Config","Network Troubleshoot","Mobile Hotspot","IP Fix"],
    Software:["MS Office 2021","Canva Tutorial","Adobe Reader","7-Zip & WinRAR","Antivirus"],
    Hardware:["RAM Upgrade","HDD to SSD","CPU Thermal Paste","Monitor Fix","USB Port Fix"],
    Security:["Windows Defender","Malwarebytes","Strong Password","VPN Setup","Phishing"],
    Troubleshooting:["PC Not On","Blue Screen Fix","Slow PC","No Sound Fix","Black Screen"],
  };

  // ── Dynamic guide cats (from GUIDES with ytq)
  const guideCatIds=[...new Set(GUIDES.filter(g=>g.ytq).map(g=>g.cat))];
  const GUIDE_CATS=CATS.filter(c=>guideCatIds.includes(c.id));

  // ── All category tabs: "all" + static cats + guide cats
  const ALL_TABS=[
    {id:"all", icon:"📋", label:"সব"},
    ...STATIC_CATS,
    ...GUIDE_CATS.map(c=>({id:`guide_${c.id}`,icon:c.icon,label:c.name})),
  ];

  const [activeCat,setActiveCat]=useState("all");
  const [search,setSearch]=useState("");
  const q=search.toLowerCase();

  // ── Build unified video list
  const staticVideos=STATIC_CATS.flatMap(cat=>
    (STATIC_DATA[cat.id]||[]).map(title=>({
      type:"static", id:`s_${cat.id}_${title}`,
      icon:cat.icon, name:title,
      short:`YouTube · ${cat.label}`,
      cat:cat.id,
      ytUrl:`https://www.youtube.com/results?search_query=${encodeURIComponent(title+" bangla")}`,
    }))
  );
  const guideVideos=GUIDES.filter(g=>g.ytq).map(g=>({
    type:"guide", id:`g_${g.id}`,
    icon:g.icon, name:g.name,
    short:g.short,
    cat:`guide_${g.cat}`,
    ytUrl:`https://www.youtube.com/results?search_query=${encodeURIComponent(g.ytq)}`,
  }));
  const allVideos=[...staticVideos,...guideVideos];

  const filtered=allVideos.filter(v=>{
    const matchCat=activeCat==="all"||v.cat===activeCat;
    const matchQ=!q||v.name.toLowerCase().includes(q)||v.short.toLowerCase().includes(q);
    return matchCat&&matchQ;
  });

  return (
    <PageWrap>
      <SectionHeader title="Video Tutorial System" sub="YouTube integrated tutorials"/>

      {/* Search */}
      <input
        value={search} onChange={e=>setSearch(e.target.value)}
        placeholder="🔍 টিউটোরিয়াল খুঁজুন…"
        style={{marginBottom:14,width:"100%",maxWidth:360,background:"rgba(255,255,255,0.04)",border:`1px solid ${C.border}`,color:C.white,borderRadius:9,padding:"9px 14px",fontFamily:"inherit",fontSize:"0.87rem",outline:"none",boxSizing:"border-box"}}
      />

      {/* Category tabs — scrollable row */}
      <div style={{display:"flex",gap:6,flexWrap:"wrap",marginBottom:20}}>
        {ALL_TABS.map(t=>{
          const active=activeCat===t.id;
          return (
            <button key={t.id} onClick={()=>setActiveCat(t.id)} style={{
              background:active?`linear-gradient(135deg,${C.skyDeep},${C.sky})`:"rgba(255,255,255,0.05)",
              border:active?"none":`1px solid ${C.border}`,
              borderRadius:8,padding:isMob?"7px 11px":"8px 14px",
              color:active?"#fff":C.silver,
              fontSize:isMob?"0.75rem":"0.83rem",
              fontWeight:active?700:500,
              cursor:"pointer",fontFamily:"inherit",whiteSpace:"nowrap",
            }}>{t.icon} {t.label}</button>
          );
        })}
      </div>

      {/* Count */}
      <div style={{fontSize:"0.74rem",color:C.dim,marginBottom:12,fontWeight:600}}>{filtered.length}টি ভিডিও</div>

      {/* Video grid */}
      <div style={{display:"grid",gridTemplateColumns:isMob?"repeat(auto-fill,minmax(150px,1fr))":"repeat(auto-fill,minmax(240px,1fr))",gap:12}}>
        {filtered.map(v=>(
          <a key={v.id} href={v.ytUrl} target="_blank" rel="noopener noreferrer" onClick={e=>{e.preventDefault();window.open(v.ytUrl,'_blank');}} style={{textDecoration:"none"}}>
            <div style={{background:C.card,border:`1px solid ${C.border}`,borderRadius:12,overflow:"hidden",height:"100%"}}>
              <div style={{background:"linear-gradient(135deg,#1a0505,#3a1010)",height:isMob?60:76,display:"flex",alignItems:"center",justifyContent:"center",gap:10}}>
                <span style={{fontSize:isMob?"1.3rem":"1.5rem"}}>{v.icon}</span>
                <div style={{width:isMob?30:36,height:isMob?30:36,borderRadius:"50%",background:"rgba(255,0,0,0.85)",display:"flex",alignItems:"center",justifyContent:"center",flexShrink:0}}>
                  <span style={{color:"#fff",fontSize:isMob?"0.75rem":"0.85rem",marginLeft:2}}>▶</span>
                </div>
              </div>
              <div style={{padding:isMob?"9px 10px":"12px 14px"}}>
                <div style={{fontSize:isMob?"0.77rem":"0.84rem",fontWeight:700,color:C.white,marginBottom:3,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{v.name}</div>
                <div style={{fontSize:"0.68rem",color:C.dim,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{v.short}</div>
              </div>
            </div>
          </a>
        ))}
      </div>
      {filtered.length===0&&<div style={{padding:40,textAlign:"center",color:C.dim}}>কোনো ভিডিও পাওয়া যায়নি।</div>}
    </PageWrap>
  );
}
