// ══ Gemini fallback ══
async function callGeminiFallback(userMsg, history, systemPrompt) {
  try {
    const contents = history
      .filter((m,i) => m.role !== "ai" || i > 0)
      .map(m => ({
        role: m.role === "ai" ? "model" : "user",
        parts: [{ text: m.text }]
      }));
    contents.push({ role: "user", parts: [{ text: userMsg }] });
    const res = await fetch(
      `/api/gemini`,
      {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          system_instruction: { parts: [{ text: systemPrompt }] },
          contents,
          generationConfig: { temperature: 0.7, maxOutputTokens: 1200 }
        }),
        signal: AbortSignal.timeout(20000)
      }
    );
    if (!res.ok) { console.warn("[Tandra] callGeminiFallback error:", res.status); return null; }
    const d = await res.json();
    const text = d?.candidates?.[0]?.content?.parts?.map(p => p.text || "").join("").trim();
    return text && text.length > 5 ? text : null;
  } catch(e) { console.warn("[Tandra] callGeminiFallback fetch error:", e?.message); return null; }
}

