// ── HTML → plain text/markdown cleanup for step content ──
function _stripStepHtml(html) {
  if (!html) return '';
  const cleaned = html
    .replace(/<br\s*\/?>/gi, '\n')
    .replace(/<strong>(.*?)<\/strong>/gi, '**$1**')
    .replace(/<code>(.*?)<\/code>/gi, '`$1`')
    .replace(/<a[^>]*href="([^"]*)"[^>]*>([^<]*)<\/a>/gi, '[$2]($1)')
    .replace(/<[^>]+>/g, '')
    .replace(/&amp;/g,'&').replace(/&#39;/g,"'").replace(/&lt;/g,'<').replace(/&gt;/g,'>');
  return cleaned
    .split('\n')
    .map(l => l.replace(/^•\s*/, '').trim())
    .filter(Boolean)
    .map(l => `• ${l}`)
    .join('\n');
}

// ── Extract inline <a href> links from step content (ISO/file sources) ──
function _extractInlineLinks(html) {
  const links = [];
  const re = /<a[^>]*href="([^"]*)"[^>]*>([^<]*)<\/a>/gi;
  let m;
  while ((m = re.exec(html||'')) !== null) links.push({ url: m[1], text: m[2].trim() });
  return links;
}

