function MakePayment({student, onSubmit}) {
  const [method,setMethod]=useState("bKash");
  const [senderName,setSenderName]=useState("");
  const [senderNum,setSenderNum]=useState("");
  const [txnId,setTxnId]=useState("");
  const [amount,setAmount]=useState("");
  const [loading,setLoading]=useState(false);
  const [done,setDone]=useState(false);
  const [err,setErr]=useState("");

  const M=[
    {
      id:"bKash", imgSrc:IMG_BKASH, Fallback:FallbackBkash,
      label:"bKash", accountName:"Md Fakhrul Islam Sagor",
      num:"+8801612745977", numAlt:null,
      color:"#E2136E", numLabel:"bKash Personal Number", imgBg:"#fff", imgH:38,
    },
    {
      id:"Rocket", imgSrc:IMG_ROCKET, Fallback:FallbackRocket,
      label:"Rocket", accountName:"Md Fakhrul Islam Sagor",
      num:"+8801612745977", numAlt:"+8801612745977 2",
      color:"#8B1A8B", numLabel:"Rocket Personal Number", imgBg:"transparent", imgH:38,
    },
    {
      id:"Bank", imgSrc:IMG_DBBL, Fallback:FallbackDbbl,
      label:"Dutch Bangla Bank — PLC", accountName:"Md Fakhrul Islam Sagor",
      num:"7017416321358", numAlt:null,
      color:"#003F8A", numLabel:"Account Number", imgBg:"#fff", imgH:34,
    },
    {
      id:"Cash", imgSrc:null, Fallback:null,
      label:"Cash", accountName:"",
      num:"Direct payment", numAlt:null,
      color:C.gold, numLabel:"", imgBg:"transparent", imgH:36,
    },
  ];

  const [cashSenderName,setCashSenderName]=useState("");
  const [cashUserId,setCashUserId]=useState(student?.id||"");
  const isMob=useResponsive()==="mobile";
  const sel=M.find(m=>m.id===method);
  const needSender=method!=="Cash";
  const isCash=method==="Cash";

  const submit=async()=>{
    setErr("");
    if(!amount||isNaN(parseInt(amount))||parseInt(amount)<=0){setErr("সঠিক পরিমাণ লিখুন।");return;}
    if(isCash&&!cashSenderName.trim()){setErr("যিনি টাকা পাঠিয়েছেন তার নাম লিখুন।");return;}
    if(isCash&&!cashUserId.trim()){setErr("User ID / Student ID লিখুন।");return;}
    if(needSender&&!senderName.trim()){setErr("প্রেরকের নাম লিখুন।");return;}
    if(needSender&&!senderNum.trim()){setErr("যে নম্বর থেকে পাঠানো হয়েছে সেটি লিখুন।");return;}
    if(needSender&&!txnId.trim()){setErr("Transaction ID লিখুন।");return;}
    setLoading(true);
    const payData={
      studentId:student?.id||"",
      studentName:student?.name||"",
      method,
      senderName:isCash?cashSenderName.trim():senderName.trim(),
      senderNum:isCash?cashUserId.trim():senderNum.trim(),
      txnId:txnId.trim(),
      amount:parseInt(amount),
      date:new Date().toISOString().split("T")[0],
      status:PAY_STATUS.PENDING,
      adminNote:"",
      createdAt:Date.now(),
    };
    const fbResult = await fbPush("payments",payData);
    const savedPay = {...payData, id: fbResult?.name||("tmp_"+Date.now()), firebaseKey: fbResult?.name||""};
    // immediately update app-level payments state so admin sees it right away
    if(onSubmit) onSubmit(savedPay);
    window._ppPayDirty = true; // signal App to reload payments from Firebase
    // ── notify all admins ──
    await notifyAllAdmins({
      type:"new_payment", icon:"💳", color:"#f59e0b",
      title:"নতুন Payment জমা!",
      body:`${payData.studentName||"একজন ব্যবহারকারী"} — ৳${payData.amount?.toLocaleString()} (${payData.method}) অনুমোদনের জন্য অপেক্ষায়।`
    });
    setLoading(false);
    setDone(true);
  };

  if(done) return (
    <PageWrap>
      <Card style={{textAlign:"center",padding:"40px 30px",maxWidth:460}}>
        <div style={{fontSize:"3rem",marginBottom:16}}>⏳</div>
        <div style={{fontSize:"1.2rem",fontWeight:800,marginBottom:8}}>Payment Submitted!</div>
        <div style={{fontSize:"0.85rem",color:C.silver,marginBottom:8}}>
          Amount: <strong style={{color:C.green}}>{fmt(parseInt(amount))}</strong> via <strong>{method}</strong>
        </div>
        {senderNum&&<div style={{fontSize:"0.82rem",color:C.dim,marginBottom:4}}>From: <strong style={{color:C.text}}>{senderNum}</strong></div>}
        {txnId&&<div style={{fontSize:"0.82rem",color:C.dim,marginBottom:16}}>TXN: <strong style={{color:C.sky,fontFamily:"monospace"}}>{txnId}</strong></div>}
        <Badge label="PENDING APPROVAL" color={C.amber}/>
        <div style={{marginTop:20}}><Btn onClick={()=>{setDone(false);setAmount("");setSenderName("");setSenderNum("");setTxnId("");}} variant="ghost">আরেকটি পেমেন্ট করুন</Btn></div>
      </Card>
    </PageWrap>
  );

  return (
    <PageWrap>
      <SectionHeader eye="PAYMENT" title="পেমেন্ট করুন"/>
      <div style={{maxWidth:500}}>
        {/* Method selector */}
        <div style={{marginBottom:20}}>
          <div style={{fontSize:"0.72rem",fontWeight:700,color:C.dim,letterSpacing:"1px",textTransform:"uppercase",marginBottom:10}}>Payment Method</div>
          <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:10}}>
            {M.map(m=>{
              const active=method===m.id;
              return (
                <button key={m.id} onClick={()=>setMethod(m.id)} style={{background:active?`${m.color}18`:C.card,border:`1.5px solid ${active?m.color+"66":C.border}`,borderRadius:14,padding:"14px 12px",cursor:"pointer",textAlign:"left",transition:"all 0.15s",position:"relative"}}>
                  {active&&<span style={{position:"absolute",top:8,right:8,fontSize:"0.6rem",background:m.color,color:"#fff",borderRadius:4,padding:"2px 5px",fontWeight:700}}>✓</span>}
                  {/* Logo area */}
                  <div style={{marginBottom:8,height:38,display:"flex",alignItems:"center"}}>
                    {m.imgSrc
                      ? <PayLogo src={m.imgSrc} Fallback={m.Fallback} height={m.imgH} bg={m.imgBg}/>
                      : <span style={{fontSize:"1.8rem"}}>💵</span>
                    }
                  </div>
                  <div style={{fontSize:"0.88rem",fontWeight:700,color:active?m.color:C.white,lineHeight:1.3}}>{m.label}</div>
                  <div style={{fontSize:"0.7rem",color:C.dim,marginTop:2,fontFamily:"monospace"}}>{m.num}</div>
                </button>
              );
            })}
          </div>
        </div>

        {/* Send-to info box — full account details */}
        <div style={{background:`${sel.color}12`,border:`1px solid ${sel.color}35`,borderRadius:14,padding:"16px 18px",marginBottom:18}}>
          <div style={{display:"flex",alignItems:"center",gap:12,marginBottom:12}}>
            {sel.imgSrc
              ? <div style={{background:sel.imgBg||"#fff",borderRadius:8,padding:"4px 8px",display:"flex",alignItems:"center"}}><PayLogo src={sel.imgSrc} Fallback={sel.Fallback} height={sel.imgH} bg={sel.imgBg}/></div>
              : <span style={{fontSize:"2rem"}}>💵</span>
            }
            <div>
              <div style={{fontWeight:800,color:sel.color,fontSize:"0.95rem"}}>{sel.label}</div>
              <div style={{fontSize:"0.72rem",color:C.dim}}>প্রযুক্তিপুঞ্জ অফিশিয়াল অ্যাকাউন্ট</div>
            </div>
          </div>
          <div style={{display:"flex",flexDirection:"column",gap:6,fontSize:"0.82rem"}}>
            {sel.accountName&&(
              <div style={{display:"flex",gap:8}}>
                <span style={{color:C.dim,minWidth:110}}>Account Name:</span>
                <span style={{fontWeight:700,color:C.white}}>{sel.accountName}</span>
              </div>
            )}
            <div style={{display:"flex",gap:8}}>
              <span style={{color:C.dim,minWidth:110}}>{sel.numLabel||"Number"}:</span>
              <span style={{fontWeight:800,color:sel.color,fontFamily:"monospace"}}>{sel.num}</span>
            </div>
            {sel.numAlt&&(
              <div style={{display:"flex",gap:8}}>
                <span style={{color:C.dim,minWidth:110}}>Alt Number:</span>
                <span style={{fontWeight:700,color:sel.color,fontFamily:"monospace"}}>{sel.numAlt}</span>
              </div>
            )}
          </div>
        </div>

        <Card>
          {/* Cash: name + userId + amount */}
          {isCash && <>
            <Inp label="যিনি টাকা পাঠিয়েছেন তার নাম *" value={cashSenderName} onChange={e=>setCashSenderName(e.target.value)} placeholder="প্রেরকের পুরো নাম"/>
            <Inp label="User ID / Student ID *" value={cashUserId} onChange={e=>setCashUserId(e.target.value)} placeholder="PP-2026-XX-XX-XXXX" helper="যার পক্ষে পেমেন্ট করা হচ্ছে তার ID"/>
          </>}
          {/* Non-cash: name + number + TXN */}
          {needSender && <>
            <Inp label="প্রেরকের নাম *" value={senderName} onChange={e=>setSenderName(e.target.value)} placeholder="যিনি টাকা পাঠিয়েছেন তার নাম"/>
            <Inp label={`যে নম্বর থেকে পাঠানো হয়েছে * (${sel.numLabel})`} value={senderNum} onChange={e=>setSenderNum(e.target.value)} placeholder="01XXXXXXXXX"/>
            <Inp label="Transaction ID *" value={txnId} onChange={e=>setTxnId(e.target.value)} placeholder="TXN123456789"/>
          </>}
          <Inp label="Amount (BDT) *" value={amount} onChange={e=>setAmount(e.target.value)} type="number" placeholder="0" required/>
          <div style={{background:`${C.sky}08`,border:`1px solid ${C.sky}20`,borderRadius:10,padding:"12px 14px",marginBottom:16,fontSize:"0.8rem",color:C.silver}}>
            <strong style={{color:C.sky}}>Points earned:</strong> {calcPoints(parseInt(amount)||0)} pts
          </div>
          {err&&<div style={{background:`${C.red}10`,border:`1px solid ${C.red}25`,borderRadius:8,padding:"9px 13px",marginBottom:12,fontSize:"0.8rem",color:C.red}}>{err}</div>}
          <Btn onClick={submit} style={{width:"100%"}} disabled={loading||!amount}>
            {loading?"জমা হচ্ছে...":"Submit Payment →"}
          </Btn>
        </Card>
      </div>
    </PageWrap>
  );
}

function OwnerRecovery({onBack,users,setUsers}) {
  const [step,setStep]=useState(0); // 0=email, 1=secret code, 2=approved, 3=reset, 4=done
  const [email1,setEmail1]=useState("");
  const [email2,setEmail2]=useState("");
  const [code,setCode]=useState("");
  const [newPwd,setNewPwd]=useState("");
  const [confirmPwd,setConfirmPwd]=useState("");
  const [codeErr,setCodeErr]=useState(false);
  const [pwdErr,setPwdErr]=useState("");

  // Email verification: both must match AND match hidden owner email
  const emailOk = email1.trim().toLowerCase()===email2.trim().toLowerCase()
                  && email1.trim().toLowerCase()===CHIEF_SECRET_EMAIL.toLowerCase()
                  && email1.length>0;

  const verifyCode=()=>{
    setCodeErr(false);
    const logEntry={action:"OWNER_RECOVERY_ATTEMPT",timestamp:new Date().toISOString(),device:navigator.userAgent||"unknown"};
    if(code.trim()===CHIEF_RECOVERY_CODE){
      fbPush("logs",{...logEntry,status:"SUCCESS"});
      setStep(2);
    } else {
      fbPush("logs",{...logEntry,status:"FAILED"});
      setCodeErr(true);
    }
  };

  const resetPassword=()=>{
    setPwdErr("");
    if(newPwd.length<8){setPwdErr("Password কমপক্ষে ৮ অক্ষর হতে হবে।");return;}
    if(newPwd!==confirmPwd){setPwdErr("Password দুটি মিলছে না।");return;}
    // Find chief admin user and update password
    const ownerEmail=CHIEF_SECRET_EMAIL.toLowerCase();
    const newUsers=users.map(u=>{
      if((u.role===ROLES.CHIEF_ADMIN||u.isMainAdmin)&&u.email&&u.email.toLowerCase()===ownerEmail){
        return {...u,password:newPwd};
      }
      return u;
    });
    setUsers(newUsers);
    // Also update Firebase chief_admin record timestamp
    fbPatch("chief_admin",{passwordUpdated:Date.now()});
    fbPush("logs",{action:"OWNER_PASSWORD_RESET",status:"SUCCESS",timestamp:new Date().toISOString()});
    setStep(4);
  };

  const STEPS=["Verify","Code","Approved","Reset"];

  return (
    <div style={{minHeight:"100vh",background:`radial-gradient(ellipse at center,${C.mid} 0%,${C.bg} 60%)`,display:"flex",alignItems:"center",justifyContent:"center",padding:16}}>
      <div style={{width:"100%",maxWidth:480}}>
        {/* No visible title — intentionally low-profile */}
        <div style={{textAlign:"center",marginBottom:22}}>
          <div style={{width:56,height:56,margin:"0 auto 10px",background:`linear-gradient(135deg,#1a1a2e,${C.navy})`,borderRadius:14,display:"flex",alignItems:"center",justifyContent:"center",border:`1px solid ${C.border}`}}>
            <img src={LOGO} alt="" onError={e=>{e.target.src=LOGO_FALLBACK;}} style={{width:42,height:42,objectFit:"contain",opacity:0.7}}/>
          </div>
          <div style={{fontSize:"0.9rem",fontWeight:700,color:C.silver}}>Account Verification</div>
          <div style={{fontSize:"0.68rem",color:C.dim,marginTop:2}}>প্রযুক্তিপুঞ্জ · Secure Access</div>
        </div>

        <Card glow>
          <StepBar steps={STEPS} current={step}/>

          {/* ── STEP 0: Email Verification ── */}
          {step===0&&(
            <div>
              <div style={{marginBottom:14}}>
                <div style={{fontSize:"0.72rem",fontWeight:700,color:C.dim,letterSpacing:"1px",textTransform:"uppercase",marginBottom:5}}>Registered Email Address <span style={{color:C.red}}>*</span></div>
                <input type="email" value={email1} onChange={e=>setEmail1(e.target.value)} placeholder="Enter registered email" style={{width:"100%",background:"rgba(255,255,255,0.05)",border:`1px solid ${C.border}`,color:C.white,borderRadius:8,padding:"9px 12px",fontFamily:"inherit",fontSize:"0.88rem",outline:"none",boxSizing:"border-box"}}/>
              </div>
              <div style={{marginBottom:18}}>
                <div style={{fontSize:"0.72rem",fontWeight:700,color:C.dim,letterSpacing:"1px",textTransform:"uppercase",marginBottom:5}}>Secret Email Address <span style={{color:C.red}}>*</span></div>
                <input type="email" value={email2} onChange={e=>setEmail2(e.target.value)} placeholder="Confirm email address" style={{width:"100%",background:"rgba(255,255,255,0.05)",border:`1px solid ${C.border}`,color:C.white,borderRadius:8,padding:"9px 12px",fontFamily:"inherit",fontSize:"0.88rem",outline:"none",boxSizing:"border-box"}}/>
              </div>
              <Btn onClick={()=>setStep(1)} disabled={!emailOk} style={{width:"100%",padding:"12px"}}>Next →</Btn>
            </div>
          )}

          {/* ── STEP 1: Secret Code ── */}
          {step===1&&(
            <div>
              <div style={{background:`${C.sky}08`,border:`1px solid ${C.sky}20`,borderRadius:10,padding:"10px 14px",marginBottom:18,fontSize:"0.8rem",color:C.silver,lineHeight:1.7}}>
                Email verified. Enter your secret access code to continue.
              </div>
              <div style={{marginBottom:18}}>
                <div style={{fontSize:"0.72rem",fontWeight:700,color:C.dim,letterSpacing:"1px",textTransform:"uppercase",marginBottom:5}}>Enter Secret Code <span style={{color:C.red}}>*</span></div>
                <input type="password" value={code} onChange={e=>{setCode(e.target.value);setCodeErr(false);}} placeholder="••••••••••••••" style={{width:"100%",background:"rgba(255,255,255,0.05)",border:`1px solid ${codeErr?C.red:C.border}`,color:C.white,borderRadius:8,padding:"9px 12px",fontFamily:"monospace",fontSize:"0.95rem",outline:"none",boxSizing:"border-box",letterSpacing:"3px"}}/>
                {codeErr&&<div style={{fontSize:"0.72rem",color:C.red,marginTop:6}}>Verification failed. Please try again.</div>}
              </div>
              <Btn onClick={verifyCode} disabled={!code.trim()} style={{width:"100%",padding:"12px"}}>Verify →</Btn>
            </div>
          )}

          {/* ── STEP 2: Approved ── */}
          {step===2&&(
            <div style={{textAlign:"center",padding:"10px 0"}}>
              <div style={{fontSize:"2.8rem",marginBottom:10}}>✅</div>
              <div style={{fontSize:"1.1rem",fontWeight:800,color:C.green,marginBottom:8}}>Your application has been approved successfully.</div>
              <div style={{fontSize:"0.82rem",color:C.silver,marginBottom:22,lineHeight:1.7}}>
                Identity confirmed. You may now reset your account password.
              </div>
              <Btn onClick={()=>setStep(3)} style={{width:"100%",padding:"12px"}}>Next → Reset Password</Btn>
            </div>
          )}

          {/* ── STEP 3: Password Reset ── */}
          {step===3&&(
            <div>
              <div style={{background:`${C.green}08`,border:`1px solid ${C.green}20`,borderRadius:10,padding:"10px 14px",marginBottom:18,fontSize:"0.8rem",color:C.green}}>
                🔒 Set a strong new password (minimum 8 characters).
              </div>
              <PwdInp label="New Password" value={newPwd} onChange={e=>setNewPwd(e.target.value)} placeholder="New password (min 8 chars)" required/>
              <PwdInp label="Confirm New Password" value={confirmPwd} onChange={e=>setConfirmPwd(e.target.value)} required/>
              {pwdErr&&<div style={{color:C.red,fontSize:"0.8rem",marginBottom:10,background:`${C.red}10`,borderRadius:8,padding:"8px 12px"}}>⚠ {pwdErr}</div>}
              <Btn onClick={resetPassword} disabled={!newPwd||!confirmPwd} style={{width:"100%",padding:"12px"}} variant="success">🔑 Update Password</Btn>
            </div>
          )}

          {/* ── STEP 4: Done ── */}
          {step===4&&(
            <div style={{textAlign:"center",padding:"10px 0"}}>
              <div style={{fontSize:"2.8rem",marginBottom:10}}>🎉</div>
              <div style={{fontSize:"1.1rem",fontWeight:800,color:C.green,marginBottom:8}}>Approval Successful.</div>
              <div style={{fontSize:"0.88rem",color:C.silver,marginBottom:6,lineHeight:1.7}}>You can now access your system.</div>
              <div style={{background:`${C.sky}08`,border:`1px solid ${C.sky}20`,borderRadius:10,padding:"10px 14px",marginBottom:20,fontSize:"0.8rem",color:C.silver,lineHeight:1.7,textAlign:"left"}}>
                ✅ Password updated successfully.<br/>
                ✅ Full system access restored.<br/>
                ✅ Login with User ID, Mobile, or Email + new password.
              </div>
              <Btn onClick={onBack} style={{width:"100%",padding:"12px"}} variant="success">← Go to Login</Btn>
            </div>
          )}
        </Card>

        {step<4&&(
          <div style={{textAlign:"center",marginTop:14}}>
            <button onClick={onBack} style={{background:"none",border:"none",color:C.dim,fontSize:"0.75rem",cursor:"pointer",fontFamily:"inherit"}}>← Back to Login</button>
          </div>
        )}
      </div>
    </div>
  );
}

