function PayLogo({src,Fallback,height=36,bg="transparent"}){
  const [err,setErr]=useState(false);
  if(err) return <Fallback/>;
  return <img src={src} alt="" style={{height,objectFit:"contain",background:bg,borderRadius:4}} onError={()=>setErr(true)}/>;
}

function PointHistory({userId, localReqs=[]}) {
  const [reqs, setReqs]       = useState([]);
  const [loading, setLoading] = useState(true);
  const [filter, setFilter]   = useState("all");
  const [detail, setDetail]   = useState(null); // selected req for detail modal
  const sc = useResponsive(); const mob = sc==="mobile";

  const load = async () => {
    setLoading(true);
    if(!window._ppAllReqs) window._ppAllReqs=[...DEMO_POINT_REQUESTS];
    const data=await fbGet("pointRequests");
    if(data){
      const demoKeys=new Set(DEMO_POINT_REQUESTS.map(d=>d._key));
      const existingKeys=new Set(window._ppAllReqs.map(r=>r._key));
      Object.entries(data).map(([k,v])=>({...v,_key:k}))
        .filter(r=>!demoKeys.has(r._key))
        .forEach(r=>{ if(!existingKeys.has(r._key)) window._ppAllReqs.push(r); });
    }
    if(!window._ppDeletedPtReqs) window._ppDeletedPtReqs=new Set();
    const myReqs=window._ppAllReqs.filter(r=>
      (!userId||r.userId===userId) && !window._ppDeletedPtReqs.has(r._key)
    );
    setReqs(myReqs.sort((a,b)=>b.createdAt-a.createdAt));
    setLoading(false);
  };

  useEffect(()=>{
    load();
    const i=setInterval(()=>{ if(window._ppPtReqDirty){ window._ppPtReqDirty=false; load(); } },1500);
    const j=setInterval(load,8000);
    return()=>{clearInterval(i);clearInterval(j);};
  },[userId]);

  const deleteReq = async (r) => {
    ppAddDeletedPtReq(r._key);
    if(!r.isDemo && r._key && !r._key.startsWith("tmp_")){
      await fbDelete(`pointRequests/${r._key}`);
    }
    setReqs(prev=>prev.filter(x=>x._key!==r._key));
    setDetail(null);
  };

  const filtered = filter==="all"?reqs:reqs.filter(r=>r.type===filter||r.status===filter);
  const sColor = s=>s==="approved"?C.green:s==="rejected"?C.red:C.amber;
  const sLabel = s=>s==="approved"?"✅ অনুমোদিত":s==="rejected"?"❌ প্রত্যাখ্যাত":"⏳ অপেক্ষায়";

  return (
    <div>
      {/* ── Detail Modal ── */}
      {detail&&(
        <div style={{position:"fixed",inset:0,background:"rgba(0,0,0,0.7)",zIndex:999,display:"flex",alignItems:"center",justifyContent:"center",padding:16}} onClick={()=>setDetail(null)}>
          <div style={{background:C.card,border:`1px solid ${C.border}`,borderRadius:16,padding:20,maxWidth:400,width:"100%",maxHeight:"80vh",overflowY:"auto"}} onClick={e=>e.stopPropagation()}>
            <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:16}}>
              <div style={{fontWeight:800,fontSize:"1rem",color:C.white}}>📋 Transaction Detail</div>
              <button onClick={()=>setDetail(null)} style={{background:"none",border:"none",color:C.dim,fontSize:"1.2rem",cursor:"pointer"}}>✕</button>
            </div>
            {[
              ["সেবা", detail.serviceName],
              ["ধরন", detail.type==="earn"?"🟢 Earn +Point":"🔴 Redeem -Point"],
              ["পয়েন্ট", `${detail.type==="earn"?"+":"-"}${detail.points} pts`],
              ["ক্যাটাগরি", detail.category],
              ["তারিখ", detail.date],
              ["স্ট্যাটাস", sLabel(detail.status)],
              ...(detail.note?[["নোট", detail.note]]:[]),
              ...(detail.status==="approved"?[["অনুমোদন", "✅ Admin অনুমোদন দিয়েছেন"]]:
                  detail.status==="rejected"?[["প্রত্যাখ্যানের কারণ", detail.rejectNote||detail.adminNote||"Admin কর্তৃক প্রত্যাখ্যাত"]]:
                  [["অবস্থা","⏳ Admin অনুমোদনের অপেক্ষায়"]])
            ].map(([l,v])=>(
              <div key={l} style={{display:"flex",justifyContent:"space-between",padding:"8px 0",borderBottom:`1px solid ${C.border}`,gap:12}}>
                <span style={{color:C.dim,fontSize:"0.8rem",flexShrink:0}}>{l}</span>
                <span style={{color:l==="প্রত্যাখ্যানের কারণ"?C.red:l==="অনুমোদন"?C.green:C.white,fontSize:"0.8rem",fontWeight:600,textAlign:"right"}}>{v}</span>
              </div>
            ))}
            <button onClick={()=>deleteReq(detail)} style={{width:"100%",marginTop:16,background:`${C.red}15`,border:`1px solid ${C.red}30`,color:C.red,borderRadius:10,padding:"10px",fontSize:"0.8rem",fontWeight:700,cursor:"pointer",fontFamily:"inherit"}}>
              🗑 এই Transaction মুছে ফেলুন
            </button>
          </div>
        </div>
      )}

      <div style={{display:"flex",gap:8,flexWrap:"wrap",marginBottom:16,alignItems:"center"}}>
        {[["all","সব"],["earn","Earn 🟢"],["redeem","Redeem 🔴"],["pending","Pending"],["approved","Approved"]].map(([k,l])=>(
          <button key={k} onClick={()=>setFilter(k)} style={{background:filter===k?`linear-gradient(135deg,${C.skyDeep},${C.sky})`:"rgba(255,255,255,0.05)",border:"none",borderRadius:8,padding:"6px 14px",color:filter===k?"#fff":C.silver,fontSize:"0.75rem",fontWeight:filter===k?700:500,cursor:"pointer",fontFamily:"inherit"}}>{l}</button>
        ))}
        <button onClick={load} style={{marginLeft:"auto",background:"rgba(255,255,255,0.05)",border:`1px solid ${C.border}`,color:C.silver,borderRadius:8,padding:"6px 12px",fontSize:"0.75rem",cursor:"pointer",fontFamily:"inherit"}}>🔄</button>
      </div>
      {loading&&<div style={{color:C.dim,textAlign:"center",padding:30}}>লোড হচ্ছে...</div>}
      {!loading&&filtered.length===0&&(
        <div style={{textAlign:"center",padding:"30px 20px"}}>
          <div style={{fontSize:"1.8rem",marginBottom:8}}>📭</div>
          <div style={{color:C.dim,marginBottom:6}}>কোনো রেকর্ড নেই।</div>
        </div>
      )}
      {filtered.length>0&&(
        <div style={{display:"flex",justifyContent:"flex-end",marginBottom:8}}>
          <button onClick={async()=>{
            for(const r of filtered){
              ppAddDeletedPtReq(r._key);
              if(!r.isDemo&&r._key&&!r._key.startsWith("tmp_")) fbDelete(`pointRequests/${r._key}`);
            }
            setReqs(prev=>prev.filter(x=>!filtered.some(f=>f._key===x._key)));
          }} style={{background:`${C.red}12`,border:`1px solid ${C.red}25`,color:C.red,borderRadius:8,padding:"5px 12px",fontSize:"0.72rem",fontWeight:700,cursor:"pointer",fontFamily:"inherit"}}>🗑 সব মুছুন</button>
        </div>
      )}
      {filtered.map(r=>(
        <div key={r._key} style={{marginBottom:8}}>
          <div style={{background:C.card,border:`1px solid ${r.type==="earn"?C.green+"25":C.red+"25"}`,borderRadius:r.status==="rejected"&&(r.rejectNote||r.adminNote)?"10px 10px 0 0":10,padding:mob?"10px 12px":"12px 16px",display:"flex",alignItems:"center",gap:12}}>
            <div onClick={()=>setDetail(r)} style={{width:36,height:36,borderRadius:10,background:r.type==="earn"?`${C.green}15`:`${C.red}15`,display:"flex",alignItems:"center",justifyContent:"center",fontSize:"1rem",flexShrink:0,cursor:"pointer"}}>{r.type==="earn"?"🟢":"🔴"}</div>
            <div onClick={()=>setDetail(r)} style={{flex:1,minWidth:0,cursor:"pointer"}}>
              <div style={{fontSize:"0.8rem",fontWeight:700,color:C.white,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{r.serviceName}</div>
              <div style={{fontSize:"0.68rem",color:C.dim}}>{r.category} • {r.date}</div>
            </div>
            <div onClick={()=>setDetail(r)} style={{textAlign:"right",flexShrink:0,cursor:"pointer",marginRight:6}}>
              <div style={{fontWeight:800,fontSize:"0.88rem",color:r.type==="earn"?C.green:C.red}}>{r.type==="earn"?"+":"-"}{r.points?.toLocaleString()} pts</div>
              <Badge label={sLabel(r.status)} color={sColor(r.status)} size="xs"/>
            </div>
            <button onClick={e=>{e.stopPropagation();deleteReq(r);}} title="মুছুন"
              style={{background:`${C.red}12`,border:`1px solid ${C.red}25`,color:C.red,borderRadius:8,padding:"5px 8px",fontSize:"0.82rem",cursor:"pointer",fontFamily:"inherit",flexShrink:0,fontWeight:700}}>🗑</button>
          </div>
          {r.status==="rejected"&&(r.rejectNote||r.adminNote)&&(
            <div style={{background:"rgba(248,113,113,0.07)",border:"1px solid rgba(248,113,113,0.2)",borderRadius:"0 0 8px 8px",padding:"7px 12px",fontSize:"0.75rem",color:"#fca5a5",lineHeight:1.6}}>
              ❌ <strong>Reject Reason:</strong> {r.rejectNote||r.adminNote}
            </div>
          )}
        </div>
      ))}
    </div>
  );
}

