function TandraCalculator() {
  const [display, setDisplay] = useState('');
  const [history, setHistory] = useState([]);
  const input = (v) => {
    if (v === 'C') { setDisplay(''); return; }
    if (v === '⌫') { setDisplay(d => d.slice(0,-1)); return; }
    if (v === '=') {
      try {
        const expr = display.replace(/×/g,'*').replace(/÷/g,'/').replace(/%/g,'*0.01');
        const result = Function(`"use strict";return(${expr})`)();
        if (!isNaN(result)) { setHistory(h => [`${display} = ${result}`,...h.slice(0,9)]); setDisplay(String(result)); }
      } catch { setDisplay('Error'); }
      return;
    }
    setDisplay(d => d + v);
  };
  const keys = ['C','⌫','%','÷','7','8','9','×','4','5','6','−','1','2','3','+','0','.','='];
  return (
    <div style={{padding:'10px 0'}}>
      <div style={{background:'rgba(0,5,20,0.8)',border:`1px solid ${C.border}`,borderRadius:8,padding:'10px 12px',fontSize:'1.4rem',color:'#4ade80',textAlign:'right',marginBottom:8,fontFamily:'monospace',minHeight:44}}>
        {display || '0'}
      </div>
      <div style={{display:'grid',gridTemplateColumns:'repeat(4,1fr)',gap:5}}>
        {keys.map(k => {
          const isOp = ['÷','×','−','+'].includes(k);
          const isEq = k === '=';
          const isDel = k === 'C' || k === '⌫';
          return (
            <button key={k} onClick={()=>input(k==='×'?'*':k==='÷'?'/':k==='−'?'-':k)}
              style={{
                padding:'11px 0', borderRadius:8, border:'none', cursor:'pointer', fontFamily:'inherit', fontSize:'0.95rem', fontWeight:700,
                gridColumn: k==='0' ? 'span 2' : undefined,
                background: isEq ? `linear-gradient(135deg,${C.skyDeep},${C.sky})` : isOp ? 'rgba(99,102,241,0.25)' : isDel ? 'rgba(239,68,68,0.18)' : 'rgba(255,255,255,0.07)',
                color: isEq ? '#fff' : isOp ? '#a5b4fc' : isDel ? '#f87171' : C.white
              }}>{k}</button>
          );
        })}
      </div>
      {history.length > 0 && (
        <div style={{marginTop:8,fontSize:'0.72rem',color:C.dim,maxHeight:60,overflowY:'auto'}}>
          {history.map((h,i) => <div key={i}>{h}</div>)}
        </div>
      )}
    </div>
  );
}

function TandraPassGen() {
  const [len, setLen] = useState(16);
  const [upper, setUpper] = useState(true);
  const [lower, setLower] = useState(true);
  const [nums, setNums] = useState(true);
  const [syms, setSyms] = useState(true);
  const [pass, setPass] = useState('');
  const generate = () => {
    let chars = '';
    if (upper) chars += 'ABCDEFGHIJKLMNOPQRSTUVWXYZ';
    if (lower) chars += 'abcdefghijklmnopqrstuvwxyz';
    if (nums) chars += '0123456789';
    if (syms) chars += '!@#$%^&*()_+-=[]{}|;:,.<>?';
    if (!chars) return;
    let p = ''; for (let i=0;i<len;i++) p += chars[Math.floor(Math.random()*chars.length)];
    setPass(p);
  };
  return (
    <div style={{padding:'10px 0'}}>
      <div style={{marginBottom:8}}><label style={{fontSize:'0.78rem',color:C.dim}}>দৈর্ঘ্য: <b style={{color:C.white}}>{len}</b></label><input type="range" min={8} max={64} value={len} onChange={e=>setLen(+e.target.value)} style={{width:'100%',marginTop:4}}/></div>
      <div style={{display:'grid',gridTemplateColumns:'1fr 1fr',gap:6,marginBottom:10}}>
        {[['upper','A-Z বড়',upper,setUpper],['lower','a-z ছোট',lower,setLower],['nums','0-9 সংখ্যা',nums,setNums],['syms','!@# চিহ্ন',syms,setSyms]].map(([k,l,v,s])=>(
          <label key={k} style={{fontSize:'0.78rem',color:C.dim,display:'flex',alignItems:'center',gap:4}}><input type="checkbox" checked={v} onChange={e=>s(e.target.checked)}/>{l}</label>
        ))}
      </div>
      <button onClick={generate} style={{width:'100%',padding:'8px',borderRadius:8,background:'linear-gradient(135deg,#dc2626,#9333ea)',border:'none',color:'#fff',fontWeight:700,cursor:'pointer',fontSize:'0.82rem',marginBottom:8}}>🔐 পাসওয়ার্ড তৈরি</button>
      {pass && (
        <div style={{background:'rgba(255,255,255,0.06)',border:`1px solid ${C.border}`,borderRadius:8,padding:'10px 12px',fontFamily:'monospace',fontSize:'0.9rem',color:'#4ade80',wordBreak:'break-all',display:'flex',justifyContent:'space-between',alignItems:'center',gap:8}}>
          <span>{pass}</span>
          <button onClick={()=>navigator.clipboard?.writeText(pass)} style={{background:'none',border:'none',color:C.sky,cursor:'pointer',fontSize:'0.75rem',flexShrink:0}}>📋 কপি</button>
        </div>
      )}
    </div>
  );
}

function TandraQRGen() {
  const [text, setText] = useState('');
  const [qrUrl, setQrUrl] = useState('');
  const generate = () => {
    if (!text.trim()) return;
    setQrUrl(`https://api.qrserver.com/v1/create-qr-code/?size=200x200&data=${encodeURIComponent(text)}`);
  };
  return (
    <div style={{padding:'10px 0'}}>
      <textarea value={text} onChange={e=>setText(e.target.value)} placeholder="টেক্সট, লিংক, ফোন নম্বর..."
        style={{width:'100%',height:70,padding:'8px',borderRadius:8,border:`1px solid ${C.border}`,background:'rgba(20,30,80,0.7)',color:C.white,fontSize:'0.82rem',resize:'none',boxSizing:'border-box',marginBottom:8,fontFamily:'inherit'}} />
      <button onClick={generate} style={{width:'100%',padding:'8px',borderRadius:8,background:`linear-gradient(135deg,${C.skyDeep},#0d9488)`,border:'none',color:'#fff',fontWeight:700,cursor:'pointer',fontSize:'0.82rem'}}>📷 QR তৈরি করুন</button>
      {qrUrl && <div style={{marginTop:12,textAlign:'center'}}><img src={qrUrl} alt="QR" style={{borderRadius:8,border:`1px solid ${C.border}`}} /><br/><a href={qrUrl} download="qr.png" style={{color:C.sky,fontSize:'0.75rem',marginTop:6,display:'inline-block'}}>⬇ ডাউনলোড</a></div>}
    </div>
  );
}

function TandraUnitConverter() {
  const UNITS = {
    length:  {label:'📏 দৈর্ঘ্য', opts:['meter','kilometer','centimeter','inch','foot','mile']},
    weight:  {label:'⚖️ ওজন',    opts:['kg','gram','pound','ounce','ton']},
    temp:    {label:'🌡️ তাপমাত্রা',opts:['Celsius','Fahrenheit','Kelvin']},
    data:    {label:'💾 ডেটা',   opts:['Byte','KB','MB','GB','TB']},
    speed:   {label:'🚀 গতি',    opts:['m/s','km/h','mph','knot']},
  };
  const [type, setType] = useState('length');
  const [from, setFrom] = useState('meter');
  const [to, setTo] = useState('kilometer');
  const [val, setVal] = useState('1');
  const [result, setResult] = useState('');

  const convert = () => {
    const v = parseFloat(val);
    if (isNaN(v)) return;
    let base; // convert to base unit first
    const toBase = {
      meter:1, kilometer:1000, centimeter:0.01, inch:0.0254, foot:0.3048, mile:1609.34,
      kg:1, gram:0.001, pound:0.453592, ounce:0.0283495, ton:1000,
      Byte:1, KB:1024, MB:1048576, GB:1073741824, TB:1099511627776,
      'm/s':1, 'km/h':0.277778, mph:0.44704, knot:0.514444,
    };
    if (type === 'temp') {
      let c;
      if (from==='Celsius') c=v; else if (from==='Fahrenheit') c=(v-32)*5/9; else c=v-273.15;
      let r;
      if (to==='Celsius') r=c; else if (to==='Fahrenheit') r=c*9/5+32; else r=c+273.15;
      setResult(`${v} ${from} = **${r.toFixed(4)} ${to}**`);
    } else {
      const inBase = v * (toBase[from]||1);
      const r = inBase / (toBase[to]||1);
      setResult(`${v} ${from} = **${r.toFixed(6)} ${to}**`);
    }
  };

  const opts = UNITS[type]?.opts || [];
  return (
    <div style={{padding:'10px 0'}}>
      <select value={type} onChange={e=>{setType(e.target.value);setFrom(UNITS[e.target.value].opts[0]);setTo(UNITS[e.target.value].opts[1]);setResult('');}}
        style={{width:'100%',padding:'8px',borderRadius:8,border:`1px solid ${C.border}`,background:'rgba(20,30,80,0.9)',color:C.white,fontSize:'0.82rem',marginBottom:8}}>
        {Object.entries(UNITS).map(([k,v])=><option key={k} value={k}>{v.label}</option>)}
      </select>
      <div style={{display:'flex',gap:6,marginBottom:8}}>
        <input type="number" value={val} onChange={e=>setVal(e.target.value)} style={{flex:1,padding:'8px',borderRadius:8,border:`1px solid ${C.border}`,background:'rgba(20,30,80,0.7)',color:C.white,fontSize:'0.82rem'}}/>
        <select value={from} onChange={e=>setFrom(e.target.value)} style={{flex:1,padding:'8px',borderRadius:8,border:`1px solid ${C.border}`,background:'rgba(20,30,80,0.9)',color:C.white,fontSize:'0.78rem'}}>
          {opts.map(o=><option key={o}>{o}</option>)}
        </select>
        <span style={{color:C.dim,alignSelf:'center'}}>→</span>
        <select value={to} onChange={e=>setTo(e.target.value)} style={{flex:1,padding:'8px',borderRadius:8,border:`1px solid ${C.border}`,background:'rgba(20,30,80,0.9)',color:C.white,fontSize:'0.78rem'}}>
          {opts.map(o=><option key={o}>{o}</option>)}
        </select>
      </div>
      <button onClick={convert} style={{width:'100%',padding:'8px',borderRadius:8,background:`linear-gradient(135deg,#7c3aed,${C.skyDeep})`,border:'none',color:'#fff',fontWeight:700,cursor:'pointer',fontSize:'0.82rem',marginBottom:8}}>📐 রূপান্তর করুন</button>
      {result && <div style={{textAlign:'center',fontSize:'1rem',color:'#4ade80',fontWeight:700}}>{result.replace(/\*\*/g,'')}</div>}
    </div>
  );
}

// ══ Welcome message — হুবুহু HTML toggleTandra() থেকে (bn/en দুটোই) ══

function TechGuide() {
  const [search,setSearch]=useState("");
  const [activeCat,setActiveCat]=useState("all");
  const [openId,setOpenId]=useState(null);
  const [openSubId,setOpenSubId]=useState(null);
  const sc=useResponsive(); const isMob=sc==="mobile";

  const filtered=GUIDES.filter(g=>{
    const matchCat=activeCat==="all"||g.cat===activeCat;
    const q=search.toLowerCase();
    const matchQ=!q||g.name.toLowerCase().includes(q)||g.short.toLowerCase().includes(q)||(g.desc||"").toLowerCase().includes(q);
    return matchCat&&matchQ;
  });
  const catCount=(id)=>GUIDES.filter(g=>g.cat===id).length;

  return (
    <PageWrap style={{maxWidth:"100%",padding:0}}>
      <div style={{background:"linear-gradient(135deg,#060e1c 0%,#0a1630 60%,#060e1c 100%)",padding:isMob?"20px 16px 18px":"40px 5% 32px",borderBottom:`1px solid ${C.border}`}}>
        <div style={{maxWidth:960,margin:"0 auto"}}>
          <div style={{display:"flex",alignItems:"center",gap:14,marginBottom:10}}>
            <img src={LOGO} alt="Logo" onError={e=>{e.target.src=LOGO_FALLBACK;}} style={{width:isMob?40:52,height:isMob?40:52,borderRadius:12,objectFit:"contain"}}/>
            <div>
              <div style={{fontSize:"0.68rem",fontWeight:700,color:C.sky,letterSpacing:"2px",textTransform:"uppercase",marginBottom:4}}>প্রযুক্তি সহায়তা কেন্দ্র</div>
              <h2 style={{fontSize:isMob?"1.2rem":"1.8rem",fontWeight:800,color:C.white,margin:0}}>প্রযুক্তিপুঞ্জ</h2>
              <p style={{fontSize:"0.76rem",color:C.silver,margin:"4px 0 0"}}>কম্পিউটার সমস্যা সমাধান · সফটওয়্যার ইনস্টলেশন · ভিডিও টিউটোরিয়াল সহ</p>
            </div>
          </div>
          <div style={{display:"inline-flex",alignItems:"center",gap:6,background:"rgba(52,211,153,0.08)",border:"1px solid rgba(52,211,153,0.2)",borderRadius:20,padding:"5px 14px",fontSize:"0.74rem",fontWeight:700,color:"#34d399"}}>
            📋 {GUIDES.length}টি গাইড · {CATS.length}টি ক্যাটাগরি
          </div>
        </div>
      </div>
      <div style={{display:isMob?"block":"flex",maxWidth:1200,margin:"0 auto",padding:isMob?"10px 0 0":"20px 20px 0"}}>
        <aside style={{width:isMob?"100%":220,flexShrink:0,marginRight:isMob?0:20,marginBottom:isMob?10:0}}>
          <div style={{padding:isMob?"0 12px":"0"}}>
            <input value={search} onChange={e=>setSearch(e.target.value)} placeholder="🔍 সফটওয়্যার বা সমস্যার নাম লিখুন…" style={{width:"100%",background:"rgba(255,255,255,0.05)",border:`1px solid ${C.border}`,color:C.white,borderRadius:8,padding:"8px 12px",fontFamily:"inherit",fontSize:"0.82rem",outline:"none",boxSizing:"border-box",marginBottom:8}}/>
            <div style={{maxHeight:isMob?140:580,overflowY:"auto",display:"flex",flexWrap:isMob?"wrap":"nowrap",flexDirection:isMob?"row":"column",gap:4}}>
              <button onClick={()=>setActiveCat("all")} style={{background:activeCat==="all"?`${C.sky}20`:"transparent",border:`1px solid ${activeCat==="all"?C.sky:C.border}`,color:activeCat==="all"?C.sky:C.silver,borderRadius:7,padding:"5px 10px",fontSize:"0.74rem",cursor:"pointer",fontFamily:"inherit",whiteSpace:"nowrap"}}>📋 সব ({GUIDES.length})</button>
              {CATS.filter(cat=>catCount(cat.id)>0).map(cat=>(
                <button key={cat.id} onClick={()=>setActiveCat(cat.id)} style={{background:activeCat===cat.id?`${C.sky}20`:"transparent",border:`1px solid ${activeCat===cat.id?C.sky:C.border}`,color:activeCat===cat.id?C.sky:C.silver,borderRadius:7,padding:"5px 10px",fontSize:"0.74rem",cursor:"pointer",fontFamily:"inherit",whiteSpace:"nowrap"}}>{cat.icon} {cat.name} ({catCount(cat.id)})</button>
              ))}
            </div>
          </div>
        </aside>
        <main style={{flex:1,padding:isMob?"0 12px 20px":"0 0 20px",minWidth:0}}>
          <div style={{fontSize:"0.74rem",color:C.dim,marginBottom:10,fontWeight:600}}>{search||activeCat!=="all"?`${filtered.length}টি ফলাফল`:`মোট ${GUIDES.length}টি গাইড`}</div>
          <div style={{display:"flex",flexDirection:"column",gap:7}}>
            {filtered.map(g=>{
              const isOpen=openId===g.id;
              const ytUrl=g.ytq?`https://www.youtube.com/results?search_query=${encodeURIComponent(g.ytq)}`:"";
              return (
                <div key={g.id} style={{background:C.card,border:`1px solid ${isOpen?C.sky+"40":C.border}`,borderRadius:11,overflow:"hidden"}}>
                  <button onClick={()=>setOpenId(isOpen?null:g.id)} style={{width:"100%",background:"none",border:"none",color:"inherit",cursor:"pointer",fontFamily:"inherit",padding:"11px 13px",display:"flex",alignItems:"center",gap:11,textAlign:"left"}}>
                    <span style={{fontSize:"1.3rem",flexShrink:0}}>{g.icon}</span>
                    <div style={{flex:1,minWidth:0}}>
                      <div style={{fontWeight:700,fontSize:"0.88rem",marginBottom:1,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{g.name}</div>
                      <div style={{fontSize:"0.7rem",color:C.silver,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{g.short}</div>
                    </div>
                    <div style={{display:"flex",gap:5,flexShrink:0,alignItems:"center"}}>
                      <span style={{background:g.price==="free"?`${C.green}15`:g.price==="paid"?`${C.red}12`:`${C.sky}12`,border:`1px solid ${g.price==="free"?C.green+"30":g.price==="paid"?C.red+"25":C.sky+"25"}`,color:g.price==="free"?C.green:g.price==="paid"?C.red:C.sky,borderRadius:5,padding:"2px 7px",fontSize:"0.62rem",fontWeight:700}}>{g.price==="free"?"FREE":g.price==="paid"?"PAID":"GUIDE"}</span>
                      <span style={{color:C.dim,fontSize:"0.85rem"}}>{isOpen?"▲":"▼"}</span>
                    </div>
                  </button>
                  {isOpen&&(
                    <div style={{padding:"0 13px 13px",borderTop:`1px solid ${C.border}`}}>
                      <p style={{fontSize:"0.8rem",color:C.silver,lineHeight:1.8,marginTop:10,marginBottom:10}}>{g.desc}</p>
                      {g.steps&&g.steps.length>0&&(
                        <div style={{marginBottom:10}}>
                          <div style={{fontSize:"0.68rem",fontWeight:700,color:C.dim,letterSpacing:"1px",marginBottom:7,textTransform:"uppercase"}}>Step-by-step গাইড</div>
                          {g.steps.map(step=>(
                            <div key={step.num} style={{display:"flex",gap:9,marginBottom:7}}>
                              <div style={{width:21,height:21,borderRadius:"50%",background:`linear-gradient(135deg,${C.skyDeep},${C.sky})`,display:"flex",alignItems:"center",justifyContent:"center",fontSize:"0.65rem",fontWeight:700,color:"#fff",flexShrink:0,marginTop:1}}>{step.num}</div>
                              <div style={{flex:1}}>
                                <div style={{fontWeight:700,fontSize:"0.78rem",marginBottom:1}}>{step.title}</div>
                                <div style={{fontSize:"0.76rem",color:C.silver,lineHeight:1.7}}>{step.content}</div>
                                {step.dl&&<a href={step.dl.url} target="_blank" rel="noopener" style={{display:"inline-flex",alignItems:"center",gap:5,marginTop:4,background:`${C.sky}10`,border:`1px solid ${C.sky}25`,color:C.sky,borderRadius:6,padding:"3px 9px",fontSize:"0.7rem",fontWeight:600,textDecoration:"none"}}>{step.dl.text}</a>}
                                {step.extraDls&&step.extraDls.length>0&&<div style={{display:"flex",flexDirection:"column",gap:5,marginTop:6}}>{step.extraDls.map((d,di)=><a key={di} href={d.url} target="_blank" rel="noopener" style={{display:"inline-flex",alignItems:"center",gap:5,background:`${C.sky}10`,border:`1px solid ${C.sky}25`,color:C.sky,borderRadius:6,padding:"4px 10px",fontSize:"0.7rem",fontWeight:600,textDecoration:"none"}}>{d.text}</a>)}</div>}
                                {step.subMethods&&step.subMethods.length>0&&(
                                  <div style={{marginTop:8,display:"flex",flexDirection:"column",gap:6}}>
                                    {step.subMethods.map(mid=>{
                                      const sg=GUIDES.find(x=>x.id===mid);
                                      if(!sg) return null;
                                      const isSubOpen=openSubId===(`${g.id}-${mid}`);
                                      const sgYt=sg.ytq?`https://www.youtube.com/results?search_query=${encodeURIComponent(sg.ytq)}`:"";
                                      return (
                                        <div key={mid} style={{border:`1px solid ${isSubOpen?C.sky+"50":C.border}`,borderRadius:8,overflow:"hidden",background:isSubOpen?`${C.sky}06`:"rgba(255,255,255,0.02)"}}>
                                          <button onClick={()=>setOpenSubId(isSubOpen?null:`${g.id}-${mid}`)} style={{width:"100%",background:"none",border:"none",color:"inherit",cursor:"pointer",fontFamily:"inherit",padding:"8px 11px",display:"flex",alignItems:"center",gap:8,textAlign:"left"}}>
                                            <span style={{fontSize:"1rem",flexShrink:0}}>{sg.icon||'🔧'}</span>
                                            <span style={{flex:1,fontWeight:700,fontSize:"0.78rem",color:isSubOpen?C.sky:C.white}}>{sg.name}</span>
                                            <span style={{color:C.sky,fontSize:"0.72rem",fontWeight:700,border:`1px solid ${C.sky}30`,borderRadius:4,padding:"1px 6px"}}>{isSubOpen?"▲ বন্ধ":"▼ গাইড"}</span>
                                          </button>
                                          {isSubOpen&&(
                                            <div style={{padding:"0 11px 11px",borderTop:`1px solid ${C.border}`}}>
                                              {sg.desc&&<p style={{fontSize:"0.76rem",color:C.silver,lineHeight:1.7,marginTop:8,marginBottom:8}}>{sg.desc}</p>}
                                              {sg.steps&&sg.steps.length>0&&(
                                                <div style={{marginBottom:8}}>
                                                  {sg.steps.map(sst=>(
                                                    <div key={sst.num} style={{display:"flex",gap:8,marginBottom:6}}>
                                                      <div style={{width:19,height:19,borderRadius:"50%",background:`linear-gradient(135deg,${C.skyDeep},${C.sky})`,display:"flex",alignItems:"center",justifyContent:"center",fontSize:"0.6rem",fontWeight:700,color:"#fff",flexShrink:0,marginTop:2}}>{sst.num}</div>
                                                      <div style={{flex:1}}>
                                                        <div style={{fontWeight:700,fontSize:"0.75rem",marginBottom:1}}>{sst.title}</div>
                                                        {sst.content&&<div style={{fontSize:"0.73rem",color:C.silver,lineHeight:1.65}} dangerouslySetInnerHTML={{__html:sst.content}}/>}
                                                        {sst.dl&&<a href={sst.dl.url} target="_blank" rel="noopener" style={{display:"inline-flex",alignItems:"center",gap:4,marginTop:4,background:`${C.sky}10`,border:`1px solid ${C.sky}25`,color:C.sky,borderRadius:5,padding:"3px 8px",fontSize:"0.68rem",fontWeight:600,textDecoration:"none"}}>{sst.dl.text}</a>}
                                                        {sst.extraDls&&sst.extraDls.length>0&&<div style={{display:"flex",flexDirection:"column",gap:4,marginTop:5}}>{sst.extraDls.map((d,di)=><a key={di} href={d.url} target="_blank" rel="noopener" style={{display:"inline-flex",alignItems:"center",gap:4,background:`${C.sky}10`,border:`1px solid ${C.sky}25`,color:C.sky,borderRadius:5,padding:"3px 8px",fontSize:"0.68rem",fontWeight:600,textDecoration:"none"}}>{d.text}</a>)}</div>}
                                                      </div>
                                                    </div>
                                                  ))}
                                                </div>
                                              )}
                                              {sg.warnings&&sg.warnings.length>0&&(
                                                <div style={{background:`${C.amber}08`,border:`1px solid ${C.amber}20`,borderRadius:6,padding:"7px 9px",marginBottom:7}}>
                                                  <div style={{fontSize:"0.65rem",fontWeight:700,color:C.amber,marginBottom:4}}>⚠️ সতর্কতা</div>
                                                  {sg.warnings.map((w,wi)=><div key={wi} style={{fontSize:"0.72rem",color:C.silver,lineHeight:1.6}} dangerouslySetInnerHTML={{__html:`• ${w}`}}/>)}
                                                </div>
                                              )}
                                              {sgYt&&<a href={sgYt} target="_blank" rel="noopener" onClick={e=>{e.preventDefault();window.open(sgYt,'_blank');}} style={{display:"inline-flex",alignItems:"center",gap:5,background:"rgba(255,0,0,0.1)",border:"1px solid rgba(255,0,0,0.25)",color:"#ff4444",borderRadius:6,padding:"5px 10px",fontSize:"0.7rem",fontWeight:700,textDecoration:"none"}}>▶ YouTube বাংলা টিউটোরিয়াল দেখুন</a>}
                                            </div>
                                          )}
                                        </div>
                                      );
                                    })}
                                  </div>
                                )}
                              </div>
                            </div>
                          ))}
                        </div>
                      )}
                      {g.warnings&&g.warnings.length>0&&(
                        <div style={{background:`${C.amber}08`,border:`1px solid ${C.amber}20`,borderRadius:8,padding:"9px 11px",marginBottom:9}}>
                          <div style={{fontSize:"0.68rem",fontWeight:700,color:C.amber,marginBottom:5}}>⚠️ সতর্কতা</div>
                          {g.warnings.map((w,i)=><div key={i} style={{fontSize:"0.76rem",color:C.silver,lineHeight:1.7}}>• {w}</div>)}
                        </div>
                      )}
                      {ytUrl&&<a href={ytUrl} target="_blank" rel="noopener" onClick={e=>{e.preventDefault();window.open(ytUrl,'_blank');}} style={{display:"inline-flex",alignItems:"center",gap:6,background:"rgba(255,0,0,0.1)",border:"1px solid rgba(255,0,0,0.25)",color:"#ff4444",borderRadius:7,padding:"6px 12px",fontSize:"0.74rem",fontWeight:700,textDecoration:"none"}}>▶ YouTube Video Tutorial খুঁজুন</a>}
                    </div>
                  )}
                </div>
              );
            })}
            {filtered.length===0&&<div style={{padding:40,textAlign:"center",color:C.dim}}>কোনো গাইড পাওয়া যায়নি।</div>}
          </div>
        </main>
      </div>
    </PageWrap>
  );
}

/* ════════════════════════════════════════════════════════════════
   NOTIFICATIONS PAGE — User sees payment/earn/redeem updates
   ════════════════════════════════════════════════════════════════ */
function NotificationsPage({user, onOpen}) {
  const [notifs, setNotifs] = useState([]);
  const [loading, setLoading] = useState(true);
  // load deleted keys from localStorage on mount
  _initPpCache();

  const safeUid = (id) => (id||"").replace(/[.#$[\]]/g,"_");

  // Reset badge count when page opens
  useEffect(()=>{ if(onOpen) onOpen(); },[]);

  const load = async () => {
    if(!user?.id) return;
    const demoList = (DEMO_NOTIFICATIONS[user.id] || [])
      .filter(d => !window._ppDeletedDemoNotifs.has(d._key));
    const demoKeys = new Set(demoList.map(d=>d._key));
    const data = await fbGet(`notifications/${safeUid(user.id)}`);
    let fbList = [];
    if(data){
      fbList = Object.entries(data).map(([k,v])=>({...v, _key:k}))
        .filter(n=>!demoKeys.has(n._key) && !window._ppDeletedFbNotifs.has(n._key));
    }
    const merged = [...fbList, ...demoList].sort((a,b)=>b.createdAt-a.createdAt);
    setNotifs(merged);
    setLoading(false);
  };

  useEffect(()=>{ load(); const i=setInterval(load,8000); return()=>clearInterval(i); },[user?.id]);

  const markAllRead = async () => {
    if(!user?.id) return;
    const unread = notifs.filter(n=>!n.read&&!n.isDemo);
    for(const n of unread){
      await fbPatch(`notifications/${safeUid(user.id)}/${n._key}`, {read:true});
    }
    setNotifs(prev=>prev.map(n=>({...n,read:true})));
  };

  const deleteNotif = async (key, isDemoNotif) => {
    // Immediately remove from UI
    setNotifs(prev=>prev.filter(n=>n._key!==key));
    if(isDemoNotif){
      // Demo notification — just track in localStorage
      ppAddDeletedDemoNotif(key);
    } else {
      // Firebase notification — track in localStorage AND delete from Firebase
      ppAddDeletedFbNotif(key);
      // Try delete, retry once if fails
      try {
        await fbDelete(`notifications/${safeUid(user.id)}/${key}`);
      } catch(e) {
        setTimeout(()=>{ fbDelete(`notifications/${safeUid(user.id)}/${key}`); }, 1000);
      }
    }
  };

  const unreadCount = notifs.filter(n=>!n.read).length;
  const [deleteNotifTarget, setDeleteNotifTarget] = useState(null);
  const [confirmDeleteAll, setConfirmDeleteAll] = useState(false);

  const markRead = async (key, isDemo) => {
    if(!isDemo) await fbPatch(`notifications/${safeUid(user.id)}/${key}`, {read:true});
    setNotifs(prev=>prev.map(n=>n._key===key?{...n,read:true}:n));
  };

  return (
    <PageWrap>
      <SectionHeader eye="NOTIFICATIONS" title="আপনার নোটিফিকেশন" sub={`${notifs.length} টি মোট — ${unreadCount} টি অপঠিত`}/>
      <div style={{display:"flex",gap:10,marginBottom:18,alignItems:"center",flexWrap:"wrap"}}>
        {unreadCount>0&&(
          <button onClick={markAllRead} style={{background:`${C.sky}15`,border:`1px solid ${C.sky}30`,color:C.sky,borderRadius:8,padding:"7px 14px",cursor:"pointer",fontFamily:"inherit",fontSize:"0.8rem"}}>✅ সব পড়া হিসেবে চিহ্নিত করুন</button>
        )}
        {notifs.length>0&&(
          <button onClick={()=>setConfirmDeleteAll(true)} style={{background:`${C.red}12`,border:`1px solid ${C.red}25`,color:C.red,borderRadius:8,padding:"7px 14px",cursor:"pointer",fontFamily:"inherit",fontSize:"0.8rem"}}>🗑 সব মুছুন</button>
        )}
        <button onClick={load} style={{background:"rgba(255,255,255,0.05)",border:`1px solid ${C.border}`,color:C.silver,borderRadius:8,padding:"7px 14px",cursor:"pointer",fontFamily:"inherit",fontSize:"0.8rem",marginLeft:"auto"}}>🔄</button>
      </div>

      {loading&&<div style={{color:C.dim,textAlign:"center",padding:40}}>লোড হচ্ছে...</div>}
      {!loading&&notifs.length===0&&(
        <div style={{textAlign:"center",padding:"50px 20px"}}>
          <div style={{fontSize:"2.5rem",marginBottom:10}}>🔔</div>
          <div style={{color:C.dim}}>কোনো নোটিফিকেশন নেই।</div>
        </div>
      )}

      {notifs.map(n=>(
        <div key={n._key} onClick={()=>!n.read&&markRead(n._key, n.isDemo)}
          style={{background:n.read?C.card:`${n.color||C.sky}08`,border:`1px solid ${n.read?C.border:(n.color||C.sky)+"40"}`,borderRadius:12,padding:"14px 16px",marginBottom:10,cursor:n.read?"default":"pointer",display:"flex",gap:12,alignItems:"flex-start",transition:"all 0.2s"}}>
          <div style={{width:42,height:42,borderRadius:12,background:`${n.color||C.sky}18`,display:"flex",alignItems:"center",justifyContent:"center",fontSize:"1.3rem",flexShrink:0}}>{n.icon||"🔔"}</div>
          <div style={{flex:1,minWidth:0}}>
            <div style={{display:"flex",alignItems:"center",gap:8,marginBottom:4}}>
              <div style={{fontWeight:700,fontSize:"0.88rem",color:n.read?C.silver:C.white}}>{n.title}</div>
              {!n.read&&<div style={{width:8,height:8,borderRadius:99,background:n.color||C.sky,flexShrink:0}}/>}
            </div>
            <div style={{fontSize:"0.78rem",color:C.dim,lineHeight:1.6}}>{n.body}</div>
            <div style={{fontSize:"0.65rem",color:C.dim,marginTop:6}}>{n.date||""} • {new Date(n.createdAt||Date.now()).toLocaleTimeString("bn-BD",{hour:"2-digit",minute:"2-digit"})}</div>
          </div>
          <button onClick={e=>{e.stopPropagation();setDeleteNotifTarget(n);}} style={{background:`${C.red}10`,border:`1px solid ${C.red}25`,color:C.red,cursor:"pointer",fontSize:"0.85rem",padding:"4px 8px",flexShrink:0,borderRadius:8,opacity:0.85}}>🗑</button>
        </div>
      ))}
      <ConfirmDeleteModal
        open={!!deleteNotifTarget}
        message={`"${deleteNotifTarget?.title||"এই নোটিফিকেশন"}" মুছে ফেলবেন?`}
        onConfirm={()=>{ deleteNotif(deleteNotifTarget._key, deleteNotifTarget.isDemo); setDeleteNotifTarget(null); }}
        onCancel={()=>setDeleteNotifTarget(null)}
      />
      <ConfirmDeleteModal
        open={confirmDeleteAll}
        message={`সব ${notifs.length} টি নোটিফিকেশন পার্মানেন্টলি মুছে ফেলবেন?`}
        onConfirm={async()=>{
          for(const n of notifs){
            if(n.isDemo){ ppAddDeletedDemoNotif(n._key); }
            else { ppAddDeletedFbNotif(n._key); fbDelete(`notifications/${safeUid(user.id)}/${n._key}`); }
          }
          setNotifs([]);
          setConfirmDeleteAll(false);
        }}
        onCancel={()=>setConfirmDeleteAll(false)}
      />
    </PageWrap>
  );
}
function useSiteMeta(){
  useEffect(()=>{
    const SITE_NAME = "প্রযুক্তিপুঞ্জ — ProjuktiPunjo Management System";
    const DESC = "প্রযুক্তিপুঞ্জ (ProjuktiPunjo) — Chandraganj, Lakshmipur-এ অবস্থিত কম্পিউটার প্রশিক্ষণ কেন্দ্র। বেসিক কম্পিউটার, MS Office, গ্রাফিক ডিজাইন, ডিজিটাল মার্কেটিং, ওয়েব ডিজাইন ও আরও অনেক কোর্স — অনলাইন ছাত্র/ক্লায়েন্ট ম্যানেজমেন্ট, পেমেন্ট, পয়েন্ট ওয়ালেট ও AI সহকারী তন্দ্রা-হরণী সহ।";
    const KEYWORDS = "প্রযুক্তিপুঞ্জ, ProjuktiPunjo, Computer Training Center, Chandraganj, Lakshmipur, Bangladesh, MS Office Course, Graphic Design, Digital Marketing, Web Design, Freelancing, কম্পিউটার প্রশিক্ষণ, কোর্স";
    const LOGO_URL = "https://i.ibb.co/gbsTT0ZQ/1000091904-removebg-preview.png";
    const THEME_COLOR = "#0a1628";

    // ── <title> ──
    if(document.title !== SITE_NAME) document.title = SITE_NAME;

    // ── helper: upsert meta by name/property ──
    const setMeta = (attr, key, content) => {
      let el = document.head.querySelector(`meta[${attr}="${key}"]`);
      if(!el){ el = document.createElement("meta"); el.setAttribute(attr, key); document.head.appendChild(el); }
      el.setAttribute("content", content);
    };
    const setLink = (rel, href, extra={}) => {
      let el = document.head.querySelector(`link[rel="${rel}"]${extra.sizes?`[sizes="${extra.sizes}"]`:""}`);
      if(!el){ el = document.createElement("link"); el.setAttribute("rel", rel); document.head.appendChild(el); }
      el.setAttribute("href", href);
      Object.entries(extra).forEach(([k,v])=>el.setAttribute(k,v));
    };

    // ── Basic SEO ──
    setMeta("name","description",DESC);
    setMeta("name","keywords",KEYWORDS);
    setMeta("name","author","প্রযুক্তিপুঞ্জ (ProjuktiPunjo)");
    setMeta("name","robots","index, follow");
    setMeta("name","viewport","width=device-width, initial-scale=1, maximum-scale=1, user-scalable=no, viewport-fit=cover");
    setMeta("name","theme-color",THEME_COLOR);

    // ── Open Graph ──
    setMeta("property","og:title",SITE_NAME);
    setMeta("property","og:description",DESC);
    setMeta("property","og:type","website");
    setMeta("property","og:image",LOGO_URL);
    setMeta("property","og:locale","bn_BD");
    setMeta("property","og:site_name","প্রযুক্তিপুঞ্জ");

    // ── Twitter Card ──
    setMeta("name","twitter:card","summary_large_image");
    setMeta("name","twitter:title",SITE_NAME);
    setMeta("name","twitter:description",DESC);
    setMeta("name","twitter:image",LOGO_URL);

    // ── Favicons / Apple touch icon ──
    setLink("icon",LOGO_URL);
    setLink("apple-touch-icon",LOGO_URL,{sizes:"180x180"});

    // ── PWA Manifest (inline data URI — no separate file needed) ──
    try{
      const manifest = {
        name: SITE_NAME,
        short_name: "প্রযুক্তিপুঞ্জ",
        description: DESC,
        start_url: ".",
        display: "standalone",
        background_color: THEME_COLOR,
        theme_color: THEME_COLOR,
        orientation: "portrait-primary",
        icons: [
          { src: LOGO_URL, sizes: "192x192", type: "image/png", purpose: "any maskable" },
          { src: LOGO_URL, sizes: "512x512", type: "image/png", purpose: "any maskable" }
        ]
      };
      const blob = new Blob([JSON.stringify(manifest)], {type:"application/json"});
      const manifestURL = URL.createObjectURL(blob);
      setLink("manifest", manifestURL);
    }catch(e){ /* manifest injection best-effort, never block app */ }
  },[]);
}

export default function App() {
  useSiteMeta();
  const [screen,setScreen]=useState("splash");
  const [user,setUser]=useState(null);
  const [page,setPage]=useState("dashboard");
  const [students,setStudents]=useState(DEMO_STUDENTS);
  const [payments,setPayments]=useState(DEMO_PAYMENTS);
  const [ptReqs,setPtReqs]=useState(DEMO_POINT_REQUESTS);
  const [localPtReqs,setLocalPtReqs]=useState([]);
  const [users,setUsers]=useState(DEMO_USERS);
  const [showContact,setShowContact]=useState(false);
  const [notifCount,setNotifCount]=useState(0);
  const sc=useResponsive();
  const isMob=sc==="mobile"||sc==="tablet";

  // ── Load user notifications count every 10s ──
  useEffect(()=>{
    if(!user?.id) return;
    const safeUid=(id)=>(id||"").replace(/[.#$[\]]/g,"_");
    const loadNotifs=async()=>{
      _initPpCache();
      const demoList = (DEMO_NOTIFICATIONS[user.id] || [])
        .filter(n=>!window._ppDeletedDemoNotifs.has(n._key));
      const demoUnread = demoList.filter(n=>!n.read).length;
      const data=await fbGet(`notifications/${safeUid(user.id)}`);
      let fbUnread=0;
      if(data){
        const demoKeys=new Set(demoList.map(d=>d._key));
        fbUnread=Object.entries(data).filter(([k,n])=>!n.read&&!demoKeys.has(k)&&!window._ppDeletedFbNotifs.has(k)).length;
      }
      setNotifCount(demoUnread+fbUnread);
    };
    loadNotifs();
    const i=setInterval(loadNotifs,10000);
    return()=>clearInterval(i);
  },[user?.id]);

  // ── Seed demo data into Firebase once, then load everything from Firebase ──
  useEffect(()=>{
    _initPpCache();
    const seedAndLoad = async () => {
      // ── PAYMENTS: seed demo payments into Firebase if not already there ──
      _initPpCache();
      const existingPay = await fbGet("payments");
      const existingPayKeys = new Set(Object.keys(existingPay || {}));
      for(const dp of DEMO_PAYMENTS){
        const fbKey = "demo_pay_" + dp.id;
        // Only seed if not already in Firebase AND not previously deleted
        if(!existingPayKeys.has(fbKey) && !window._ppDeletedPayKeys.has(fbKey) && !window._ppDeletedPayKeys.has(dp.id)){
          await fbSet(`payments/${fbKey}`, {...dp, firebaseKey:fbKey, createdAt: dp.createdAt || (Date.now() - 30*24*3600*1000)});
        }
      }
      // ── POINT REQUESTS: seed demo ptreqs into Firebase if not already there ──
      const existingPt = await fbGet("pointRequests");
      const existingPtKeys = new Set(Object.keys(existingPt || {}));
      for(const dr of DEMO_POINT_REQUESTS){
        // Only seed if not already in Firebase AND not previously deleted
        if(!existingPtKeys.has(dr._key) && !window._ppDeletedPtReqs.has(dr._key)){
          const {_key, ...rest} = dr;
          await fbSet(`pointRequests/${_key}`, rest);
        }
      }
    };
    seedAndLoad();
  }, []);

  // ── Load payments from Firebase every 10s ──
  useEffect(()=>{
    _initPpCache();
    const load=async()=>{
      const d=await fbGet("payments");
      if(d){
        const arr=Object.entries(d).map(([k,v])=>{
          // Preserve original id if stored (demo payments have id like "TXN001" but key like "demo_pay_TXN001")
          const originalId = v.id || k;
          return {status:"pending",...v, id:originalId, firebaseKey:k};
        })
          .filter(p=>!window._ppDeletedPayKeys.has(p.firebaseKey) && !window._ppDeletedPayKeys.has(p.id));
        setPayments(arr.sort((a,b)=>(b.createdAt||0)-(a.createdAt||0)));
      }
    };
    load();
    const i=setInterval(load,5000);
    const j=setInterval(()=>{ if(window._ppPayDirty){ window._ppPayDirty=false; load(); } },800);
    return()=>{clearInterval(i);clearInterval(j);};
  },[]);

  // ── Load pointRequests from Firebase + Demo merge every 3s ──
  useEffect(()=>{
    const load=async()=>{
      _initPpCache();
      const d=await fbGet("pointRequests");
      const fbArr = d ? Object.entries(d).map(([k,v])=>({...v,_key:k}))
        .filter(r=>!window._ppDeletedPtReqs.has(r._key)) : [];
      // Merge Demo requests with status overrides
      const fbKeys = new Set(fbArr.map(r=>r._key));
      const demoArr = DEMO_POINT_REQUESTS
        .filter(r=>!window._ppDeletedPtReqs.has(r._key)&&!fbKeys.has(r._key))
        .map(r=>{ const ov=window._ppDemoStatus[r._key]; return ov?{...r,...ov}:r; });
      const arr = [...fbArr, ...demoArr];
      setPtReqs(arr.sort((a,b)=>(b.createdAt||0)-(a.createdAt||0)));
    };
    load();
    const i=setInterval(load,3000);
    const j=setInterval(()=>{ if(window._ppPtReqDirty){ window._ppPtReqDirty=false; load(); } },300);
    return()=>{clearInterval(i);clearInterval(j);};
  },[]);

  // ── Load users + pending_registrations from Firebase every 8s ──
  useEffect(()=>{
    const load=async()=>{
      // Load from "users" path (approved/active users saved here)
      const fbUsers=await fbGet("users");
      // Load from "pending_registrations" path (new registrations)
      const fbPending=await fbGet("pending_registrations");
      
      let fbArr=[];
      if(fbUsers){
        const arr=Object.entries(fbUsers).map(([k,v])=>({...v,_fbKey:k}));
        fbArr=[...fbArr,...arr];
      }
      if(fbPending){
        const arr=Object.entries(fbPending).map(([k,v])=>({...v,_fbKey:k}));
        // merge: don't duplicate users already in fbUsers
        const existIds=new Set(fbArr.map(u=>u.userId));
        fbArr=[...fbArr,...arr.filter(u=>!existIds.has(u.userId))];
      }
      
      if(fbArr.length>0){
        // Merge with DEMO — keep demo users, add/update firebase users
        const fbIds=new Set(fbArr.map(u=>u.userId));
        const merged=[...fbArr,...DEMO_USERS.filter(u=>!fbIds.has(u.userId))];
        setUsers(merged);
        // Also update students list from Firebase users
        const fbStudents=merged.filter(u=>u.role===ROLES.STUDENT&&u.status===STATUS.ACTIVE);
        if(fbStudents.length>0){
          const sIds=new Set(fbStudents.map(u=>u.userId));
          const mergedS=[
            ...fbStudents.map(u=>({
              id:u.userId,
              name:u.fullNameEn||u.fullNameBn||"—",
              email:u.email||"",
              phone:u.mobile||"",
              course:u.course||"",
              enrolled:u.regDate||u.approvedAt||"",
              status:u.status||"active",
              paid:u.paid||0,
              balance:u.balance||0,
              points:u.points||0,
              usedPoints:u.usedPoints||0,
              referralId:u.referralId||"",
              referrals:u.referrals||0,
            })),
            ...DEMO_STUDENTS.filter(s=>!sIds.has(s.id))
          ];
          setStudents(mergedS);
        }
      }
    };
    load();
    const i=setInterval(load,8000);
    return()=>clearInterval(i);
  },[]);

  const handleLogin=(role,userData)=>{setUser({...userData,role});setPage(role===ROLES.ADMIN||role===ROLES.CHIEF_ADMIN?"dashboard":"portal");setScreen("app");};
  const handleLogout=()=>{setUser(null);setScreen("login");setPage("dashboard");};

  const isAdmin=user?.role===ROLES.ADMIN||user?.role===ROLES.CHIEF_ADMIN;
  const isChief=user?.isMainAdmin||user?.role===ROLES.CHIEF_ADMIN;

  const [fbPendingCount,setFbPendingCount]=useState(0);
  useEffect(()=>{
    const load=async()=>{
      const d=await fbGet("pending_registrations");
      if(d){ const n=Object.values(d).filter(u=>u.status==="pending"&&(u.role===ROLES.STUDENT||u.role===ROLES.CLIENT)).length; setFbPendingCount(n); }
    };
    load(); const i=setInterval(load,8000); return()=>clearInterval(i);
  },[]);
  const inMemPending=users.filter(u=>!u.isDemo&&u.status===STATUS.PENDING&&(u.role===ROLES.STUDENT||u.role===ROLES.CLIENT)).length;
  const pendingCount=Math.max(inMemPending,fbPendingCount);

  const pendingPayCount=payments.filter(p=>p.status===PAY_STATUS.PENDING||p.status==="pending").length;
  const pendingPtCount = ptReqs.filter(r=>r.status==="pending").length;

  const [pendingProfileCount, setPendingProfileCount] = useState(0);
  useEffect(()=>{
    if(!isAdmin) return;
    const loadProfileCount = async () => {
      const d = await fbGet("profile_update_requests");
      // Merge Firebase + window cache for accurate count
      const merged = {...(window._ppProfileReqs||{})};
      if(d){ Object.entries(d).forEach(([k,v])=>{ merged[k]=v; }); }
      if(d) window._ppProfileReqs = {...merged};
      const cnt = Object.values(merged).filter(r=>r.status==="pending").length;
      setPendingProfileCount(cnt);
    };
    loadProfileCount();
    const i = setInterval(loadProfileCount, 3000);
    const j = setInterval(()=>{ if(window._ppProfileReqDirty){ loadProfileCount(); } },300);
    return () => { clearInterval(i); clearInterval(j); };
  },[isAdmin]);

  const [adminMsgCount,setAdminMsgCount]=useState(0);
  useEffect(()=>{
    if(!isAdmin) return;
    const loadMsgCount=async()=>{
      const data=await fbGet("messages/admin_convs");
      if(data){ const cnt=Object.values(data).filter(c=>c.unread&&c.lastSenderRole!=="admin"&&c.lastSenderRole!=="chief_admin").length; setAdminMsgCount(cnt); }
    };
    loadMsgCount();
    const i=setInterval(loadMsgCount,8000);
    return()=>clearInterval(i);
  },[isAdmin]);

  const ADMIN_NAV=[
    {id:"dashboard",    icon:"📊", label:"Dashboard"},
    {id:"pendingReg",   icon:"🔔", label:"Pending Reg", badge:pendingCount},
    {id:"students",     icon:"👥", label:"Students"},
    {id:"payments",     icon:"💳", label:"Payments", badge:pendingPayCount},
    {id:"adminApprove", icon:"🔐", label:"Admin Approval"},
    {id:"resetApprove", icon:"🔑", label:"Reset Requests"},
    {id:"pointRequests", icon:"🎯", label:"Point Requests", badge:pendingPtCount},
    {id:"profileApprove",icon:"📝", label:"Profile Updates", badge:pendingProfileCount},
    {id:"messages",     icon:"💬", label:"Messages", badge:adminMsgCount},
    ...(isChief ? [{id:"userManage", icon:"🛡️", label:"User Control"}] : []),
    {id:"services",     icon:"🛠️", label:"Services"},
    {id:"courses",      icon:"📚", label:"Courses"},
    {id:"tutorials",    icon:"📺", label:"Tutorials"},
    {id:"ai",           icon:"🤖", label:"AI Assistant"},
    {id:"settings",     icon:"⚙️", label:"Settings"},
  ];
  const STUDENT_NAV=[
    {id:"portal",      icon:"🏠", label:"My Portal"},
    {id:"mycard",      icon:"💎", label:"Elite Pass"},
    {id:"wallet",      icon:"👛", label:"Wallet"},
    {id:"earnPoints",  icon:"🟢", label:"Earn Points"},
    {id:"redeemPoints",icon:"🔴", label:"Redeem Points"},
    {id:"pay",         icon:"💰", label:"Make Payment"},
    {id:"enroll",      icon:"📚", label:"Courses"},
    {id:"svcList",     icon:"🛠️", label:"Services"},
    {id:"notifications",icon:"🔔", label:"Notifications", badge:notifCount},
    {id:"messages",    icon:"💬", label:"Messages"},
    {id:"tutorials",   icon:"📺", label:"Tutorials"},
    {id:"techGuide",   icon:"📋", label:"Tech Guide"},
    {id:"ai",          icon:"🤖", label:"AI Assistant"},
    {id:"profile",     icon:"👤", label:"Profile"},
  ];

  const nav=isAdmin?ADMIN_NAV:STUDENT_NAV;
  const _rawStudent = students.find(s=>s.id===user?.id)
    || users.find(u=>(u.userId===user?.id||u.id===user?.id)&&u.role===ROLES.STUDENT)
    || (user?.role===ROLES.CLIENT ? users.find(u=>u.userId===user?.id||u.id===user?.id) : null);
  const myStudent = _rawStudent ? {
    ..._rawStudent,
    id: _rawStudent.id || _rawStudent.userId || "",
    name: _rawStudent.name || _rawStudent.fullNameEn || _rawStudent.fullNameBn || "",
    points: _rawStudent.points || 0,
    usedPoints: _rawStudent.usedPoints || 0,
    balance: _rawStudent.balance || 0,
    paid: _rawStudent.paid || 0,
    referrals: _rawStudent.referrals || 0,
    status: _rawStudent.status || "active",
  } : (user?.role===ROLES.CLIENT ? {id:user?.id||"",name:user?.name||"",points:0,usedPoints:0,balance:0,paid:0,referrals:0,status:"active"} : students[0]);

  const renderPage=()=>{
    if(isAdmin){
      if(page==="dashboard")    return <AdminDashboard students={students} payments={payments} users={users}/>;
      if(page==="students")     return <StudentManagement students={students} setStudents={setStudents} users={users} setUsers={setUsers} currentUser={user}/>;
      if(page==="payments")     return <PaymentManagement payments={payments} setPayments={setPayments} students={students}/>;
      if(page==="pendingReg")   return <PendingRegistrationsPanel users={users} setUsers={setUsers} currentUser={user}/>;
      if(page==="adminApprove") return <AdminApprovalPanel users={users} setUsers={setUsers}/>;
      if(page==="resetApprove") return <ResetApproval user={user}/>;
      if(page==="profileApprove") return <ProfileUpdateApproval user={user}/>;
      if(page==="messages")     return <MessagingPage user={user} isAdmin={true}/>;
      if(page==="userManage"&&isChief) return <UserManagementPanel users={users} setUsers={setUsers} currentUser={user}/>;
      if(page==="services")     return <ServicesPage/>;
      if(page==="courses")      return <CoursesPage/>;
      if(page==="tutorials")    return <TutorialSystem/>;
      if(page==="ai")           return <AIAssistant setPage={setPage}/>;
      if(page==="settings")     return <Settings/>;
      if(page==="pointRequests") return <PointRequestsPanel students={students} setStudents={setStudents}/>;
    } else {
      if(page==="portal")    return <StudentPortal student={myStudent} payments={payments}/>;
      if(page==="svcList")   return <ServicesPage/>;
      if(page==="mycard")    return <LuxCard student={myStudent}/>;
      if(page==="wallet")    return <Wallet student={myStudent} localPtReqs={localPtReqs} onPtReqSubmit={r=>{setLocalPtReqs(prev=>[r,...prev]);setPtReqs(prev=>{const keys=new Set(prev.map(x=>x._key));return keys.has(r._key)?prev:[r,...prev];});}}/>; 
      if(page==="earnPoints")  return <EarnPointsPage student={myStudent} onSubmit={r=>{setLocalPtReqs(prev=>[r,...prev]);setPtReqs(prev=>{const keys=new Set(prev.map(x=>x._key));return keys.has(r._key)?prev:[r,...prev];});}}/>; 
      if(page==="redeemPoints")return <RedeemPointsPage student={myStudent} onSubmit={r=>{setLocalPtReqs(prev=>[r,...prev]);setPtReqs(prev=>{const keys=new Set(prev.map(x=>x._key));return keys.has(r._key)?prev:[r,...prev];});}}/>;
      if(page==="pay")       return <MakePayment student={myStudent} onSubmit={p=>setPayments(prev=>[p,...prev])}/>;
      if(page==="enroll")    return <EnrollPage setPage={setPage}/>;
      if(page==="messages")  return <MessagingPage user={user} isAdmin={false}/>;
      if(page==="notifications") return <NotificationsPage user={user} onOpen={()=>setNotifCount(0)}/>;
      if(page==="tutorials") return <TutorialSystem/>;
      if(page==="ai")        return <AIAssistant setPage={setPage}/>;
      if(page==="techGuide") return <TechGuide/>;
      if(page==="profile")   return <Profile user={user}/>;
    }
    return null;
  };

  return (
    <>
      <style>{`*{box-sizing:border-box;margin:0;padding:0}body{background:${C.bg};color:${C.white};font-family:'Segoe UI',system-ui,-apple-system,sans-serif;-webkit-text-size-adjust:100%}::-webkit-scrollbar{width:5px;height:5px}::-webkit-scrollbar-track{background:${C.bg}}::-webkit-scrollbar-thumb{background:${C.border};border-radius:99px}input,select,textarea{font-family:inherit;-webkit-tap-highlight-color:transparent}button{-webkit-tap-highlight-color:transparent;touch-action:manipulation}@keyframes spin{to{transform:rotate(360deg)}}@keyframes bounce{0%,80%,100%{transform:translateY(0)}40%{transform:translateY(-8px)}}@media(max-width:767px){html{font-size:13.5px}table td,table th{padding:8px 8px!important;font-size:0.72rem!important}table th{font-size:0.65rem!important}}@media(max-width:380px){html{font-size:12.5px}}`}</style>

      {screen==="splash"      && <Splash onDone={()=>setScreen("login")}/>}
      {screen==="login"       && <Login onLogin={handleLogin} onRegister={()=>setScreen("register")} onForgot={()=>setScreen("forgot")} onFirstAdmin={()=>setScreen("firstAdmin")} onOwnerRecovery={()=>setScreen("ownerRecovery")} users={users}/>}
      {screen==="register"    && <RegisterSelector onBack={()=>setScreen("login")} onSuccess={(newScreen,d)=>{if(newScreen!=="pendingSuccess"){handleLogin(newScreen,d);}}} users={users} setUsers={setUsers}/>}
      {screen==="forgot"      && <ForgotPassword onBack={()=>setScreen("login")} users={users} setUsers={setUsers}/>}
      {screen==="ownerRecovery" && <OwnerRecovery onBack={()=>setScreen("login")} users={users} setUsers={setUsers}/>}
      {screen==="firstAdmin"  && <FirstAdminSetup onDone={()=>setScreen("login")} users={users} setUsers={setUsers}/>}

      {screen==="app"&&(
        <div style={{display:"flex",minHeight:"100vh",width:"100%",overflowX:"hidden"}}>
          <Sidebar nav={nav} active={page} onNav={setPage} user={user} onLogout={handleLogout}/>
          <main style={{flex:1,overflowX:"hidden",overflowY:"auto",background:`radial-gradient(ellipse at 80% 0%,${C.mid}50 0%,transparent 60%)`,minHeight:"100vh",width:isMob?"100%":"calc(100% - 220px)",paddingTop:isMob?54:0}}>
            {renderPage()}
          </main>
        </div>
      )}
    </>
  );
}
